package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

public final class FixBriefGenerator {

    private static final String UNASSIGNED = "(project-level findings with no source file)";

    private FixBriefGenerator() {}

    public static List<Path> generate(final AggregatedReport report, final Path outputDir) throws IOException {
        Files.createDirectories(outputDir);
        final Map<String, List<Finding>> byFile = groupByFile(report.findings());
        final List<Path> written = writeBriefs(byFile, outputDir);
        written.add(writeIndex(report.projectName(), byFile, outputDir));
        return written;
    }

    private static List<Path> writeBriefs(final Map<String, List<Finding>> byFile,
                                          final Path outputDir) throws IOException {
        final List<Path> written = new ArrayList<>();
        for (final Map.Entry<String, List<Finding>> entry : byFile.entrySet()) {
            final Path brief = outputDir.resolve(briefFileName(entry.getKey()));
            Files.writeString(brief, renderBrief(entry.getKey(), entry.getValue()));
            written.add(brief);
        }
        return written;
    }

    private static Path writeIndex(final String projectName,
                                   final Map<String, List<Finding>> byFile,
                                   final Path outputDir) throws IOException {
        final Path indexFile = outputDir.resolve("_INDEX.md");
        Files.writeString(indexFile, renderIndex(projectName, byFile));
        return indexFile;
    }

    private static Map<String, List<Finding>> groupByFile(final List<Finding> findings) {
        final Map<String, List<Finding>> byFile = new LinkedHashMap<>();
        findings.stream()
                .sorted(Comparator.comparing(FixBriefGenerator::fileKey)
                        .thenComparingInt(Finding::startLine))
                .forEach(f -> byFile.computeIfAbsent(fileKey(f), k -> new ArrayList<>()).add(f));
        return byFile;
    }

    private static String fileKey(final Finding f) {
        return f.sourceFile() == null ? UNASSIGNED : f.sourceFile();
    }

    private static String briefFileName(final String sourceFile) {
        if (UNASSIGNED.equals(sourceFile)) {
            return "_project-level.md";
        }
        final String base = sourceFile.replaceAll(".*/", "").replace(".java", "");
        return base + ".md";
    }

    static String renderBrief(final String sourceFile, final List<Finding> findings) {
        final StringBuilder sb = new StringBuilder();
        sb.append("# Fix brief: ").append(sourceFile).append('\n')
                .append('\n')
                .append(findings.size()).append(" finding").append(findings.size() == 1 ? "" : "s")
                .append(" on this file.\n")
                .append('\n')
                .append("## Rules\n")
                .append("- Address only findings on this file. Do not modify other files except to fix "
                        + "compilation.\n")
                .append("- Prefer deleting dead code to refactoring it.\n")
                .append("- Never degrade readability to satisfy a metric. If a fix would make the code harder "
                        + "to read (e.g. cramming methods onto one line to pass a line-count check), leave the "
                        + "finding and note it in your final summary.\n")
                .append("- Run `./gradlew :<module>:test` after your changes. Tests must pass.\n")
                .append('\n');
        for (final Map.Entry<HeuristicCode, List<Finding>> entry : groupByCode(findings).entrySet()) {
            sb.append(renderCodeSection(entry.getKey(), entry.getValue()));
        }
        sb.append("## Final self-check\n")
                .append("Before handing back, confirm:\n")
                .append("1. Tests pass for the affected module.\n")
                .append("2. Each change makes the code clearer, not just shorter.\n")
                .append("3. List any findings you intentionally did not fix and why.\n");
        return sb.toString();
    }

    private static Map<HeuristicCode, List<Finding>> groupByCode(final List<Finding> findings) {
        final Map<HeuristicCode, List<Finding>> byCode = new LinkedHashMap<>();
        findings.stream()
                .sorted(Comparator.comparing((Finding f) -> f.severity().ordinal())
                        .thenComparing(f -> f.code().name()))
                .forEach(f -> byCode.computeIfAbsent(f.code(), k -> new ArrayList<>()).add(f));
        return byCode;
    }

    static String renderCodeSection(final HeuristicCode code, final List<Finding> findings) {
        final StringBuilder sb = new StringBuilder();
        final String title = HeuristicDescriptions.name(code);
        sb.append("## ").append(code.name()).append(": ").append(title).append('\n')
                .append('\n');
        final String skillPath = SkillPathRegistry.skillPathFor(code);
        if (skillPath != null) {
            sb.append("> Read `").append(skillPath).append("` before addressing these.\n\n");
        }
        for (final Finding f : findings) {
            sb.append(renderFindingLine(f));
        }
        sb.append('\n');
        return sb.toString();
    }

    private static String renderFindingLine(final Finding f) {
        final StringBuilder sb = new StringBuilder("- ");
        if (f.startLine() > 0) {
            sb.append("L").append(f.startLine());
            if (f.endLine() > f.startLine()) {
                sb.append('-').append(f.endLine());
            }
            sb.append(": ");
        }
        sb.append(f.message()).append('\n');
        return sb.toString();
    }

    static String renderIndex(final String projectName,
                              final Map<String, List<Finding>> byFile) {
        final StringBuilder sb = new StringBuilder();
        sb.append("# Fix briefs for ").append(projectName).append('\n')
                .append('\n')
                .append("One brief per file. Each brief lists every finding on that file and points at the "
                        + "relevant skill. Designed to be handed to a single agent so two agents never edit "
                        + "the same file.\n")
                .append('\n')
                .append("| File | Findings | Brief |\n")
                .append("|---|---:|---|\n");
        byFile.entrySet().stream()
                .sorted(Map.Entry.<String, List<Finding>>comparingByValue(
                        Comparator.comparingInt(List::size)).reversed())
                .forEach(e -> sb.append("| ").append(e.getKey())
                        .append(" | ").append(e.getValue().size())
                        .append(" | [").append(briefFileName(e.getKey())).append("](")
                        .append(briefFileName(e.getKey())).append(") |\n"));
        return sb.toString();
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.time.LocalDate;
import java.util.Set;

record Suppression(
        String sourceFile,
        int startLine,
        int endLine,
        Set<HeuristicCode> codes,
        String reason,
        String until,
        String packagePath
) {
    boolean isPackageScoped() {
        return packagePath != null;
    }

    boolean isExpired() {
        if (until.isEmpty()) {
            return false;
        }
        return LocalDate.parse(until).isBefore(LocalDate.now());
    }

    boolean covers(Finding finding) {
        if (!codes.contains(finding.code())) {
            return false;
        }
        if (isExpired()) {
            return false;
        }
        if (isPackageScoped()) {
            return matchesPackage(finding.sourceFile()) || matchesPackage(otherFile(finding));
        }
        return matchesFile(finding.sourceFile())
                && finding.startLine() >= startLine
                && finding.startLine() <= endLine;
    }

    private boolean matchesPackage(String path) {
        return path != null && path.contains(packagePath + "/");
    }

    private boolean matchesFile(String findingFile) {
        return findingFile.equals(sourceFile)
                || findingFile.endsWith(sourceFile)
                || sourceFile.endsWith(findingFile);
    }

    private static String otherFile(Finding finding) {
        return finding.metadata() == null ? null : finding.metadata().get("otherFile");
    }
}

package org.fiftieshousewife.cleancode.core;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ParseResult;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.PackageDeclaration;
import com.github.javaparser.ast.body.BodyDeclaration;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.ConstructorDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.AnnotationExpr;
import com.github.javaparser.ast.expr.BinaryExpr;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MemberValuePair;
import com.github.javaparser.ast.expr.NormalAnnotationExpr;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Stream;

final class SuppressionParser {

    private static final String SUPPRESS_ANNOTATION = "SuppressCleanCode";
    private static final String SUPPRESS_LIST_ANNOTATION = "SuppressCleanCode.List";

    private final List<Suppression> suppressions = new ArrayList<>();
    private final List<Finding> metaFindings = new ArrayList<>();
    private final JavaParser parser = new JavaParser();

    static ParseOutcome parse(final Path sourceRoot) {
        final SuppressionParser instance = new SuppressionParser();
        instance.walk(sourceRoot);
        return new ParseOutcome(instance.suppressions, instance.metaFindings);
    }

    private void walk(final Path sourceRoot) {
        try (Stream<Path> files = Files.walk(sourceRoot)) {
            files.filter(p -> p.toString().endsWith(".java")).forEach(this::parseFile);
        } catch (IOException unreadableSourceRoot) {
            ignoreUnreadable(unreadableSourceRoot);
        }
    }

    private void parseFile(final Path file) {
        try {
            final ParseResult<CompilationUnit> result = parser.parse(file);
            if (result.isSuccessful() && result.getResult().isPresent()) {
                final CompilationUnit cu = result.getResult().get();
                final String relativePath = deriveSourceFile(cu, file);
                processCompilationUnit(cu, relativePath);
            }
        } catch (IOException unreadableFile) {
            ignoreUnreadable(unreadableFile);
        }
    }

    /**
     * Best-effort walk: a file that can't be read is treated as having no
     * suppressions. The exception parameter is consumed so this is not an
     * empty catch block, but there is no sink available for logging in
     * this module.
     */
    private static void ignoreUnreadable(final IOException ignored) {
        final IOException consumed = ignored;
        if (consumed == null) {
            throw new AssertionError("unreachable");
        }
    }

    private void processCompilationUnit(final CompilationUnit cu, final String sourceFile) {
        cu.getPackageDeclaration().ifPresent(pkg -> processPackageDeclaration(pkg, sourceFile));
        final ParseContext fileContext = new ParseContext(sourceFile, null);
        cu.findAll(ClassOrInterfaceDeclaration.class)
                .forEach(cls -> processAnnotatedNode(cls, fileContext));
        cu.findAll(MethodDeclaration.class)
                .forEach(method -> processAnnotatedNode(method, fileContext));
        cu.findAll(ConstructorDeclaration.class)
                .forEach(ctor -> processAnnotatedNode(ctor, fileContext));
    }

    private void processPackageDeclaration(final PackageDeclaration pkg, final String sourceFile) {
        final String packagePath = pkg.getNameAsString().replace('.', '/');
        final int line = pkg.getBegin().map(p -> p.line).orElse(-1);
        final ParseContext context = new ParseContext(sourceFile, packagePath);
        final LineRange range = new LineRange(line, line);
        for (final AnnotationExpr ann : pkg.getAnnotations()) {
            if (SUPPRESS_ANNOTATION.equals(ann.getNameAsString())) {
                processSingleAnnotation(ann, context, range);
            }
        }
    }

    private void processAnnotatedNode(final BodyDeclaration<?> node, final ParseContext context) {
        final int startLine = node.getBegin().map(p -> p.line).orElse(-1);
        final int endLine = node.getEnd().map(p -> p.line).orElse(-1);
        final LineRange range = new LineRange(startLine, endLine);

        for (final AnnotationExpr ann : node.getAnnotations()) {
            final String annName = ann.getNameAsString();
            if (SUPPRESS_ANNOTATION.equals(annName)) {
                processSingleAnnotation(ann, context, range);
            } else if (SUPPRESS_LIST_ANNOTATION.equals(annName)) {
                processRepeatableContainer(ann, context, range);
            }
        }
    }

    private void processRepeatableContainer(final AnnotationExpr ann,
                                            final ParseContext context,
                                            final LineRange range) {
        if (!(ann instanceof NormalAnnotationExpr normal)) {
            return;
        }
        for (final MemberValuePair pair : normal.getPairs()) {
            if (!"value".equals(pair.getNameAsString())) {
                continue;
            }
            pair.getValue().toArrayInitializerExpr().ifPresent(arr ->
                    arr.getValues().forEach(v -> {
                        if (v instanceof AnnotationExpr inner) {
                            processSingleAnnotation(inner, context, range);
                        }
                    }));
        }
    }

    private void processSingleAnnotation(final AnnotationExpr ann,
                                         final ParseContext context,
                                         final LineRange range) {
        final Set<HeuristicCode> codes = new HashSet<>();
        String reason = "";
        String until = "";

        if (ann instanceof NormalAnnotationExpr normal) {
            for (final MemberValuePair pair : normal.getPairs()) {
                switch (pair.getNameAsString()) {
                    case "value" -> codes.addAll(extractCodes(pair.getValue()));
                    case "reason" -> reason = extractStringValue(pair.getValue());
                    case "until" -> until = extractStringValue(pair.getValue());
                }
            }
        }

        if (codes.isEmpty()) {
            return;
        }

        recordExpiryMetaFinding(ann, context.sourceFile(), codes, until);
        recordReasonMetaFinding(ann, context.sourceFile(), reason);

        suppressions.add(new Suppression(
                context.sourceFile(), range.start(), range.end(), codes, reason, until, context.packagePath()));
    }

    private void recordExpiryMetaFinding(final AnnotationExpr ann, final String sourceFile,
                                         final Set<HeuristicCode> codes, final String until) {
        if (until.isEmpty()) {
            return;
        }
        final java.time.LocalDate untilDate = java.time.LocalDate.parse(until);
        if (!untilDate.isBefore(java.time.LocalDate.now())) {
            return;
        }
        metaFindings.add(Finding.at(
                HeuristicCode.META_SUPPRESSION_EXPIRED, sourceFile,
                ann.getBegin().map(p -> p.line).orElse(-1),
                ann.getEnd().map(p -> p.line).orElse(-1),
                "Suppression expired on " + until + " for " + codes,
                Severity.ERROR, Confidence.HIGH,
                "suppression-index", "expired-suppression"));
    }

    private void recordReasonMetaFinding(final AnnotationExpr ann, final String sourceFile,
                                         final String reason) {
        if (!reason.isBlank() && !"TODO".equalsIgnoreCase(reason.trim())) {
            return;
        }
        metaFindings.add(Finding.at(
                HeuristicCode.META_SUPPRESSION_NO_REASON, sourceFile,
                ann.getBegin().map(p -> p.line).orElse(-1),
                ann.getEnd().map(p -> p.line).orElse(-1),
                "Suppression has no meaningful reason: '" + reason + "'",
                Severity.WARNING, Confidence.HIGH,
                "suppression-index", "blank-reason"));
    }

    private static String extractStringValue(final Expression expr) {
        if (expr.isStringLiteralExpr()) {
            return expr.asStringLiteralExpr().getValue();
        }
        if (expr.isBinaryExpr()) {
            final BinaryExpr bin = expr.asBinaryExpr();
            if (bin.getOperator() == BinaryExpr.Operator.PLUS) {
                return extractStringValue(bin.getLeft()) + extractStringValue(bin.getRight());
            }
        }
        return expr.toString();
    }

    private static Set<HeuristicCode> extractCodes(final Expression expr) {
        final Set<HeuristicCode> codes = new HashSet<>();
        if (expr.isFieldAccessExpr()) {
            final String name = expr.asFieldAccessExpr().getNameAsString();
            codes.add(HeuristicCode.valueOf(name));
        } else if (expr.isArrayInitializerExpr()) {
            expr.asArrayInitializerExpr().getValues().forEach(v -> codes.addAll(extractCodes(v)));
        }
        return codes;
    }

    private static String deriveSourceFile(final CompilationUnit cu, final Path file) {
        final String packageName = cu.getPackageDeclaration()
                .map(pd -> pd.getNameAsString().replace('.', '/'))
                .orElse("");
        final String fileName = file.getFileName().toString();
        return packageName.isEmpty() ? fileName : packageName + "/" + fileName;
    }

    record ParseOutcome(List<Suppression> suppressions, List<Finding> metaFindings) {
    }

    private record ParseContext(String sourceFile, String packagePath) {
    }

    private record LineRange(int start, int end) {
    }
}

