package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.ZoneOffset;
import java.time.format.DateTimeFormatter;
import java.util.Comparator;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.stream.Collectors;

import static org.fiftieshousewife.cleancode.core.HtmlEscaping.escape;

public final class HtmlReportWriter {

    private static final DateTimeFormatter TIMESTAMP_FORMAT =
            DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss z").withZone(ZoneOffset.UTC);

    private HtmlReportWriter() {}

    public static void write(final AggregatedReport report, final Path outputFile) throws IOException {
        write(report, outputFile, "");
    }

    public static void write(final AggregatedReport report, final Path outputFile,
                              final String repositoryUrl) throws IOException {
        final Path parent = outputFile.getParent();
        if (parent != null) {
            Files.createDirectories(parent);
        }
        Files.writeString(outputFile, render(report, repositoryUrl));
    }

    private static String render(final AggregatedReport report, final String repositoryUrl) {
        final StringBuilder html = new StringBuilder();
        appendDocumentStart(html, report);
        appendSeveritySummary(html, report);

        if (report.findings().isEmpty()) {
            html.append("    <p class=\"clean\">No violations found. The code is clean.</p>\n");
        } else {
            appendFindingsByCode(html, report.findings(), repositoryUrl);
            appendToolSummary(html, report.findings());
        }

        appendFooter(html, report);
        appendDocumentEnd(html);
        return html.toString();
    }

    private static void appendDocumentStart(final StringBuilder html, final AggregatedReport report) {
        html.append("<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n");
        html.append("  <meta charset=\"UTF-8\">\n");
        html.append("  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n");
        html.append("  <title>Clean Code Report — ").append(escape(report.projectName()));
        html.append("</title>\n");
        appendStyles(html);
        html.append("</head>\n<body>\n");
        html.append("  <header>\n");
        html.append("    <h1>Clean Code Analysis</h1>\n");
        html.append("    <p>").append(escape(report.projectName()));
        if (report.projectVersion() != null) {
            html.append(" v").append(escape(report.projectVersion()));
        }
        html.append("</p>\n");
        html.append("  </header>\n");
        html.append("  <main>\n");
    }

    private static void appendStyles(final StringBuilder html) {
        html.append("  <style>\n").append(HtmlReportStyles.css()).append("  </style>\n");
    }

    private static void appendSeveritySummary(final StringBuilder html, final AggregatedReport report) {
        final Map<Severity, List<Finding>> bySeverity = report.bySeverity();
        html.append("    <div class=\"summary\">\n");
        appendSeverityBadge(html, "error", countOf(bySeverity, Severity.ERROR), "errors");
        appendSeverityBadge(html, "warning", countOf(bySeverity, Severity.WARNING), "warnings");
        appendSeverityBadge(html, "info", countOf(bySeverity, Severity.INFO), "info");
        html.append("    </div>\n");
    }

    private static int countOf(final Map<Severity, List<Finding>> bySeverity, final Severity severity) {
        return bySeverity.getOrDefault(severity, List.of()).size();
    }

    private static void appendSeverityBadge(final StringBuilder html, final String cssClass,
                                             final int count, final String label) {
        html.append("      <span class=\"badge ").append(cssClass).append("\">");
        html.append(count).append(' ').append(label).append("</span>\n");
    }

    private static void appendFindingsByCode(final StringBuilder html, final List<Finding> findings,
                                               final String repositoryUrl) {
        final Map<HeuristicCode, List<Finding>> byCode = findings.stream()
                .collect(Collectors.groupingBy(Finding::code));

        byCode.entrySet().stream()
                .sorted(Comparator.comparing(e -> e.getKey().name()))
                .forEach(entry -> appendCodeGroup(html, entry.getKey(), entry.getValue(), repositoryUrl));
    }

    private static void appendCodeGroup(final StringBuilder html, final HeuristicCode code,
                                         final List<Finding> group, final String repositoryUrl) {
        final String name = HeuristicDescriptions.name(code);

        html.append("    <details>\n");
        html.append("      <summary><span class=\"code-label\">").append(escape(code.name()));
        html.append("</span>").append(escape(name));
        html.append(" (").append(group.size()).append(")</summary>\n");
        html.append("      <div class=\"group-body\">\n");

        appendOptionalParagraph(html, "reference", HeuristicDescriptions.reference(code));
        appendOptionalParagraph(html, "guidance", HeuristicDescriptions.guidance(code));

        html.append("        <table>\n");
        html.append("          <tr><th>Severity</th><th>Location</th><th>Message</th></tr>\n");

        group.stream()
                .sorted(Comparator.comparing(f -> f.sourceFile() != null ? f.sourceFile() : ""))
                .forEach(f -> appendFindingRow(html, f, repositoryUrl));

        html.append("        </table>\n");
        html.append("      </div>\n");
        html.append("    </details>\n");
    }

    private static void appendOptionalParagraph(final StringBuilder html, final String cssClass,
                                                  final String text) {
        if (text == null) {
            return;
        }
        html.append("        <p class=\"").append(cssClass).append("\">");
        html.append(escape(text)).append("</p>\n");
    }

    private static void appendFindingRow(final StringBuilder html, final Finding finding,
                                          final String repositoryUrl) {
        final String severityClass = "sev-" + finding.severity().name().toLowerCase(Locale.ROOT);
        final String location = formatLocation(finding);
        final String locationHtml = buildLocationHtml(finding, location, repositoryUrl);

        html.append("          <tr>");
        html.append("<td class=\"").append(severityClass).append("\">");
        html.append(finding.severity().name()).append("</td>");
        html.append("<td class=\"location\">").append(locationHtml).append("</td>");
        html.append("<td>").append(escape(finding.message())).append("</td>");
        html.append("</tr>\n");
    }

    private static String buildLocationHtml(final Finding finding, final String location,
                                             final String repositoryUrl) {
        if (finding.sourceFile() == null || repositoryUrl == null || repositoryUrl.isBlank()) {
            return escape(location);
        }
        final String baseUrl = repositoryUrl.endsWith("/")
                ? repositoryUrl.substring(0, repositoryUrl.length() - 1) : repositoryUrl;
        final String relativePath = relativiseSourceFile(finding.sourceFile());
        final String fileUrl = baseUrl + "/" + relativePath;
        final String linkedUrl = finding.startLine() > 0
                ? fileUrl + "#L" + finding.startLine() : fileUrl;
        return "<a href=\"" + escape(linkedUrl) + "\">" + escape(location) + "</a>";
    }

    private static String relativiseSourceFile(final String sourceFile) {
        final int srcIdx = sourceFile.indexOf("src/");
        if (srcIdx > 0) {
            return sourceFile.substring(srcIdx);
        }
        return sourceFile;
    }

    private static void appendToolSummary(final StringBuilder html, final List<Finding> findings) {
        final Map<String, Long> byTool = findings.stream()
                .collect(Collectors.groupingBy(Finding::tool, Collectors.counting()));

        html.append("    <div class=\"tool-summary\">\n");
        html.append("      <h2>Sources</h2>\n");
        html.append("      <table>\n");
        html.append("        <tr><th>Tool</th><th>Findings</th></tr>\n");

        byTool.entrySet().stream()
                .sorted(Map.Entry.<String, Long>comparingByValue().reversed())
                .forEach(entry -> appendToolRow(html, entry.getKey(), entry.getValue()));

        html.append("      </table>\n");
        html.append("    </div>\n");
    }

    private static void appendToolRow(final StringBuilder html, final String tool, final Long count) {
        html.append("        <tr><td>").append(escape(tool));
        html.append("</td><td>").append(count).append("</td></tr>\n");
    }

    private static void appendFooter(final StringBuilder html, final AggregatedReport report) {
        final String timestamp = TIMESTAMP_FORMAT.format(report.generatedAt());
        html.append("  </main>\n");
        html.append("  <footer>\n");
        html.append("    <p>Generated by Clean Code Plugin &mdash; ").append(escape(timestamp));
        html.append("</p>\n");
        html.append("    <p>").append(report.findings().size()).append(" total findings</p>\n");
        html.append("  </footer>\n");
    }

    private static void appendDocumentEnd(final StringBuilder html) {
        html.append("</body>\n</html>\n");
    }

    private static String formatLocation(final Finding finding) {
        if (finding.sourceFile() == null) {
            return "(project)";
        }
        final String file = shortenPath(finding.sourceFile());
        if (finding.startLine() > 0) {
            return file + ":" + finding.startLine();
        }
        return file;
    }

    private static String shortenPath(final String path) {
        final int srcIdx = path.indexOf("src/main/java/");
        if (srcIdx >= 0) {
            return path.substring(srcIdx + "src/main/java/".length());
        }
        return path;
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.util.Comparator;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.stream.Collectors;

import static org.fiftieshousewife.cleancode.core.HtmlEscaping.escape;

final class HtmlFindingsRenderer {

    private HtmlFindingsRenderer() {}

    static void appendFindingsByCode(final StringBuilder html, final List<Finding> findings,
                                      final String repositoryUrl) {
        final Map<HeuristicCode, List<Finding>> byCode = findings.stream()
                .collect(Collectors.groupingBy(Finding::code));

        byCode.entrySet().stream()
                .sorted(Comparator.comparing(e -> e.getKey().name()))
                .forEach(entry -> appendCodeGroup(html, entry.getKey(), entry.getValue(), repositoryUrl));
    }

    static void appendToolSummary(final StringBuilder html, final List<Finding> findings) {
        final Map<String, Long> byTool = findings.stream()
                .collect(Collectors.groupingBy(Finding::tool, Collectors.counting()));

        html.append("    <div class=\"tool-summary\">\n");
        html.append("      <h2>Sources</h2>\n");
        html.append("      <table>\n");
        html.append("        <tr><th>Tool</th><th>Findings</th></tr>\n");

        byTool.entrySet().stream()
                .sorted(Map.Entry.<String, Long>comparingByValue().reversed())
                .forEach(entry -> appendToolRow(html, entry.getKey(), entry.getValue()));

        html.append("      </table>\n");
        html.append("    </div>\n");
    }

    private static void appendCodeGroup(final StringBuilder html, final HeuristicCode code,
                                         final List<Finding> group, final String repositoryUrl) {
        final String name = HeuristicDescriptions.name(code);

        html.append("    <details>\n");
        html.append("      <summary><span class=\"code-label\">").append(escape(code.name()));
        html.append("</span>").append(escape(name));
        html.append(" (").append(group.size()).append(")</summary>\n");
        html.append("      <div class=\"group-body\">\n");

        appendOptionalParagraph(html, "reference", HeuristicDescriptions.reference(code));
        appendOptionalParagraph(html, "guidance", HeuristicDescriptions.guidance(code));

        html.append("        <table>\n");
        html.append("          <tr><th>Severity</th><th>Location</th><th>Message</th></tr>\n");

        group.stream()
                .sorted(Comparator.comparing(f -> f.sourceFile() != null ? f.sourceFile() : ""))
                .forEach(f -> appendFindingRow(html, f, repositoryUrl));

        html.append("        </table>\n");
        html.append("      </div>\n");
        html.append("    </details>\n");
    }

    private static void appendOptionalParagraph(final StringBuilder html, final String cssClass,
                                                  final String text) {
        if (text == null) {
            return;
        }
        html.append("        <p class=\"").append(cssClass).append("\">");
        html.append(escape(text)).append("</p>\n");
    }

    private static void appendFindingRow(final StringBuilder html, final Finding finding,
                                          final String repositoryUrl) {
        final String severityClass = "sev-" + finding.severity().name().toLowerCase(Locale.ROOT);
        final String location = formatLocation(finding);
        final String locationHtml = buildLocationHtml(finding, location, repositoryUrl);

        html.append("          <tr>");
        html.append("<td class=\"").append(severityClass).append("\">");
        html.append(finding.severity().name()).append("</td>");
        html.append("<td class=\"location\">").append(locationHtml).append("</td>");
        html.append("<td>").append(escape(finding.message())).append("</td>");
        html.append("</tr>\n");
    }

    private static String buildLocationHtml(final Finding finding, final String location,
                                             final String repositoryUrl) {
        if (finding.sourceFile() == null || repositoryUrl == null || repositoryUrl.isBlank()) {
            return escape(location);
        }
        final String baseUrl = repositoryUrl.endsWith("/")
                ? repositoryUrl.substring(0, repositoryUrl.length() - 1) : repositoryUrl;
        final String relativePath = relativiseSourceFile(finding.sourceFile());
        final String fileUrl = baseUrl + "/" + relativePath;
        final String linkedUrl = finding.startLine() > 0
                ? fileUrl + "#L" + finding.startLine() : fileUrl;
        return "<a href=\"" + escape(linkedUrl) + "\">" + escape(location) + "</a>";
    }

    private static String relativiseSourceFile(final String sourceFile) {
        final int srcIdx = sourceFile.indexOf("src/");
        if (srcIdx > 0) {
            return sourceFile.substring(srcIdx);
        }
        return sourceFile;
    }

    private static void appendToolRow(final StringBuilder html, final String tool, final Long count) {
        html.append("        <tr><td>").append(escape(tool));
        html.append("</td><td>").append(count).append("</td></tr>\n");
    }

    private static String formatLocation(final Finding finding) {
        if (finding.sourceFile() == null) {
            return "(project)";
        }
        final String file = shortenPath(finding.sourceFile());
        if (finding.startLine() > 0) {
            return file + ":" + finding.startLine();
        }
        return file;
    }

    private static String shortenPath(final String path) {
        final int srcIdx = path.indexOf("src/main/java/");
        if (srcIdx >= 0) {
            return path.substring(srcIdx + "src/main/java/".length());
        }
        return path;
    }
}

package org.fiftieshousewife.cleancode.core;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.ZoneOffset;
import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.Map;

import static org.fiftieshousewife.cleancode.core.HtmlEscaping.escape;
import static org.fiftieshousewife.cleancode.core.HtmlFindingsRenderer.appendFindingsByCode;
import static org.fiftieshousewife.cleancode.core.HtmlFindingsRenderer.appendToolSummary;

public final class HtmlReportWriter {

    private static final DateTimeFormatter TIMESTAMP_FORMAT =
            DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss z").withZone(ZoneOffset.UTC);

    private HtmlReportWriter() {}

    public static void write(final AggregatedReport report, final Path outputFile) throws IOException {
        write(report, outputFile, "");
    }

    public static void write(final AggregatedReport report, final Path outputFile,
                              final String repositoryUrl) throws IOException {
        final Path parent = outputFile.getParent();
        if (parent != null) {
            Files.createDirectories(parent);
        }
        Files.writeString(outputFile, render(report, repositoryUrl));
    }

    private static String render(final AggregatedReport report, final String repositoryUrl) {
        final StringBuilder html = new StringBuilder();
        appendDocumentStart(html, report);
        appendSeveritySummary(html, report);

        if (report.findings().isEmpty()) {
            html.append("    <p class=\"clean\">No violations found. The code is clean.</p>\n");
        } else {
            appendFindingsByCode(html, report.findings(), repositoryUrl);
            appendToolSummary(html, report.findings());
        }

        appendFooter(html, report);
        appendDocumentEnd(html);
        return html.toString();
    }

    private static void appendDocumentStart(final StringBuilder html, final AggregatedReport report) {
        html.append("<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n");
        html.append("  <meta charset=\"UTF-8\">\n");
        html.append("  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n");
        html.append("  <title>Clean Code Report — ").append(escape(report.projectName()));
        html.append("</title>\n");
        appendStyles(html);
        html.append("</head>\n<body>\n");
        appendHeader(html, report);
        html.append("  <main>\n");
    }

    private static void appendHeader(final StringBuilder html, final AggregatedReport report) {
        html.append("  <header>\n");
        html.append("    <h1>Clean Code Analysis</h1>\n");
        html.append("    <p>").append(escape(report.projectName()));
        if (report.projectVersion() != null) {
            html.append(" v").append(escape(report.projectVersion()));
        }
        html.append("</p>\n");
        html.append("  </header>\n");
    }

    private static void appendStyles(final StringBuilder html) {
        html.append("  <style>\n").append(HtmlReportStyles.css()).append("  </style>\n");
    }

    private static void appendSeveritySummary(final StringBuilder html, final AggregatedReport report) {
        final Map<Severity, List<Finding>> bySeverity = report.bySeverity();
        html.append("    <div class=\"summary\">\n");
        appendSeverityBadge(html, "error", countOf(bySeverity, Severity.ERROR), "errors");
        appendSeverityBadge(html, "warning", countOf(bySeverity, Severity.WARNING), "warnings");
        appendSeverityBadge(html, "info", countOf(bySeverity, Severity.INFO), "info");
        html.append("    </div>\n");
    }

    private static int countOf(final Map<Severity, List<Finding>> bySeverity, final Severity severity) {
        return bySeverity.getOrDefault(severity, List.of()).size();
    }

    private static void appendSeverityBadge(final StringBuilder html, final String cssClass,
                                             final int count, final String label) {
        html.append("      <span class=\"badge ").append(cssClass).append("\">");
        html.append(count).append(' ').append(label).append("</span>\n");
    }

    private static void appendFooter(final StringBuilder html, final AggregatedReport report) {
        final String timestamp = TIMESTAMP_FORMAT.format(report.generatedAt());
        html.append("  </main>\n");
        html.append("  <footer>\n");
        html.append("    <p>Generated by Clean Code Plugin &mdash; ").append(escape(timestamp));
        html.append("</p>\n");
        html.append("    <p>").append(report.findings().size()).append(" total findings</p>\n");
        html.append("  </footer>\n");
    }

    private static void appendDocumentEnd(final StringBuilder html) {
        html.append("</body>\n</html>\n");
    }
}

