package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.util.Map;

final class BaselineDeltaFormatter {

    private BaselineDeltaFormatter() {}

    static void append(final StringBuilder out,
                       final Map<HeuristicCode, BaselineManager.Delta> deltas) {
        final int newViolations = sumPositive(deltas);
        final int fixedViolations = sumNegated(deltas);

        out.append("  vs baseline: ");
        if (newViolations > 0) {
            out.append("+").append(newViolations).append(" new");
        }
        if (newViolations > 0 && fixedViolations > 0) {
            out.append("  ·  ");
        }
        if (fixedViolations > 0) {
            out.append("-").append(fixedViolations).append(" fixed");
        }
        if (newViolations == 0 && fixedViolations == 0) {
            out.append("no change");
        }
        out.append('\n');
    }

    private static int sumPositive(final Map<HeuristicCode, BaselineManager.Delta> deltas) {
        return deltas.values().stream()
                .mapToInt(d -> Math.max(0, d.change()))
                .sum();
    }

    private static int sumNegated(final Map<HeuristicCode, BaselineManager.Delta> deltas) {
        return deltas.values().stream()
                .mapToInt(d -> Math.max(0, -d.change()))
                .sum();
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.util.Comparator;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

final class FindingsByCodeFormatter {

    private static final String DIVIDER =
            "───────────────────────────────────────────────────────────────────────────";
    private static final int WRAP_WIDTH = 72;

    private FindingsByCodeFormatter() {}

    static void append(final StringBuilder out, final List<Finding> findings) {
        final Map<HeuristicCode, List<Finding>> byCode = findings.stream()
                .collect(Collectors.groupingBy(Finding::code));

        byCode.entrySet().stream()
                .sorted(Comparator.comparing(e -> e.getKey().name()))
                .forEach(entry -> appendCodeGroup(out, entry.getKey(), entry.getValue()));
    }

    private static void appendCodeGroup(final StringBuilder out,
                                        final HeuristicCode code,
                                        final List<Finding> group) {
        out.append('\n').append(DIVIDER).append('\n');

        final String name = HeuristicDescriptions.name(code);
        out.append("  ").append(code.name()).append(": ").append(name);
        out.append(" (").append(group.size()).append(")\n");

        appendIfPresent(out, HeuristicDescriptions.summary(code));
        appendIfPresent(out, HeuristicDescriptions.reference(code));

        final String guidance = HeuristicDescriptions.guidance(code);
        if (guidance != null) {
            out.append('\n');
            appendWrapped(out, guidance, "  ", WRAP_WIDTH);
        }

        out.append('\n');
        group.stream()
                .sorted(Comparator.comparing(f -> f.sourceFile() != null ? f.sourceFile() : ""))
                .forEach(f -> appendFinding(out, f));
    }

    private static void appendIfPresent(final StringBuilder out, final String text) {
        if (text != null) {
            out.append("  ").append(text).append('\n');
        }
    }

    private static void appendFinding(final StringBuilder out, final Finding finding) {
        final String location = formatLocation(finding);
        out.append("    ").append(severityIcon(finding.severity()));
        out.append(" ").append(location);
        out.append("  ").append(finding.message()).append('\n');
    }

    private static void appendWrapped(final StringBuilder out,
                                      final String text,
                                      final String indent,
                                      final int width) {
        final String[] words = text.split(" ");
        final StringBuilder line = new StringBuilder(indent);
        for (final String word : words) {
            if (line.length() + word.length() + 1 > width && line.length() > indent.length()) {
                out.append(line).append('\n');
                line.setLength(0);
                line.append(indent);
            }
            if (line.length() > indent.length()) {
                line.append(' ');
            }
            line.append(word);
        }
        if (line.length() > indent.length()) {
            out.append(line).append('\n');
        }
    }

    private static String formatLocation(final Finding finding) {
        if (finding.sourceFile() == null) {
            return "(project)";
        }
        final String file = finding.sourceFile();
        if (finding.startLine() > 0) {
            return file + ":" + finding.startLine();
        }
        return file;
    }

    private static String severityIcon(final Severity severity) {
        return switch (severity) {
            case ERROR -> "!!";
            case WARNING -> " !";
            case INFO -> "  ";
        };
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

public final class BuildOutputFormatter {

    private static final String HEADER =
            "═══════════════════════════════════════════════════════════════════════════";
    private static final String DIVIDER =
            "───────────────────────────────────────────────────────────────────────────";

    private BuildOutputFormatter() {}

    public static String format(final AggregatedReport report) {
        return format(report, Map.of());
    }

    public static String format(final AggregatedReport report,
                                final Map<HeuristicCode, BaselineManager.Delta> deltas) {
        final StringBuilder out = new StringBuilder();
        final List<Finding> findings = report.findings();

        appendBanner(out, report.projectName());

        if (findings.isEmpty()) {
            out.append("\n  No violations found. The code is clean.\n");
            out.append('\n').append(HEADER).append('\n');
            return out.toString();
        }

        appendSeveritySummary(out, report);

        if (!deltas.isEmpty()) {
            BaselineDeltaFormatter.append(out, deltas);
        }

        FindingsByCodeFormatter.append(out, findings);
        appendToolSummary(out, findings);
        appendFooter(out, findings);

        return out.toString();
    }

    private static void appendBanner(final StringBuilder out, final String projectName) {
        out.append('\n').append(HEADER).append('\n');
        out.append("  CLEAN CODE ANALYSIS  —  ").append(projectName).append('\n');
        out.append(HEADER).append('\n');
    }

    private static void appendSeveritySummary(final StringBuilder out, final AggregatedReport report) {
        final Map<Severity, List<Finding>> bySeverity = report.bySeverity();

        out.append('\n');
        out.append("  ").append(severityCount(bySeverity, Severity.ERROR)).append(" errors");
        out.append("  ·  ").append(severityCount(bySeverity, Severity.WARNING)).append(" warnings");
        out.append("  ·  ").append(severityCount(bySeverity, Severity.INFO)).append(" info\n");
    }

    private static int severityCount(final Map<Severity, List<Finding>> bySeverity,
                                     final Severity severity) {
        return bySeverity.getOrDefault(severity, List.of()).size();
    }

    private static void appendToolSummary(final StringBuilder out, final List<Finding> findings) {
        final Map<String, Long> byTool = findings.stream()
                .collect(Collectors.groupingBy(Finding::tool, Collectors.counting()));

        out.append('\n').append(DIVIDER).append('\n');
        out.append("  Sources:\n");

        byTool.entrySet().stream()
                .sorted(Map.Entry.<String, Long>comparingByValue().reversed())
                .forEach(entry ->
                        out.append("    ").append(entry.getKey())
                                .append(": ").append(entry.getValue()).append('\n'));
    }

    private static void appendFooter(final StringBuilder out, final List<Finding> findings) {
        out.append('\n').append(HEADER).append('\n');
        out.append("  ").append(findings.size()).append(" findings");
        out.append("  —  ./gradlew cleanCodeExplain --finding=<code>\n");
        out.append(HEADER).append('\n');
    }
}

package org.fiftieshousewife.cleancode.core;

public enum RecipeThreshold {

    CLASS_LINE_COUNT(150),
    RECORD_COMPONENT_COUNT(6),
    NULL_CHECK_DENSITY(3),
    CHAIN_DEPTH_THRESHOLD(3),
    VERTICAL_SEPARATION_DISTANCE(10),
    METHOD_BLANK_LINE_SECTIONS(4),
    PRIVATE_METHOD_MIN_LINES(5),
    MAGIC_STRING_MIN_OCCURRENCES(2),
    STRING_SWITCH_MIN_CASES(3),
    SHORT_NAME_MIN_LENGTH(2),
    CPD_MINIMUM_TOKENS(50),
    MAGIC_NUMBER_MIN_VALUE(1),
    SECTION_COMMENT_THRESHOLD(1),
    HARDCODED_LIST_MIN_LITERALS(5),
    TEMPORAL_COUPLING_MIN_CALLS(3);

    private final int defaultValue;

    RecipeThreshold(final int defaultValue) {
        this.defaultValue = defaultValue;
    }

    public int defaultValue() {
        return defaultValue;
    }
}

package org.fiftieshousewife.cleancode.core;

import java.util.EnumMap;
import java.util.Map;

public final class RecipeThresholds {

    private final Map<RecipeThreshold, Integer> values;

    private RecipeThresholds(final Map<RecipeThreshold, Integer> values) {
        this.values = new EnumMap<>(values);
    }

    public static RecipeThresholds defaults() {
        final Map<RecipeThreshold, Integer> values = new EnumMap<>(RecipeThreshold.class);
        for (final RecipeThreshold threshold : RecipeThreshold.values()) {
            values.put(threshold, threshold.defaultValue());
        }
        return new RecipeThresholds(values);
    }

    public static RecipeThresholds of(final Map<RecipeThreshold, Integer> values) {
        final Map<RecipeThreshold, Integer> resolved = new EnumMap<>(RecipeThreshold.class);
        for (final RecipeThreshold threshold : RecipeThreshold.values()) {
            resolved.put(threshold, values.getOrDefault(threshold, threshold.defaultValue()));
        }
        return new RecipeThresholds(resolved);
    }

    public int get(final RecipeThreshold threshold) {
        return values.get(threshold);
    }

    public int classLineCount() {
        return get(RecipeThreshold.CLASS_LINE_COUNT);
    }

    public int recordComponentCount() {
        return get(RecipeThreshold.RECORD_COMPONENT_COUNT);
    }

    public int nullCheckDensity() {
        return get(RecipeThreshold.NULL_CHECK_DENSITY);
    }

    public int chainDepthThreshold() {
        return get(RecipeThreshold.CHAIN_DEPTH_THRESHOLD);
    }

    public int verticalSeparationDistance() {
        return get(RecipeThreshold.VERTICAL_SEPARATION_DISTANCE);
    }

    public int methodBlankLineSections() {
        return get(RecipeThreshold.METHOD_BLANK_LINE_SECTIONS);
    }

    public int privateMethodMinLines() {
        return get(RecipeThreshold.PRIVATE_METHOD_MIN_LINES);
    }

    public int magicStringMinOccurrences() {
        return get(RecipeThreshold.MAGIC_STRING_MIN_OCCURRENCES);
    }

    public int stringSwitchMinCases() {
        return get(RecipeThreshold.STRING_SWITCH_MIN_CASES);
    }

    public int shortNameMinLength() {
        return get(RecipeThreshold.SHORT_NAME_MIN_LENGTH);
    }

    public int cpdMinimumTokens() {
        return get(RecipeThreshold.CPD_MINIMUM_TOKENS);
