package org.fiftieshousewife.cleancode.plugin;

import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;

final class SkillTemplateResolver {

    private final ThresholdsExtension thresholds;

    SkillTemplateResolver(final ThresholdsExtension thresholds) {
        this.thresholds = thresholds;
    }

    String loadAndResolveTemplate(final String filename) {
        final String template = loadTemplateResource(filename);
        if (template == null) {
            return null;
        }
        return replaceTokens(template);
    }

    String resolveTemplateWithHash(final String filename, final String previousHash) {
        if (previousHash == null) {
            return null;
        }
        final String template = loadTemplateResource(filename);
        if (template == null) {
            return null;
        }
        final String[] values = parseThresholdsHash(previousHash);
        if (values == null) {
            return null;
        }
        return template
                .replace("{{classLineCount}}", values[0])
                .replace("{{classTargetLines}}", values[1])
                .replace("{{recordComponentCount}}", values[2]);
    }

    String replaceTokens(final String content) {
        return content
                .replace("{{classLineCount}}", String.valueOf(thresholds.getClassLineCount().get()))
                .replace("{{classTargetLines}}",
                        String.valueOf(thresholds.getClassLineCount().get() / 3))
                .replace("{{recordComponentCount}}",
                        String.valueOf(thresholds.getRecordComponentCount().get()));
    }

    String computeThresholdsHash() {
        final int classLineCount = thresholds.getClassLineCount().get();
        final int classTargetLines = classLineCount / 3;
        final int recordComponentCount = thresholds.getRecordComponentCount().get();
        return classLineCount + ":" + classTargetLines + ":" + recordComponentCount;
    }

    private String loadTemplateResource(final String filename) {
        try (InputStream is = getClass().getResourceAsStream("/skills/" + filename)) {
            if (is == null) {
                return null;
            }
            return new String(is.readAllBytes(), StandardCharsets.UTF_8);
        } catch (IOException e) {
            return null;
        }
    }

    private String[] parseThresholdsHash(final String hash) {
        final String[] parts = hash.split(":");
        if (parts.length != 3) {
            return null;
        }
        return parts;
    }
}

package org.fiftieshousewife.cleancode.plugin;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import org.gradle.api.logging.Logger;

final class SkillFileScaffolder {

    private static final List<String> SKILL_FILES = List.of(
            "SKILLS.md",
            "clean-code-exception-handling/SKILL.md",
            "clean-code-null-handling/SKILL.md",
            "clean-code-functions/SKILL.md",
            "clean-code-classes/SKILL.md",
            "clean-code-naming/SKILL.md",
            "clean-code-conditionals-and-expressions/SKILL.md",
            "clean-code-comments-and-clutter/SKILL.md",
            "clean-code-java-idioms/SKILL.md",
            "clean-code-test-quality/SKILL.md",
            "clean-code-project-conventions/SKILL.md");

    private static final String THRESHOLDS_HASH_FILE = ".thresholds-hash";

    private final Path skillsDir;
    private final SkillTemplateResolver resolver;
    private final Logger logger;

    SkillFileScaffolder(Path skillsDir,
            ThresholdsExtension thresholds, Logger logger) {
        this.skillsDir = skillsDir;
        this.resolver = new SkillTemplateResolver(thresholds);
        this.logger = logger;
    }

    void scaffold() {
        try {
            Files.createDirectories(skillsDir);
        } catch (IOException e) {
            logger.warn("Could not create skills directory: {}", skillsDir, e);
            return;
        }

        final String currentHash = resolver.computeThresholdsHash();
        final Path hashFile = skillsDir.resolve(THRESHOLDS_HASH_FILE);
        final String previousHash = readHashFile(hashFile);
        final boolean thresholdsChanged = !currentHash.equals(previousHash);

        SKILL_FILES.forEach(filename -> scaffoldFile(filename, thresholdsChanged, previousHash));

        writeHashFile(hashFile, currentHash);
    }

    private void scaffoldFile(String filename, boolean thresholdsChanged,
            String previousHash) {
        final Path target = skillsDir.resolve(filename);
        final String resolvedContent = resolver.loadAndResolveTemplate(filename);
        if (resolvedContent == null) {
            return;
        }

        if (!Files.exists(target)) {
            writeSkillFile(target, resolvedContent);
            return;
        }

        if (thresholdsChanged) {
            refreshIfUnmodified(target, filename, resolvedContent, previousHash);
        }
    }

    private void refreshIfUnmodified(Path target, String filename,
            String resolvedContent, String previousHash) {
        try {
            final String currentFileContent = Files.readString(target);
            final String previousTemplate = resolver.resolveTemplateWithHash(filename, previousHash);
            if (previousTemplate != null && currentFileContent.equals(previousTemplate)) {
                writeSkillFile(target, resolvedContent);
                logger.lifecycle("Refreshed skill file with new thresholds: {}", target);
            } else {
                logger.warn("Threshold changed but {} has been customised — manual update needed",
                        filename);
            }
        } catch (IOException e) {
            logger.warn("Could not read skill file for refresh: {}", filename, e);
        }
    }

    private void writeSkillFile(Path target, String content) {
        try {
            final Path parent = target.getParent();
            if (parent != null) {
                Files.createDirectories(parent);
            }
            Files.writeString(target, content);
            logger.lifecycle("Scaffolded skill file: {}", target);
        } catch (IOException e) {
            logger.warn("Could not write skill file: {}", target, e);
        }
    }

    private String readHashFile(Path hashFile) {
        try {
            if (Files.exists(hashFile)) {
                return Files.readString(hashFile).strip();
            }
        } catch (IOException ignored) {
        }
        return null;
    }

    private void writeHashFile(Path hashFile, String hash) {
        try {
            Files.writeString(hashFile, hash);
        } catch (IOException e) {
            logger.warn("Could not write thresholds hash: {}", hashFile, e);
        }
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.Severity;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;

public class CpdFindingSource implements FindingSource {

    private static final int ERROR_TOKEN_THRESHOLD = 200;

    private record DuplicationStats(int tokens, int lines, Severity severity) {}

    @Override
    public String id() {
        return "cpd";
    }

    @Override
    public String displayName() {
        return "CPD";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return Set.of(HeuristicCode.G5);
    }

    @Override
    public boolean isAvailable(final ProjectContext context) {
        return Files.exists(reportPath(context));
    }

    @Override
    public List<Finding> collectFindings(final ProjectContext context) throws FindingSourceException {
        final Optional<Document> doc = loadReport(context);
        if (doc.isEmpty()) {
            return List.of();
        }

        final List<Finding> findings = new ArrayList<>();
        final NodeList duplications = doc.get().getElementsByTagName("duplication");

        for (int i = 0; i < duplications.getLength(); i++) {
            findings.addAll(findingsForDuplication((Element) duplications.item(i), context));
        }

        return findings;
    }

    List<Finding> findingsForDuplication(final Element duplication, final ProjectContext context) {
        final int tokens = Integer.parseInt(duplication.getAttribute("tokens"));
        final int lines = Integer.parseInt(duplication.getAttribute("lines"));
        final DuplicationStats stats = new DuplicationStats(tokens, lines, severityForTokenCount(tokens));
        final List<Element> files = extractFileElements(duplication);

        final List<Finding> findings = new ArrayList<>();
        for (int i = 0; i < files.size(); i++) {
            findings.add(buildFinding(files, i, stats, context));
        }
        return findings;
    }

    Finding buildFinding(final List<Element> files, final int index,
                         final DuplicationStats stats, final ProjectContext context) {
        final Element file = files.get(index);
        final String relativePath = PathUtils.relativise(file.getAttribute("path"), context.projectRoot());
        final int startLine = Integer.parseInt(file.getAttribute("line"));
        final int endLine = startLine + stats.lines() - 1;

        final List<String> otherFiles = otherFilePaths(files, index, context);
        final Map<String, String> metadata = Map.of(
                "otherFile", String.join(", ", otherFiles),
                "tokens", String.valueOf(stats.tokens()));

        return new Finding(
                HeuristicCode.G5, relativePath, startLine, endLine,
                "Duplicated block (" + stats.tokens() + " tokens)",
                stats.severity(), Confidence.HIGH,
                "cpd", "cpd-duplication", metadata);
    }

    List<String> otherFilePaths(final List<Element> files, final int excludeIndex, final ProjectContext context) {
        final List<String> paths = new ArrayList<>();
        for (int i = 0; i < files.size(); i++) {
            if (i != excludeIndex) {
                paths.add(PathUtils.relativise(files.get(i).getAttribute("path"), context.projectRoot()));
            }
        }
        return paths;
    }

    Severity severityForTokenCount(final int tokens) {
        if (tokens >= ERROR_TOKEN_THRESHOLD) {
            return Severity.ERROR;
        }
        return Severity.WARNING;
    }

    private Optional<Document> loadReport(final ProjectContext context) {
        final Path report = reportPath(context);
        if (!Files.exists(report)) {
            return Optional.empty();
        }
        return Optional.of(XmlReportParser.parse(report));
    }

    private List<Element> extractFileElements(final Element duplication) {
        final NodeList fileNodes = duplication.getElementsByTagName("file");
        final List<Element> files = new ArrayList<>();
        for (int i = 0; i < fileNodes.getLength(); i++) {
            files.add((Element) fileNodes.item(i));
        }
        return files;
    }

    private Path reportPath(final ProjectContext context) {
        return context.reportsDir().resolve("cpd/cpd.xml");
    }
}

