package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.Severity;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.io.IOException;
import java.nio.file.DirectoryStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Set;

public class SurefireFindingSource implements FindingSource {

    private static final double SLOW_TEST_WARNING_SECONDS = 5.0;
    private static final double SLOW_TEST_ERROR_SECONDS = 30.0;
    private static final double SKIP_PERCENTAGE_THRESHOLD = 10.0;

    @Override
    public String id() {
        return "surefire";
    }

    @Override
    public String displayName() {
        return "Surefire";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return Set.of(HeuristicCode.T3, HeuristicCode.T4, HeuristicCode.T9);
    }

    @Override
    public boolean isAvailable(ProjectContext context) {
        final Path dir = reportsDir(context);
        if (!Files.isDirectory(dir)) {
            return false;
        }
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(dir, "TEST-*.xml")) {
            return stream.iterator().hasNext();
        } catch (IOException e) {
            return false;
        }
    }

    @Override
    public List<Finding> collectFindings(ProjectContext context) throws FindingSourceException {
        final Path dir = reportsDir(context);
        if (!Files.isDirectory(dir)) {
            return List.of();
        }

        try {
            final List<Finding> findings = new ArrayList<>();
            int totalTests = 0;
            int totalSkipped = 0;

            try (DirectoryStream<Path> stream = Files.newDirectoryStream(dir, "TEST-*.xml")) {
                for (final Path reportFile : stream) {
                    final Document doc = XmlReportParser.parse(reportFile);
                    final Element suite = doc.getDocumentElement();

                    totalTests += Integer.parseInt(suite.getAttribute("tests"));
                    totalSkipped += Integer.parseInt(suite.getAttribute("skipped"));

                    findings.addAll(findingsForSuite(doc));
                }
            }

            addSkipPercentageFinding(findings, totalSkipped, totalTests);
            return findings;
        } catch (Exception e) {
            throw new FindingSourceException("Failed to parse Surefire reports: " + dir, e);
        }
    }

    List<Finding> findingsForSuite(Document doc) {
        final List<Finding> findings = new ArrayList<>();
        final NodeList testcases = doc.getElementsByTagName("testcase");

        for (int i = 0; i < testcases.getLength(); i++) {
            final Element testcase = (Element) testcases.item(i);
            findingForTestCase(testcase).ifPresent(findings::add);
        }

        return findings;
    }

    Optional<Finding> findingForTestCase(Element testcase) {
        final String testName = testcase.getAttribute("name");
        final String className = testcase.getAttribute("classname");
        final String sourceFile = className.replace('.', '/') + ".java";

        if (isSkipped(testcase)) {
            return Optional.of(Finding.at(
                    HeuristicCode.T3, sourceFile, -1, -1,
                    String.format("Test '%s' is skipped", testName),
                    Severity.INFO, Confidence.HIGH, "surefire", "skipped-test"));
        }

        return findingForSlowTest(testcase, testName, sourceFile);
    }

    Optional<Finding> findingForSlowTest(Element testcase, String testName, String sourceFile) {
        final double time = Double.parseDouble(testcase.getAttribute("time"));
        if (time > SLOW_TEST_ERROR_SECONDS) {
            return Optional.of(slowTestFinding(testName, sourceFile, time, SLOW_TEST_ERROR_SECONDS, Severity.ERROR));
        }
        if (time > SLOW_TEST_WARNING_SECONDS) {
            return Optional.of(slowTestFinding(testName, sourceFile, time, SLOW_TEST_WARNING_SECONDS, Severity.WARNING));
        }
        return Optional.empty();
    }

    Finding slowTestFinding(String testName, String sourceFile, double time, double threshold, Severity severity) {
        return Finding.at(
                HeuristicCode.T9, sourceFile, -1, -1,
                String.format("Test '%s' took %.1fs (exceeds %.0fs threshold)", testName, time, threshold),
                severity, Confidence.HIGH, "surefire", "slow-test");
    }

    void addSkipPercentageFinding(List<Finding> findings, int totalSkipped, int totalTests) {
        if (totalTests <= 0) {
            return;
        }

        final double skipPercentage = (totalSkipped * 100.0) / totalTests;
        if (skipPercentage > SKIP_PERCENTAGE_THRESHOLD) {
            findings.add(Finding.projectLevel(
                    HeuristicCode.T3,
                    String.format("%.1f%% of tests are skipped (%d/%d)",
                            skipPercentage, totalSkipped, totalTests),
                    Severity.WARNING, Confidence.HIGH, "surefire", "skip-percentage"));
        }
    }

    private boolean isSkipped(Element testcase) {
        return testcase.getElementsByTagName("skipped").getLength() > 0;
    }

    private Path reportsDir(ProjectContext context) {
        return context.buildDir().resolve("test-results/test");
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.core.RecipeThreshold;
import org.fiftieshousewife.cleancode.core.RecipeThresholds;
import org.fiftieshousewife.cleancode.recipes.*;
import org.openrewrite.ScanningRecipe;

import java.util.List;

final class OpenRewriteRecipeFactory {

    private final RecipeThresholds thresholds;

    OpenRewriteRecipeFactory(final RecipeThresholds thresholds) {
        this.thresholds = thresholds;
    }

    List<ScanningRecipe<?>> createRecipes() {
        final List<ScanningRecipe<?>> recipes = new java.util.ArrayList<>();
        recipes.addAll(structuralRecipes());
        recipes.addAll(commentAndNamingRecipes());
        recipes.addAll(behaviouralRecipes());
        return List.copyOf(recipes);
    }

    private List<ScanningRecipe<?>> structuralRecipes() {
        return List.of(
                new FlagArgumentRecipe(),
                new OutputArgumentRecipe(),
                new CatchLogContinueRecipe(),
                new NegativeConditionalRecipe(),
                new LawOfDemeterRecipe(thresholds.get(RecipeThreshold.CHAIN_DEPTH_THRESHOLD)),
                new EncapsulateConditionalRecipe(),
                new NullDensityRecipe(thresholds.get(RecipeThreshold.NULL_CHECK_DENSITY)),
                new ClassLineLengthRecipe(thresholds.get(RecipeThreshold.CLASS_LINE_COUNT)),
                new LargeRecordRecipe(thresholds.get(RecipeThreshold.RECORD_COMPONENT_COUNT)),
                new DisabledTestRecipe(),
                new SwitchOnTypeRecipe(),
                new LargeConstructorRecipe(thresholds.get(RecipeThreshold.RECORD_COMPONENT_COUNT)),
                new VisibilityReductionRecipe(),
                new ImperativeLoopRecipe(),
                new UncheckedCastRecipe(),
                new FeatureEnvyRecipe(),
                new NestedTernaryRecipe());
    }

    private List<ScanningRecipe<?>> commentAndNamingRecipes() {
        return List.of(
                new CommentedCodeRecipe(),
                new MumblingCommentRecipe(),
                new SectionCommentRecipe(thresholds.get(RecipeThreshold.SECTION_COMMENT_THRESHOLD)),
                new EncodingNamingRecipe(),
                new VerticalSeparationRecipe(thresholds.get(RecipeThreshold.VERTICAL_SEPARATION_DISTANCE)),
                new InheritConstantsRecipe(),
                new EnumForConstantsRecipe(),
                new ShortVariableNameRecipe(thresholds.get(RecipeThreshold.SHORT_NAME_MIN_LENGTH)),
                new MagicStringRecipe(thresholds.get(RecipeThreshold.MAGIC_STRING_MIN_OCCURRENCES)),
                new WhitespaceSplitMethodRecipe(thresholds.get(RecipeThreshold.METHOD_BLANK_LINE_SECTIONS)),
                new PrivateMethodTestabilityRecipe(thresholds.get(RecipeThreshold.PRIVATE_METHOD_MIN_LINES)),
                new StringSwitchRecipe(thresholds.get(RecipeThreshold.STRING_SWITCH_MIN_CASES)),
                new SideEffectNamingRecipe(),
                new InconsistentNamingRecipe(),
                new BadClassNameRecipe(),
                new ObsoleteCommentRecipe(),
                new MissingExplanatoryVariableRecipe(),
                new BoundaryConditionRecipe());
    }

    private List<ScanningRecipe<?>> behaviouralRecipes() {
        return List.of(
                new SystemOutRecipe(),
                new LegacyFileApiRecipe(),
                new MultipleAssertRecipe(),
                new InappropriateStaticRecipe(),
                new StringlyTypedDispatchRecipe(),
                new ConfigurableDataRecipe(thresholds.get(RecipeThreshold.MAGIC_NUMBER_MIN_VALUE)),
                new EmbeddedLanguageRecipe(),
                new GuardClauseRecipe(),
                new BaseClassDependencyRecipe(),
                new ArtificialCouplingRecipe(),
                new HardcodedListRecipe(thresholds.get(RecipeThreshold.HARDCODED_LIST_MIN_LITERALS)),
                new SelectorArgumentRecipe(),
                new TemporalCouplingRecipe(thresholds.get(RecipeThreshold.TEMPORAL_COUPLING_MIN_CALLS)),
                new BroadCatchRecipe(),
                new RawGenericRecipe(),
                new SwallowedExceptionRecipe(),
                new InconsistentReturnRecipe(),
                new SuppressedWarningRecipe());
    }
}

