package org.fiftieshousewife.cleancode.claudereview;

import com.anthropic.client.AnthropicClient;
import com.anthropic.models.messages.CacheControlEphemeral;
import com.anthropic.models.messages.ContentBlock;
import com.anthropic.models.messages.Message;
import com.anthropic.models.messages.MessageCreateParams;
import com.anthropic.models.messages.TextBlockParam;
import org.fiftieshousewife.cleancode.core.Finding;

import java.util.List;
import java.util.logging.Level;
import java.util.logging.Logger;
import java.util.stream.Collectors;

final class ClaudeFileAnalyser {

    private static final Logger LOG = Logger.getLogger(ClaudeFileAnalyser.class.getName());
    private static final long MAX_TOKENS = 4096L;

    private final AnthropicClient client;
    private final String model;
    private final ClaudeFindingParser parser;

    ClaudeFileAnalyser(AnthropicClient client, String model, ClaudeFindingParser parser) {
        this.client = client;
        this.model = model;
        this.parser = parser;
    }

    List<Finding> analyse(AnalysisRequest request) {
        try {
            final String responseText = callApi(request);
            return parser.parse(responseText, request.relativePath());
        } catch (Exception e) {
            LOG.log(Level.WARNING, "Claude review failed for " + request.relativePath() + ": " + e.getMessage());
            return List.of();
        }
    }

    private String callApi(AnalysisRequest request) {
        final String userPrompt = "Assess this Java file for violations of: %s\n\nFile: %s\n\n%s"
                .formatted(request.codesKey(), request.relativePath(), addLineNumbers(request.content()));

        final MessageCreateParams params = MessageCreateParams.builder()
                .model(model)
                .maxTokens(MAX_TOKENS)
                .systemOfTextBlockParams(List.of(TextBlockParam.builder()
                        .text(request.systemPrompt())
                        .cacheControl(CacheControlEphemeral.builder().build())
                        .build()))
                .addUserMessage(userPrompt)
                .build();

        final Message response = client.messages().create(params);
        return response.content().stream()
                .filter(ContentBlock::isText)
                .map(block -> block.text().orElseThrow().text())
                .collect(Collectors.joining());
    }

    private static String addLineNumbers(String content) {
        final String[] lines = content.split("\n", -1);
        final StringBuilder sb = new StringBuilder();
        for (int i = 0; i < lines.length; i++) {
            sb.append(i + 1).append(": ").append(lines[i]).append('\n');
        }
        return sb.toString();
    }
}

package org.fiftieshousewife.cleancode.claudereview;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.Severity;

import java.util.List;
import java.util.Map;

final class FindingCacheMapper {

    private final String tool;

    FindingCacheMapper(String tool) {
        this.tool = tool;
    }

    List<Finding> toFindings(List<ReviewCache.CachedFinding> cached, String sourceFile) {
        return cached.stream()
                .map(cf -> new Finding(
                        HeuristicCode.valueOf(cf.code()), sourceFile,
                        cf.startLine(), cf.endLine(), cf.message(),
                        Severity.WARNING, Confidence.LOW, tool, cf.code(), Map.of()))
                .toList();
    }

    List<ReviewCache.CachedFinding> toCachedFindings(List<Finding> findings) {
        return findings.stream()
                .map(f -> new ReviewCache.CachedFinding(
                        f.code().name(), f.sourceFile(), f.startLine(), f.endLine(), f.message()))
                .toList();
    }
}

package org.fiftieshousewife.cleancode.claudereview;

import com.anthropic.client.AnthropicClient;
import com.anthropic.client.okhttp.AnthropicOkHttpClient;
import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;
import java.util.stream.Collectors;

public class ClaudeReviewFindingSource implements FindingSource {

    private static final String TOOL = "claude-review";
    private static final Logger LOG = Logger.getLogger(ClaudeReviewFindingSource.class.getName());

    private final ClaudeReviewConfig config;
    private final ClaudeFindingParser parser;
    private final FindingCacheMapper cacheMapper;
    private final SourceFileCollector fileCollector;
    private final SystemPromptLoader promptLoader;

    public ClaudeReviewFindingSource(ClaudeReviewConfig config) {
        this.config = config;
        this.parser = new ClaudeFindingParser(config.enabledCodes(), TOOL, config.model());
        this.cacheMapper = new FindingCacheMapper(TOOL);
        this.fileCollector = new SourceFileCollector(config.excludePatterns(), config.minFileLines());
        this.promptLoader = new SystemPromptLoader();
    }

    @Override
    public String id() {
        return TOOL;
    }

    @Override
    public String displayName() {
        return "Claude Review";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return config.enabledCodes();
    }

    @Override
    public boolean isAvailable(ProjectContext context) {
        return config.enabled() && config.hasApiKey();
    }

    @Override
    public List<Finding> collectFindings(ProjectContext context) throws FindingSourceException {
        if (!config.hasApiKey()) {
            return List.of();
        }
        final AnthropicClient client = AnthropicOkHttpClient.builder().apiKey(config.apiKey()).build();
        final ClaudeFileAnalyser analyser = new ClaudeFileAnalyser(client, config.model(), parser);
        final String systemPrompt = promptLoader.load();
        final String codesKey = buildCodesKey();
        final ReviewCache cache = ReviewCache.load(context.buildDir().resolve("claude-review-cache"));

        final List<Finding> allFindings = analyseAll(context, analyser, systemPrompt, codesKey, cache);
        persistCache(cache);
        return allFindings;
    }

    List<Finding> parseFindings(String json, String sourceFile) {
        return parser.parse(json, sourceFile);
    }

    private String buildCodesKey() {
        return config.enabledCodes().stream()
                .map(HeuristicCode::name)
                .sorted()
                .collect(Collectors.joining(","));
    }

    private List<Finding> analyseAll(ProjectContext context, ClaudeFileAnalyser analyser,
                                     String systemPrompt, String codesKey, ReviewCache cache) {
        final List<Path> files = fileCollector.collect(context);
        final List<Finding> allFindings = new ArrayList<>();
        int analysed = 0;
        for (final Path file : files) {
            if (analysed >= config.maxFilesPerRun()) {
                break;
            }
            if (analyseFile(file, context, analyser, systemPrompt, codesKey, cache, allFindings)) {
                analysed++;
            }
        }
        return allFindings;
    }

    private boolean analyseFile(Path file, ProjectContext context, ClaudeFileAnalyser analyser,
                                String systemPrompt, String codesKey, ReviewCache cache,
                                List<Finding> sink) {
        try {
            final String content = Files.readString(file, StandardCharsets.UTF_8);
            final String relativePath = context.projectRoot().relativize(file).toString();
            final String hash = ReviewCache.hash(content, codesKey);
            final var cached = cache.lookup(hash);
            if (cached.isPresent()) {
                sink.addAll(cacheMapper.toFindings(cached.get(), relativePath));
                return false;
            }
            final List<Finding> findings = analyser.analyse(
                    new AnalysisRequest(content, relativePath, systemPrompt, codesKey));
            cache.store(hash, cacheMapper.toCachedFindings(findings));
            sink.addAll(findings);
            return true;
        } catch (IOException e) {
            LOG.log(Level.WARNING, "Failed to read file: " + file, e);
            return false;
        }
    }

    private static void persistCache(ReviewCache cache) {
        try {
            cache.save();
        } catch (IOException e) {
            LOG.log(Level.WARNING, "Failed to save review cache", e);
        }
    }
}

