package org.fiftieshousewife.cleancode.core;

import com.github.javaparser.ast.Node;
import com.github.javaparser.ast.expr.AnnotationExpr;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.time.LocalDate;
import java.util.List;
import java.util.Set;

final class SuppressionMetaFindings {

    private static final String TOOL = "suppression-index";
    private static final String TODO = "TODO";

    private final List<Finding> sink;

    SuppressionMetaFindings(final List<Finding> sink) {
        this.sink = sink;
    }

    void recordIfExpired(final AnnotationExpr ann, final String sourceFile,
                         final Set<HeuristicCode> codes, final String until) {
        if (!isExpired(until)) {
            return;
        }
        final int beginLine = beginLineOf(ann);
        final int endLine = endLineOf(ann);
        sink.add(Finding.at(
                HeuristicCode.META_SUPPRESSION_EXPIRED, sourceFile,
                beginLine, endLine,
                "Suppression expired on " + until + " for " + codes,
                Severity.ERROR, Confidence.HIGH,
                TOOL, "expired-suppression"));
    }

    void recordIfBlankReason(final AnnotationExpr ann, final String sourceFile, final String reason) {
        if (isMeaningfulReason(reason)) {
            return;
        }
        final int beginLine = beginLineOf(ann);
        final int endLine = endLineOf(ann);
        sink.add(Finding.at(
                HeuristicCode.META_SUPPRESSION_NO_REASON, sourceFile,
                beginLine, endLine,
                "Suppression has no meaningful reason: '" + reason + "'",
                Severity.WARNING, Confidence.HIGH,
                TOOL, "blank-reason"));
    }

    private static boolean isExpired(final String until) {
        if (until.isEmpty()) {
            return false;
        }
        final LocalDate untilDate = LocalDate.parse(until);
        return untilDate.isBefore(LocalDate.now());
    }

    private static boolean isMeaningfulReason(final String reason) {
        return !reason.isBlank() && !TODO.equalsIgnoreCase(reason.trim());
    }

    private static int beginLineOf(final Node node) {
        return node.getBegin().map(p -> p.line).orElse(-1);
    }

    private static int endLineOf(final Node node) {
        return node.getEnd().map(p -> p.line).orElse(-1);
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

public final class BuildOutputFormatter {

    private static final String HEADER =
            "═══════════════════════════════════════════════════════════════════════════";
    private static final String DIVIDER =
            "───────────────────────────────────────────────────────────────────────────";
    private static final String METRIC_SEPARATOR = "  ·  ";

    private BuildOutputFormatter() {}

    public static String format(final AggregatedReport report) {
        return format(report, Map.of());
    }

    public static String format(final AggregatedReport report,
                                final Map<HeuristicCode, BaselineManager.Delta> deltas) {
        final StringBuilder out = new StringBuilder();
        appendBanner(out, report.projectName());
        if (report.findings().isEmpty()) {
            return appendNoViolations(out).toString();
        }
        return appendFindings(out, report, deltas).toString();
    }

    private static StringBuilder appendNoViolations(final StringBuilder out) {
        return out.append("\n  No violations found. The code is clean.\n")
                .append('\n').append(HEADER).append('\n');
    }

    private static StringBuilder appendFindings(final StringBuilder out,
                                                final AggregatedReport report,
                                                final Map<HeuristicCode, BaselineManager.Delta> deltas) {
        final List<Finding> findings = report.findings();
        appendSeveritySummary(out, report);
        if (!deltas.isEmpty()) {
            BaselineDeltaFormatter.append(out, deltas);
        }
        FindingsByCodeFormatter.append(out, findings);
        appendToolSummary(out, findings);
        appendFooter(out, findings);
        return out;
    }

    private static void appendBanner(final StringBuilder out, final String projectName) {
        out.append('\n').append(HEADER).append('\n')
                .append("  CLEAN CODE ANALYSIS  —  ").append(projectName).append('\n')
                .append(HEADER).append('\n');
    }

    private static void appendSeveritySummary(final StringBuilder out, final AggregatedReport report) {
        final Map<Severity, List<Finding>> bySeverity = report.bySeverity();
        out.append('\n')
                .append("  ").append(severityCount(bySeverity, Severity.ERROR)).append(" errors")
                .append(METRIC_SEPARATOR).append(severityCount(bySeverity, Severity.WARNING)).append(" warnings")
                .append(METRIC_SEPARATOR).append(severityCount(bySeverity, Severity.INFO)).append(" info\n");
    }

    private static int severityCount(final Map<Severity, List<Finding>> bySeverity,
                                     final Severity severity) {
        return bySeverity.getOrDefault(severity, List.of()).size();
    }

    private static void appendToolSummary(final StringBuilder out, final List<Finding> findings) {
        final Map<String, Long> byTool = findings.stream()
                .collect(Collectors.groupingBy(Finding::tool, Collectors.counting()));
        out.append('\n').append(DIVIDER).append('\n')
                .append("  Sources:\n");
        byTool.entrySet().stream()
                .sorted(Map.Entry.<String, Long>comparingByValue().reversed())
                .forEach(entry -> out.append("    ").append(entry.getKey())
                        .append(": ").append(entry.getValue()).append('\n'));
    }

    private static void appendFooter(final StringBuilder out, final List<Finding> findings) {
        out.append('\n').append(HEADER).append('\n')
                .append("  ").append(findings.size()).append(" findings")
                .append("  —  ./gradlew cleanCodeExplain --finding=<code>\n")
                .append(HEADER).append('\n');
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Statement;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Set;

public class CatchLogContinueRecipe extends ScanningRecipe<CatchLogContinueRecipe.Accumulator> {

    private static final Set<String> LOGGER_METHOD_NAMES = Set.of(
            "trace", "debug", "info", "warn", "error", "fatal", "log",
            "printStackTrace", "println");

    public record Row(String className, String methodName, String exceptionType, int lineNumber) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Catch-log-continue detection (Ch7.1)";
    }

    @Override
    public String getDescription() {
        return "Detects catch blocks whose body contains only logging or is empty.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new CatchLogContinueVisitor(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static final class CatchLogContinueVisitor extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;

        CatchLogContinueVisitor(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.Try visitTry(final J.Try tryStatement, final ExecutionContext ctx) {
            final J.Try t = super.visitTry(tryStatement, ctx);

            for (final J.Try.Catch catchClause : t.getCatches()) {
                if (isCatchLogContinue(catchClause)) {
                    final String className = findEnclosingClassName();
                    final String methodName = findEnclosingMethodName();
                    final String exceptionType = resolveExceptionType(catchClause);

                    acc.rows.add(new Row(className, methodName, exceptionType, -1));
                }
            }

            return t;
        }

        private String resolveExceptionType(final J.Try.Catch catchClause) {
            if (catchClause.getParameter().getTree().getTypeAsFullyQualified() != null) {
                return catchClause.getParameter().getTree().getTypeAsFullyQualified().getClassName();
            }
            if (catchClause.getParameter().getTree().getType() != null) {
                return catchClause.getParameter().getTree().getType().toString();
            }
            return "Exception";
        }

        private boolean isCatchLogContinue(final J.Try.Catch catchClause) {
            final List<Statement> statements = catchClause.getBody().getStatements();

            if (statements.isEmpty()) {
                return true;
            }

            if (containsThrow(statements)) {
                return false;
            }

            return statements.stream().allMatch(this::isLoggingStatement);
        }

        private boolean containsThrow(final List<Statement> statements) {
            return statements.stream().anyMatch(s -> s instanceof J.Throw);
        }

        private boolean isLoggingStatement(final Statement statement) {
            if (statement instanceof J.MethodInvocation invocation) {
                return isLoggerCall(invocation);
            }
            return false;
        }

        private boolean isLoggerCall(final J.MethodInvocation invocation) {
            final String methodName = invocation.getSimpleName();
            return LOGGER_METHOD_NAMES.contains(methodName);
        }

        private String findEnclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : "<unknown>";
        }

        private String findEnclosingMethodName() {
            final J.MethodDeclaration methodDecl = getCursor().firstEnclosing(J.MethodDeclaration.class);
            return methodDecl != null ? methodDecl.getSimpleName() : "<unknown>";
        }
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import org.openrewrite.ExecutionContext;
import org.openrewrite.Recipe;
import org.openrewrite.Tree;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Space;
import org.openrewrite.marker.Markers;

import java.util.ArrayList;
import java.util.List;
import java.util.Set;

public class AddFinalRecipe extends Recipe {

    @Override
    public String getDisplayName() {
        return "Add final to non-reassigned local variables";
    }

    @Override
    public String getDescription() {
        return "Adds the final modifier to local variables that are never reassigned after declaration.";
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor() {
        return new AddFinalMethodVisitor();
    }

    private static final class AddFinalMethodVisitor extends JavaIsoVisitor<ExecutionContext> {
        @Override
        public J.MethodDeclaration visitMethodDeclaration(J.MethodDeclaration method, ExecutionContext ctx) {
            final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
            if (m.getBody() == null) {
                return m;
            }
            final Set<String> reassigned = ReassignedVariableCollector.collect(m);
            return (J.MethodDeclaration) new AddFinalToLocalsVisitor().visit(m, reassigned);
        }
    }

    private static final class AddFinalToLocalsVisitor extends JavaIsoVisitor<Set<String>> {
        @Override
        public J.VariableDeclarations visitVariableDeclarations(
                J.VariableDeclarations varDecls, Set<String> reassignedNames) {
            final J.VariableDeclarations v = super.visitVariableDeclarations(varDecls, reassignedNames);
            if (shouldSkip(v, reassignedNames)) {
                return v;
            }
            return addFinalModifier(v);
        }
    }

    static boolean shouldSkip(J.VariableDeclarations v, Set<String> reassignedNames) {
        return isField(v) || isAlreadyFinal(v) || hasReassignedVariable(v, reassignedNames);
    }

    private static boolean hasReassignedVariable(J.VariableDeclarations v, Set<String> reassignedNames) {
        return v.getVariables().stream()
                .anyMatch(named -> reassignedNames.contains(named.getSimpleName()));
    }

    private static boolean isField(J.VariableDeclarations varDecls) {
        return varDecls.getModifiers().stream()
                .anyMatch(m -> m.getType() == J.Modifier.Type.Static
                        || m.getType() == J.Modifier.Type.Private
                        || m.getType() == J.Modifier.Type.Protected
                        || m.getType() == J.Modifier.Type.Public);
    }

    private static boolean isAlreadyFinal(J.VariableDeclarations varDecls) {
        return varDecls.getModifiers().stream()
                .anyMatch(m -> m.getType() == J.Modifier.Type.Final);
    }

    static J.VariableDeclarations addFinalModifier(J.VariableDeclarations varDecls) {
        final J.Modifier finalMod = new J.Modifier(
                Tree.randomId(),
                Space.EMPTY,
                Markers.EMPTY,
                null,
                J.Modifier.Type.Final,
                List.of());

        final List<J.Modifier> newModifiers = new ArrayList<>(varDecls.getModifiers());
        newModifiers.add(finalMod);

        final J.VariableDeclarations withMod = varDecls.withModifiers(newModifiers);

        if (varDecls.getTypeExpression() != null
                && varDecls.getTypeExpression().getPrefix().getWhitespace().isEmpty()) {
            return withMod.withTypeExpression(
                    varDecls.getTypeExpression().withPrefix(Space.SINGLE_SPACE));
        }
        return withMod;
    }
}

package org.fiftieshousewife.cleancode.plugin;

import java.util.Optional;

record ThresholdValues(int classLineCount, int classTargetLines, int recordComponentCount) {

    private static final String HASH_SEPARATOR = ":";
    private static final int HASH_PART_COUNT = 3;
    private static final int TARGET_LINES_DIVISOR = 3;

    static ThresholdValues from(final ThresholdsExtension thresholds) {
        final int classLineCount = thresholds.getClassLineCount().get();
        final int recordComponentCount = thresholds.getRecordComponentCount().get();
        return new ThresholdValues(
                classLineCount,
                classLineCount / TARGET_LINES_DIVISOR,
                recordComponentCount);
    }

    static Optional<ThresholdValues> parseHash(final String hash) {
        final String[] parts = hash.split(HASH_SEPARATOR);
        if (parts.length != HASH_PART_COUNT) {
            return Optional.empty();
        }
        try {
            return Optional.of(new ThresholdValues(
                    Integer.parseInt(parts[0]),
                    Integer.parseInt(parts[1]),
                    Integer.parseInt(parts[2])));
        } catch (NumberFormatException e) {
            return Optional.empty();
        }
    }

    String toHash() {
        return classLineCount + HASH_SEPARATOR + classTargetLines + HASH_SEPARATOR + recordComponentCount;
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import org.openrewrite.ExecutionContext;
import org.openrewrite.Recipe;
import org.openrewrite.SourceFile;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.JavaParser;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Statement;

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

public class RemoveNestedTernaryRecipe extends Recipe {

    private static final String RESULT_VAR = "result";
    private static final String ASSIGNMENT = " = ";
    private static final String BLOCK_CLOSE = "; }";
    private static final String WRAPPER_TEMPLATE =
            "class _T { Object _m() { Object result; %s return result; } }";

    @Override
    public String getDisplayName() {
        return "Replace nested ternary with if/else";
    }

    @Override
    public String getDescription() {
        return "Replaces nested ternary expressions in return statements with if/else chains. Fixes G16.";
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor() {
        return new NestedTernaryVisitor();
    }

    private static final class NestedTernaryVisitor extends JavaIsoVisitor<ExecutionContext> {
        @Override
        public J.Block visitBlock(J.Block block, ExecutionContext ctx) {
            final J.Block transformedBlock = super.visitBlock(block, ctx);
            final List<Statement> newStatements = new ArrayList<>();
            boolean changed = false;

            for (final Statement stmt : transformedBlock.getStatements()) {
                final List<Statement> replacement = rewriteStatement(stmt);
                if (replacement.isEmpty()) {
                    newStatements.add(stmt);
                } else {
                    newStatements.addAll(replacement);
                    changed = true;
                }
            }

            return changed ? transformedBlock.withStatements(newStatements) : transformedBlock;
        }

        private List<Statement> rewriteStatement(Statement stmt) {
            if (!isNestedTernaryReturn(stmt)) {
                return List.of();
            }
            final J.Ternary ternary = (J.Ternary) ((J.Return) stmt).getExpression();
            final String ifElse = ternaryToIfElse(ternary, RESULT_VAR);
            return parseReplacement(ifElse)
                    .map(statements -> applyPrefix(statements, stmt))
                    .orElseGet(List::of);
        }

        private Optional<List<Statement>> parseReplacement(String ifElseSource) {
            final String wrapper = WRAPPER_TEMPLATE.formatted(ifElseSource);
            final List<SourceFile> parsed = JavaParser.fromJavaVersion()
                    .logCompilationWarningsAndErrors(false)
                    .build().parse(wrapper).toList();

            if (parsed.isEmpty()) {
                return Optional.empty();
            }
            final J.MethodDeclaration method = (J.MethodDeclaration)
                    ((J.CompilationUnit) parsed.getFirst())
                            .getClasses().getFirst().getBody().getStatements().getFirst();
            return Optional.of(method.getBody().getStatements());
        }

        private List<Statement> applyPrefix(List<Statement> statements, Statement source) {
            final List<Statement> prefixed = new ArrayList<>();
            statements.forEach(s -> prefixed.add(s.withPrefix(source.getPrefix())));
            return prefixed;
        }
    }

    static boolean isNestedTernaryReturn(Statement stmt) {
        if (!(stmt instanceof J.Return ret) || ret.getExpression() == null) {
            return false;
        }
        if (!(ret.getExpression() instanceof J.Ternary ternary)) {
            return false;
        }
        return hasNestedTernary(ternary);
    }

    private static boolean hasNestedTernary(J.Ternary ternary) {
        return ternary.getTruePart() instanceof J.Ternary
                || ternary.getFalsePart() instanceof J.Ternary;
    }

    static String ternaryToIfElse(J.Ternary ternary, String varName) {
        final String condition = ternary.getCondition().toString().trim();
        final String truePart = ternary.getTruePart().toString().trim();
        final var falsePart = ternary.getFalsePart();

        final StringBuilder sb = new StringBuilder();
        sb.append("if (").append(condition).append(") { ")
                .append(varName).append(ASSIGNMENT).append(truePart).append(BLOCK_CLOSE);

        if (falsePart instanceof J.Ternary nested) {
            sb.append(" else ").append(ternaryToIfElse(nested, varName));
        } else {
            sb.append(" else { ").append(varName).append(ASSIGNMENT)
                    .append(falsePart.toString().trim()).append(BLOCK_CLOSE);
        }

        return sb.toString();
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.HashSet;
import java.util.Set;

final class ReassignedVariableCollector extends JavaIsoVisitor<Set<String>> {

    private final Set<String> reassigned = new HashSet<>();

    static Set<String> collect(J.MethodDeclaration method) {
        final ReassignedVariableCollector collector = new ReassignedVariableCollector();
        collector.visit(method.getBody(), collector.reassigned);
        return collector.reassigned;
    }

    @Override
    public J.Assignment visitAssignment(J.Assignment assignment, Set<String> unused) {
        if (assignment.getVariable() instanceof J.Identifier ident) {
            reassigned.add(ident.getSimpleName());
        }
        return super.visitAssignment(assignment, unused);
    }

    @Override
    public J.AssignmentOperation visitAssignmentOperation(J.AssignmentOperation assignOp, Set<String> unused) {
        if (assignOp.getVariable() instanceof J.Identifier ident) {
            reassigned.add(ident.getSimpleName());
        }
        return super.visitAssignmentOperation(assignOp, unused);
    }

    @Override
    public J.Unary visitUnary(J.Unary unary, Set<String> unused) {
        if (isIncrementOrDecrement(unary) && unary.getExpression() instanceof J.Identifier ident) {
            reassigned.add(ident.getSimpleName());
        }
        return super.visitUnary(unary, unused);
    }

    private static boolean isIncrementOrDecrement(J.Unary unary) {
        final J.Unary.Type operator = unary.getOperator();
        final boolean isPreIncrementOrDecrement =
                operator == J.Unary.Type.PreIncrement || operator == J.Unary.Type.PreDecrement;
        final boolean isPostIncrementOrDecrement =
                operator == J.Unary.Type.PostIncrement || operator == J.Unary.Type.PostDecrement;
        return isPreIncrementOrDecrement || isPostIncrementOrDecrement;
    }
}

package org.fiftieshousewife.cleancode.core;

import java.io.IOException;
import java.io.InputStream;
import java.io.UncheckedIOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.ZoneOffset;
import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.Map;

import static org.fiftieshousewife.cleancode.core.HtmlEscaping.escape;
import static org.fiftieshousewife.cleancode.core.HtmlFindingsRenderer.appendFindingsByCode;
import static org.fiftieshousewife.cleancode.core.HtmlFindingsRenderer.appendToolSummary;

public final class HtmlReportWriter {

    private static final String TEMPLATE_RESOURCE = "/org/fiftieshousewife/cleancode/core/html-report.html";
    private static final String TEMPLATE = loadTemplate();

    private static final DateTimeFormatter TIMESTAMP_FORMAT =
            DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss z").withZone(ZoneOffset.UTC);

    private static final String NO_FINDINGS_BODY =
            "    <p class=\"clean\">No violations found. The code is clean.</p>\n";

    private HtmlReportWriter() {}

    public static void write(final AggregatedReport report, final Path outputFile) throws IOException {
        write(report, outputFile, "");
    }

    public static void write(final AggregatedReport report, final Path outputFile,
                              final String repositoryUrl) throws IOException {
        final Path parent = outputFile.getParent();
        if (parent != null) {
            Files.createDirectories(parent);
        }
        Files.writeString(outputFile, render(report, repositoryUrl));
    }

    static String render(final AggregatedReport report, final String repositoryUrl) {
        return TEMPLATE
                .replace("{projectName}", escape(report.projectName()))
                .replace("{styles}", HtmlReportStyles.css())
                .replace("{projectHeading}", projectHeading(report))
                .replace("{errorCount}", severityCount(report, Severity.ERROR))
                .replace("{warningCount}", severityCount(report, Severity.WARNING))
                .replace("{infoCount}", severityCount(report, Severity.INFO))
                .replace("{body}", body(report, repositoryUrl))
                .replace("{timestamp}", escape(TIMESTAMP_FORMAT.format(report.generatedAt())))
                .replace("{totalFindings}", Integer.toString(report.findings().size()));
    }

    static String projectHeading(final AggregatedReport report) {
        final String name = escape(report.projectName());
        if (report.projectVersion() == null) {
            return name;
        }
        return name + " v" + escape(report.projectVersion());
    }

    static String severityCount(final AggregatedReport report, final Severity severity) {
        final Map<Severity, List<Finding>> bySeverity = report.bySeverity();
        return Integer.toString(bySeverity.getOrDefault(severity, List.of()).size());
    }

    static String body(final AggregatedReport report, final String repositoryUrl) {
        if (report.findings().isEmpty()) {
            return NO_FINDINGS_BODY;
        }
        final StringBuilder html = new StringBuilder();
        appendFindingsByCode(html, report.findings(), repositoryUrl);
        appendToolSummary(html, report.findings());
        return html.toString();
    }

    private static String loadTemplate() {
        try (InputStream stream = HtmlReportWriter.class.getResourceAsStream(TEMPLATE_RESOURCE)) {
            if (stream == null) {
                throw new IllegalStateException("Missing HTML template resource: " + TEMPLATE_RESOURCE);
            }
            return new String(stream.readAllBytes(), StandardCharsets.UTF_8);
        } catch (final IOException exception) {
            throw new UncheckedIOException("Failed to load HTML template: " + TEMPLATE_RESOURCE, exception);
        }
    }
}

