package org.fiftieshousewife.cleancode.core;

import com.google.gson.Gson;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.Instant;
import java.util.EnumSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

public final class JsonReportReader {

    private JsonReportReader() {}

    private record JsonReport(
            String projectName,
            String projectVersion,
            String generatedAt,
            List<JsonFinding> findings
    ) {}

    private record JsonFinding(
            String code,
            String sourceFile,
            int startLine,
            int endLine,
            String message,
            String severity,
            String confidence,
            String tool,
            String ruleRef,
            Map<String, String> metadata
    ) {}

    public static AggregatedReport read(final Path inputFile) throws IOException {
        final JsonReport jsonReport = parseJson(inputFile);
        final List<Finding> findings = jsonReport.findings().stream()
                .map(JsonReportReader::toFinding)
                .toList();
        return new AggregatedReport(
                findings,
                coveredCodes(findings),
                Instant.parse(jsonReport.generatedAt()),
                jsonReport.projectName(),
                jsonReport.projectVersion());
    }

    private static JsonReport parseJson(final Path inputFile) throws IOException {
        final String json = Files.readString(inputFile);
        return new Gson().fromJson(json, JsonReport.class);
    }

    private static Finding toFinding(final JsonFinding raw) {
        return new Finding(
                HeuristicCode.valueOf(raw.code()),
                raw.sourceFile(),
                raw.startLine(),
                raw.endLine(),
                raw.message(),
                Severity.valueOf(raw.severity()),
                Confidence.valueOf(raw.confidence()),
                raw.tool(),
                raw.ruleRef(),
                raw.metadata() != null ? raw.metadata() : Map.of());
    }

    private static Set<HeuristicCode> coveredCodes(final List<Finding> findings) {
        final Set<HeuristicCode> codes = EnumSet.noneOf(HeuristicCode.class);
        findings.forEach(finding -> codes.add(finding.code()));
        return codes;
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonProperty;
import org.openrewrite.ExecutionContext;
import org.openrewrite.Recipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Space;

import java.util.List;

public class ReduceVisibilityRecipe extends Recipe {

    private final int minLines;

    @JsonCreator
    public ReduceVisibilityRecipe(@JsonProperty("minLines") final int minLines) {
        this.minLines = minLines;
    }

    @Override
    public String getDisplayName() {
        return "Reduce private method visibility for testability";
    }

    @Override
    public String getDescription() {
        return "Changes private methods with %d+ statements to package-private for direct testing. Fixes Ch3.1."
                .formatted(minLines);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor() {
        return new ReduceVisibilityVisitor(minLines);
    }

    static boolean isPrivate(final J.MethodDeclaration method) {
        return method.getModifiers().stream().anyMatch(mod -> mod.getType() == J.Modifier.Type.Private);
    }

    static boolean isShorterThan(final J.MethodDeclaration method, final int minLines) {
        return method.getBody() == null || method.getBody().getStatements().size() < minLines;
    }

    static List<J.Modifier> modifiersWithoutPrivate(final J.MethodDeclaration method) {
        return method.getModifiers().stream()
                .filter(mod -> mod.getType() != J.Modifier.Type.Private)
                .toList();
    }

    static J.MethodDeclaration preservePrefixOnReturnType(
            final J.MethodDeclaration updated, final J.MethodDeclaration original) {
        if (original.getReturnTypeExpression() == null) {
            return updated;
        }
        final Space originalPrivatePrefix = original.getModifiers().getFirst().getPrefix();
        return updated.withReturnTypeExpression(
                original.getReturnTypeExpression().withPrefix(originalPrivatePrefix));
    }

    private static final class ReduceVisibilityVisitor extends JavaIsoVisitor<ExecutionContext> {

        private final int minLines;

        ReduceVisibilityVisitor(final int minLines) {
            this.minLines = minLines;
        }

        @Override
        public J.MethodDeclaration visitMethodDeclaration(
                final J.MethodDeclaration method, final ExecutionContext ctx) {
            final J.MethodDeclaration visited = super.visitMethodDeclaration(method, ctx);
            if (shouldSkip(visited)) {
                return visited;
            }
            return removePrivateModifier(visited);
        }

        private boolean shouldSkip(final J.MethodDeclaration method) {
            return !isPrivate(method) || isShorterThan(method, minLines);
        }

        private J.MethodDeclaration removePrivateModifier(final J.MethodDeclaration method) {
            final J.MethodDeclaration updated = method.withModifiers(modifiersWithoutPrivate(method));
            return preservePrefixOnReturnType(updated, method);
        }
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;

public final class ClaudeMdGenerator {

    private static final List<HeuristicCode> NARRATIVE_STUB_CODES = List.of(
            HeuristicCode.G2, HeuristicCode.G3, HeuristicCode.G6, HeuristicCode.G13,
            HeuristicCode.G20, HeuristicCode.G21, HeuristicCode.G31, HeuristicCode.G32
    );

    private ClaudeMdGenerator() {}

    public static void generate(final AggregatedReport report, final Path claudeMdFile,
                                final Path baselineFile) throws IOException {
        generate(report, claudeMdFile, baselineFile, List.of());
    }

    public static void generate(final AggregatedReport report, final Path claudeMdFile,
                                final Path baselineFile,
                                final List<String> dependencies) throws IOException {
        final Map<String, String> preservedAnnotations = loadPreservedAnnotations(claudeMdFile);

        final String preamble = buildPreamble();
        final String frameworks = buildFrameworksSection(dependencies);
        final String deltaTable = buildDeltaTable(report, baselineFile);
        final String findingSections = buildFindingSections(report, preservedAnnotations);
        final String narrativeStubs = buildNarrativeStubs(report, preservedAnnotations);

        Files.writeString(claudeMdFile, preamble + frameworks + deltaTable + findingSections + narrativeStubs);
    }

    private static Map<String, String> loadPreservedAnnotations(final Path claudeMdFile) throws IOException {
        final Map<String, String> preservedAnnotations = new LinkedHashMap<>();
        if (Files.exists(claudeMdFile)) {
            preservedAnnotations.putAll(AnnotateSectionParser.parse(Files.readString(claudeMdFile)));
        }
        return preservedAnnotations;
    }

    static String buildPreamble() {
        return """
                ## Before you start any work in this codebase

                1. Read `.claude/skills/SKILLS.md` now, before reading anything else.
                   This is mandatory, not optional.
                2. When a finding section below points to a skill file, read it before
                   acting on that finding.
                3. When working on anything not covered by a finding, check SKILLS.md
                   for a matching skill before proceeding.

                """;
    }

    private static String buildFrameworksSection(final List<String> dependencies) {
        final List<String> frameworks = FrameworkRegistry.detect(dependencies);
        if (frameworks.isEmpty()) {
            return "";
        }
        final StringBuilder sb = new StringBuilder("## Frameworks in use\n\n");
        frameworks.forEach(f -> sb.append(String.format("- %s%n", f)));
        sb.append('\n');
        return sb.toString();
    }

    private static String buildDeltaTable(final AggregatedReport report, final Path baselineFile) throws IOException {
        final StringBuilder sb = new StringBuilder();
        DeltaTableWriter.append(sb, report, baselineFile);
        return sb.toString();
    }

    private static String buildNarrativeStubs(final AggregatedReport report,
                                              final Map<String, String> preservedAnnotations) {
        final Set<HeuristicCode> codesWithFindings = report.byCode().keySet();
        final StringBuilder sb = new StringBuilder();
        NARRATIVE_STUB_CODES.stream()
                .filter(code -> !codesWithFindings.contains(code))
                .forEach(code -> {
                    final String codeName = code.name();
                    final String heading = HeuristicDescriptions.name(code);
                    sb.append(String.format("## %s: %s%n", codeName, heading));
                    sb.append("> This heuristic requires human judgment"
                            + " \u2014 no automated detection available.\n\n");
                    sb.append(String.format("<!-- ANNOTATE: %s -->%n", codeName));
                    if (preservedAnnotations.containsKey(codeName)) {
                        sb.append(preservedAnnotations.get(codeName));
                    } else {
                        sb.append("<!-- Add project-specific guidance for this heuristic here -->\n");
                    }
                    sb.append("<!-- /ANNOTATE -->\n\n");
                });
        return sb.toString();
    }

    private static String buildFindingSections(final AggregatedReport report,
                                               final Map<String, String> preservedAnnotations) {
        final StringBuilder sb = new StringBuilder();
        report.byCode().forEach((code, findings) -> sb.append(buildFindingSection(code, findings, preservedAnnotations)));
        return sb.toString();
    }

    private static String buildFindingSection(final HeuristicCode code, final List<Finding> findings,
                                              final Map<String, String> preservedAnnotations) {
        return sectionHeading(code, findings)
                + skillPointerLine(code)
                + preservedAnnotationBlock(code, preservedAnnotations)
                + generatedFindingsBlock(code, findings);
    }

    private static String sectionHeading(final HeuristicCode code, final List<Finding> findings) {
        return String.format("## %s [%d finding%s]%n", code.name(),
                findings.size(), findings.size() == 1 ? "" : "s");
    }

    private static String skillPointerLine(final HeuristicCode code) {
        final String skillPath = SkillPathRegistry.skillPathFor(code);
        if (skillPath == null) {
            return "\n";
        }
        return String.format("> Read `%s` before addressing these.%n%n", skillPath);
    }

    private static String preservedAnnotationBlock(final HeuristicCode code,
                                                   final Map<String, String> preservedAnnotations) {
        final String annotateKey = code.name();
        if (!preservedAnnotations.containsKey(annotateKey)) {
            return "";
        }
        return String.format("<!-- ANNOTATE: %s -->%n", annotateKey)
                + preservedAnnotations.get(annotateKey)
                + String.format("<!-- /ANNOTATE -->%n%n");
    }

    private static String generatedFindingsBlock(final HeuristicCode code, final List<Finding> findings) {
        final StringBuilder sb = new StringBuilder();
        sb.append(String.format("<!-- GENERATED: %s -->%n", code.name()));
        sb.append("**From analysis:**\n");
        findings.forEach(f -> sb.append(formatFinding(f)));
        sb.append("<!-- /GENERATED -->\n\n");
        return sb.toString();
    }

    private static String formatFinding(final Finding finding) {
        if (finding.sourceFile() != null) {
            return String.format("- %s:%d%n", finding.sourceFile(), finding.startLine());
        }
        return String.format("- (project-level) %s%n", finding.message());
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class VisibilityReductionRecipe extends ScanningRecipe<VisibilityReductionRecipe.Accumulator> {

    public record Row(String className, String fieldName, String currentVisibility, int lineNumber) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Visibility reduction detection (G8)";
    }

    @Override
    public String getDescription() {
        return "Detects public mutable (non-final, non-static) instance fields that should almost always be private.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new JavaIsoVisitor<>() {
            @Override
            public J.VariableDeclarations visitVariableDeclarations(J.VariableDeclarations multiVariable,
                                                                    ExecutionContext ctx) {
                final J.VariableDeclarations vd = super.visitVariableDeclarations(multiVariable, ctx);
                if (isReducibleVisibilityField(getCursor(), vd)) {
                    acc.rows.addAll(rowsFor(findEnclosingClassName(getCursor()), vd));
                }
                return vd;
            }
        };
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static boolean isReducibleVisibilityField(org.openrewrite.Cursor cursor, J.VariableDeclarations vd) {
        return isFieldDeclaration(cursor) && isPublicInstanceMutableField(vd);
    }

    private static boolean isFieldDeclaration(org.openrewrite.Cursor cursor) {
        return cursor.firstEnclosing(J.MethodDeclaration.class) == null
                && cursor.firstEnclosing(J.ClassDeclaration.class) != null;
    }

    private static boolean isPublicInstanceMutableField(J.VariableDeclarations vd) {
        return hasModifier(vd, J.Modifier.Type.Public)
                && !hasModifier(vd, J.Modifier.Type.Static)
                && !hasModifier(vd, J.Modifier.Type.Final);
    }

    private static boolean hasModifier(J.VariableDeclarations vd, J.Modifier.Type type) {
        return vd.getModifiers().stream().anyMatch(mod -> mod.getType() == type);
    }

    private static String findEnclosingClassName(org.openrewrite.Cursor cursor) {
        final J.ClassDeclaration classDecl = cursor.firstEnclosing(J.ClassDeclaration.class);
        return classDecl != null ? classDecl.getSimpleName() : "<unknown>";
    }

    private static List<Row> rowsFor(String className, J.VariableDeclarations vd) {
        return vd.getVariables().stream()
                .map(var -> new Row(className, var.getSimpleName(), "public", -1))
                .toList();
    }
}

