package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.RecipeThresholds;
import org.openrewrite.ExecutionContext;
import org.openrewrite.InMemoryExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.SourceFile;
import org.openrewrite.internal.InMemoryLargeSourceSet;
import org.openrewrite.java.JavaParser;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.stream.Stream;

public class OpenRewriteFindingSource implements FindingSource {

    private static final String TOOL = "openrewrite";
    private static final String JAVA_EXTENSION = ".java";
    private static final int JAVA_EXTENSION_LENGTH = JAVA_EXTENSION.length();
    private static final char PATH_SEPARATOR = '/';

    private static final Set<HeuristicCode> COVERED = Set.of(
            HeuristicCode.F1, HeuristicCode.F2, HeuristicCode.F3,
            HeuristicCode.C3, HeuristicCode.C5,
            HeuristicCode.Ch3_1,
            HeuristicCode.Ch7_1, HeuristicCode.Ch7_2,
            HeuristicCode.Ch10_1, HeuristicCode.Ch10_2,
            HeuristicCode.G4, HeuristicCode.G8,
            HeuristicCode.G10, HeuristicCode.G11, HeuristicCode.G14,
            HeuristicCode.G16, HeuristicCode.G19,
            HeuristicCode.G23, HeuristicCode.G25, HeuristicCode.G26,
            HeuristicCode.G28, HeuristicCode.G29,
            HeuristicCode.G30, HeuristicCode.G33, HeuristicCode.G34, HeuristicCode.G36,
            HeuristicCode.J2, HeuristicCode.J3,
            HeuristicCode.N1, HeuristicCode.N5, HeuristicCode.N6, HeuristicCode.N7,
            HeuristicCode.T1, HeuristicCode.T3, HeuristicCode.T4);

    private final OpenRewriteRecipeFactory recipeFactory;

    public OpenRewriteFindingSource() {
        this(RecipeThresholds.defaults());
    }

    public OpenRewriteFindingSource(final RecipeThresholds thresholds) {
        this.recipeFactory = new OpenRewriteRecipeFactory(thresholds);
    }

    @Override
    public String id() {
        return TOOL;
    }

    @Override
    public String displayName() {
        return "OpenRewrite";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return COVERED;
    }

    @Override
    public List<Finding> collectFindings(final ProjectContext context) throws FindingSourceException {
        final List<Path> javaFiles = collectSourceFiles(context);
        if (javaFiles.isEmpty()) {
            return List.of();
        }

        final List<SourceFile> parsed = parseSourceFiles(javaFiles);
        final Map<String, String> sourcePathIndex = buildSourcePathIndex(parsed);
        final List<ScanningRecipe<?>> recipes = recipeFactory.createRecipes();
        recipes.forEach(recipe -> runRecipe(parsed, recipe));
        return extractFindings(recipes, sourcePathIndex);
    }

    private Map<String, String> buildSourcePathIndex(final List<SourceFile> parsed) {
        final Map<String, String> index = new HashMap<>();
        parsed.forEach(sf -> {
            final String path = sf.getSourcePath().toString();
            final String fileName = extractFileName(path);
            final String className = stripJavaExtension(fileName);
            index.put(className, path);
        });
        return index;
    }

    private String extractFileName(final String path) {
        if (!path.contains(String.valueOf(PATH_SEPARATOR))) {
            return path;
        }
        final int fileNameStart = path.lastIndexOf(PATH_SEPARATOR) + 1;
        return path.substring(fileNameStart);
    }

    private String stripJavaExtension(final String fileName) {
        if (!fileName.endsWith(JAVA_EXTENSION)) {
            return fileName;
        }
        return fileName.substring(0, fileName.length() - JAVA_EXTENSION_LENGTH);
    }

    private List<Finding> extractFindings(final List<ScanningRecipe<?>> recipes,
                                          final Map<String, String> sourcePathIndex) {
        final OpenRewriteFindingMapper mapper = new OpenRewriteFindingMapper(sourcePathIndex);
        final List<Finding> findings = new ArrayList<>();
        recipes.forEach(recipe -> findings.addAll(mapper.mapRecipe(recipe)));
        return findings;
    }

    private List<Path> collectSourceFiles(final ProjectContext context) {
        return context.sourceRoots().stream()
                .filter(Files::isDirectory)
                .flatMap(this::javaFilesUnder)
                .toList();
    }

    private Stream<Path> javaFilesUnder(final Path root) {
        try (Stream<Path> walk = Files.walk(root)) {
            return walk.filter(p -> p.toString().endsWith(JAVA_EXTENSION)).toList().stream();
        } catch (IOException unreadableRoot) {
            return skipUnreadable(root, unreadableRoot);
        }
    }

    /**
     * Source file collection is best-effort: an unreadable root contributes
     * no files but must not abort the whole run. Named method so the catch
     * block documents its intent rather than being a silently empty block.
     */
    @SuppressWarnings("unused")
    private Stream<Path> skipUnreadable(final Path root, final IOException cause) {
        return Stream.empty();
    }

    private List<SourceFile> parseSourceFiles(final List<Path> files) {
        return JavaParser.fromJavaVersion()
                .logCompilationWarningsAndErrors(false)
                .build()
                .parse(files, null, new InMemoryExecutionContext(Throwable::printStackTrace))
                .toList();
    }

    private void runRecipe(final List<SourceFile> parsed, final ScanningRecipe<?> recipe) {
        final ExecutionContext ctx = new InMemoryExecutionContext(Throwable::printStackTrace);
        recipe.run(new InMemoryLargeSourceSet(parsed), ctx);
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.Severity;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Collections;
import java.util.EnumSet;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Properties;
import java.util.Set;
import java.util.stream.IntStream;
import java.util.stream.Stream;

public class CheckstyleFindingSource implements FindingSource {

    private record RuleMapping(HeuristicCode code, Severity severity, Confidence confidence, String ruleUrl) {}

    private static final String CHECKSTYLE_DOCS_BASE = "https://checkstyle.org/checks/";
    private static final String RULE_MAPPING_RESOURCE = "/checkstyle/rule-mapping.properties";
    private static final String CHECK_SUFFIX = "Check";
    private static final String TOOL_ID = "checkstyle";
    private static final String REPORT_PATH = "checkstyle/main.xml";
    private static final String RULE_URL_KEY = "ruleUrl";
    private static final String FIELD_SEPARATOR = "\\|";

    private static final Map<String, RuleMapping> RULE_MAP = loadRuleMap();

    @Override
    public String id() {
        return TOOL_ID;
    }

    @Override
    public String displayName() {
        return "Checkstyle";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        final Set<HeuristicCode> codes = EnumSet.noneOf(HeuristicCode.class);
        RULE_MAP.values().forEach(m -> codes.add(m.code()));
        return Collections.unmodifiableSet(codes);
    }

    @Override
    public boolean isAvailable(final ProjectContext context) {
        return Files.exists(reportPath(context));
    }

    @Override
    public List<Finding> collectFindings(final ProjectContext context) throws FindingSourceException {
        final Path report = reportPath(context);
        if (!Files.exists(report)) {
            return List.of();
        }
        try {
            return elementsOf(XmlReportParser.parse(report).getElementsByTagName("file"))
                    .flatMap(file -> findingsFromFile(file, context))
                    .toList();
        } catch (final Exception e) {
            throw new FindingSourceException("Failed to parse Checkstyle report: " + report, e);
        }
    }

    private Stream<Finding> findingsFromFile(final Element fileElement, final ProjectContext context) {
        final String relativePath = PathUtils.relativise(fileElement.getAttribute("name"), context.projectRoot());
        return elementsOf(fileElement.getElementsByTagName("error"))
                .map(error -> toFinding(error, relativePath))
                .filter(Optional::isPresent)
                .map(Optional::get);
    }

    private Optional<Finding> toFinding(final Element error, final String relativePath) {
        final String checkName = extractCheckName(error.getAttribute("source"));
        final RuleMapping mapping = RULE_MAP.get(checkName);
        if (mapping == null) {
            return Optional.empty();
        }
        final int line = Integer.parseInt(error.getAttribute("line"));
        final Severity severity = xmlSeverityOrDefault(error.getAttribute("severity"), mapping.severity());
        return Optional.of(new Finding(
                mapping.code(), relativePath, line, line,
                error.getAttribute("message"), severity, mapping.confidence(),
                TOOL_ID, checkName, Map.of(RULE_URL_KEY, mapping.ruleUrl())));
    }

    private Path reportPath(final ProjectContext context) {
        return context.reportsDir().resolve(REPORT_PATH);
    }

    String extractCheckName(final String sourceFqn) {
        final int lastDot = sourceFqn.lastIndexOf('.');
        final String simpleName = lastDot >= 0 ? sourceFqn.substring(lastDot + 1) : sourceFqn;
        if (simpleName.endsWith(CHECK_SUFFIX)) {
            return simpleName.substring(0, simpleName.length() - CHECK_SUFFIX.length());
        }
        return simpleName;
    }

    private Severity xmlSeverityOrDefault(final String xmlSeverity, final Severity defaultSeverity) {
        return switch (xmlSeverity) {
            case "error" -> Severity.ERROR;
            case "info" -> Severity.INFO;
            case "warning" -> Severity.WARNING;
            default -> defaultSeverity;
        };
    }

    private static Stream<Element> elementsOf(final NodeList nodes) {
        return IntStream.range(0, nodes.getLength()).mapToObj(i -> (Element) nodes.item(i));
    }

    private static Map<String, RuleMapping> loadRuleMap() {
        final Properties properties = new Properties();
        try (InputStream stream = CheckstyleFindingSource.class.getResourceAsStream(RULE_MAPPING_RESOURCE)) {
            if (stream == null) {
                throw new IllegalStateException("Missing resource: " + RULE_MAPPING_RESOURCE);
            }
            properties.load(stream);
        } catch (final IOException e) {
            throw new IllegalStateException("Failed to load " + RULE_MAPPING_RESOURCE, e);
        }
        final Map<String, RuleMapping> map = new HashMap<>();
        properties.forEach((key, value) -> map.put(key.toString(), parseRuleMapping(value.toString())));
        return Collections.unmodifiableMap(map);
    }

    private static RuleMapping parseRuleMapping(final String value) {
        final String[] parts = value.split(FIELD_SEPARATOR);
        if (parts.length != 4) {
            throw new IllegalStateException("Invalid rule mapping format: " + value);
        }
        return new RuleMapping(
                HeuristicCode.valueOf(parts[0].trim()),
                Severity.valueOf(parts[1].trim()),
                Confidence.valueOf(parts[2].trim()),
                CHECKSTYLE_DOCS_BASE + parts[3].trim());
    }
}

