package org.fiftieshousewife.cleancode.plugin;

import org.gradle.api.Project;
import org.gradle.api.tasks.TaskProvider;

final class CleanCodeTaskRegistrar {

    private static final String DEPENDENCY_UPDATES_TASK = "dependencyUpdates";
    private static final String VERIFICATION_GROUP = "verification";
    private static final String HELP_GROUP = "help";

    private final Project project;

    CleanCodeTaskRegistrar(final Project project) {
        this.project = project;
    }

    void registerAll() {
        final TaskProvider<AnalyseTask> analyse = registerAnalyseTask();
        wireAnalyseDependencies(analyse);
        registerGenerateClaudeMdTask(analyse);
        registerBaselineTask(analyse);
        registerFixPlanTask(analyse);
        registerExplainTask();
    }

    private TaskProvider<AnalyseTask> registerAnalyseTask() {
        return project.getTasks()
                .register("analyseCleanCode", AnalyseTask.class, task -> {
                    task.setDescription("Analyse codebase for Clean Code violations");
                    task.setGroup(VERIFICATION_GROUP);
                });
    }

    private void registerGenerateClaudeMdTask(final TaskProvider<AnalyseTask> analyse) {
        project.getTasks()
                .register("generateClaudeMd", GenerateClaudeMdTask.class, task -> {
                    task.setDescription("Generate CLAUDE.md from analysis findings");
                    task.setGroup(VERIFICATION_GROUP);
                    task.dependsOn(analyse);
                });
    }

    private void registerBaselineTask(final TaskProvider<AnalyseTask> analyse) {
        project.getTasks()
                .register("cleanCodeBaseline", BaselineTask.class, task -> {
                    task.setDescription("Snapshot current findings as baseline");
                    task.setGroup(VERIFICATION_GROUP);
                    task.dependsOn(analyse);
                });
    }

    private void registerFixPlanTask(final TaskProvider<AnalyseTask> analyse) {
        project.getTasks()
                .register("cleanCodeFixPlan", FixPlanTask.class, task -> {
                    task.setDescription("Group findings by file into per-class fix briefs for agent handoff");
                    task.setGroup(VERIFICATION_GROUP);
                    task.dependsOn(analyse);
                });
    }

    private void registerExplainTask() {
        project.getTasks()
                .register("cleanCodeExplain", ExplainTask.class, task -> {
                    task.setDescription("Print skill guidance for a finding concern");
                    task.setGroup(HELP_GROUP);
                });
    }

    private void wireAnalyseDependencies(final TaskProvider<AnalyseTask> analyse) {
        project.afterEvaluate(p -> analyse.configure(task -> {
            task.dependsOn("pmdMain", "checkstyleMain", "jacocoTestReport",
                    "spotbugsMain", "cpdMain");

            if (p.getTasks().findByName(DEPENDENCY_UPDATES_TASK) != null) {
                task.dependsOn(DEPENDENCY_UPDATES_TASK);
            }
        }));
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Severity;

import java.io.IOException;
import java.io.InputStream;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.Properties;

final class PmdRuleMap {

    record Entry(HeuristicCode code, Severity severity, Confidence confidence, String ruleUrl) {}

    private static final String RULE_MAPPING_RESOURCE = "/pmd/pmd-rule-mapping.properties";
    private static final String FIELD_SEPARATOR = "\\|";
    private static final int FIELD_COUNT = 5;

    private static final Map<String, String> CATEGORY_URLS = Map.of(
            "BP", "https://pmd.github.io/pmd/pmd_rules_java_bestpractices.html#",
            "DS", "https://pmd.github.io/pmd/pmd_rules_java_design.html#",
            "EP", "https://pmd.github.io/pmd/pmd_rules_java_errorprone.html#",
            "CS", "https://pmd.github.io/pmd/pmd_rules_java_codestyle.html#");

    private PmdRuleMap() {}

    static Map<String, Entry> load() {
        final Properties properties = readProperties();
        final Map<String, Entry> mappings = new LinkedHashMap<>();
        properties.stringPropertyNames().forEach(rule ->
                mappings.put(rule, parseEntry(rule, properties.getProperty(rule))));
        return Collections.unmodifiableMap(mappings);
    }

    private static Properties readProperties() {
        final Properties properties = new Properties();
        try (InputStream stream = PmdRuleMap.class.getResourceAsStream(RULE_MAPPING_RESOURCE)) {
            if (stream == null) {
                throw new IllegalStateException("PMD rule mapping resource not found: " + RULE_MAPPING_RESOURCE);
            }
            properties.load(stream);
        } catch (final IOException e) {
            throw new IllegalStateException("Failed to load PMD rule mapping: " + RULE_MAPPING_RESOURCE, e);
        }
        return properties;
    }

    private static Entry parseEntry(final String rule, final String value) {
        final String[] parts = value.split(FIELD_SEPARATOR);
        if (parts.length != FIELD_COUNT) {
            throw new IllegalStateException("Invalid PMD rule mapping for " + rule + ": " + value);
        }
        final HeuristicCode code = HeuristicCode.valueOf(parts[0]);
        final Severity severity = Severity.valueOf(parts[1]);
        final Confidence confidence = Confidence.valueOf(parts[2]);
        final String categoryPrefix = CATEGORY_URLS.get(parts[3]);
        if (categoryPrefix == null) {
            throw new IllegalStateException("Unknown PMD rule category for " + rule + ": " + parts[3]);
        }
        return new Entry(code, severity, confidence, categoryPrefix + parts[4]);
    }
}

