package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.Cursor;
import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.JavaType;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class ConfigurableDataRecipe extends ScanningRecipe<ConfigurableDataRecipe.Accumulator> {

    private static final String UNKNOWN_CLASS_NAME = "<unknown>";

    private final int minValue;

    public record Row(String className, String methodName, String literalValue) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    public ConfigurableDataRecipe(final int minValue) {
        this.minValue = minValue;
    }

    @Override
    public String getDisplayName() {
        return "Configurable data at high levels detection (G35)";
    }

    @Override
    public String getDescription() {
        return "Detects magic numeric literals in private methods that should be class-level constants.";
    }

    @Override
    public Accumulator getInitialValue(final ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(final Accumulator acc) {
        return new JavaIsoVisitor<>() {
            @Override
            public J.Literal visitLiteral(final J.Literal literal, final ExecutionContext ctx) {
                final J.Literal lit = super.visitLiteral(literal, ctx);
                if (isReportableMagicNumber(lit, getCursor())) {
                    acc.rows.add(toRow(lit, getCursor()));
                }
                return lit;
            }
        };
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(final Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private boolean isReportableMagicNumber(final J.Literal lit, final Cursor cursor) {
        return isNumericLiteral(lit)
                && isSignificantValue(lit)
                && isInProductionClass(cursor)
                && isInPrivateMethod(cursor)
                && isInExecutableStatement(cursor);
    }

    private Row toRow(final J.Literal lit, final Cursor cursor) {
        final J.ClassDeclaration enclosingClass = cursor.firstEnclosing(J.ClassDeclaration.class);
        final J.MethodDeclaration enclosingMethod = cursor.firstEnclosing(J.MethodDeclaration.class);
        final String className = enclosingClass != null ? enclosingClass.getSimpleName() : UNKNOWN_CLASS_NAME;
        return new Row(className, enclosingMethod.getSimpleName(), lit.getValueSource());
    }

    private static boolean isNumericLiteral(final J.Literal lit) {
        return lit.getType() instanceof JavaType.Primitive p
                && (p == JavaType.Primitive.Int || p == JavaType.Primitive.Long
                || p == JavaType.Primitive.Double || p == JavaType.Primitive.Float);
    }

    boolean isSignificantValue(final J.Literal lit) {
        return lit.getValue() instanceof Number n
                && Math.abs(n.doubleValue()) > minValue;
    }

    private static boolean isInProductionClass(final Cursor cursor) {
        final J.ClassDeclaration enclosingClass = cursor.firstEnclosing(J.ClassDeclaration.class);
        return enclosingClass != null && !enclosingClass.getSimpleName().endsWith("Test");
    }

    private static boolean isInPrivateMethod(final Cursor cursor) {
        final J.MethodDeclaration enclosingMethod = cursor.firstEnclosing(J.MethodDeclaration.class);
        return enclosingMethod != null && isPrivate(enclosingMethod);
    }

    private static boolean isInExecutableStatement(final Cursor cursor) {
        final J.VariableDeclarations varDecls = cursor.firstEnclosing(J.VariableDeclarations.class);
        return varDecls == null || !isConstantDeclaration(varDecls);
    }

    private static boolean isPrivate(final J.MethodDeclaration m) {
        return m.getModifiers().stream().anyMatch(mod -> mod.getType() == J.Modifier.Type.Private);
    }

    private static boolean isConstantDeclaration(final J.VariableDeclarations varDecls) {
        final boolean isStatic = varDecls.getModifiers().stream()
                .anyMatch(mod -> mod.getType() == J.Modifier.Type.Static);
        final boolean isFinal = varDecls.getModifiers().stream()
                .anyMatch(mod -> mod.getType() == J.Modifier.Type.Final);
        return isStatic && isFinal;
    }
}

package org.fiftieshousewife.cleancode.claudereview;

import com.anthropic.client.AnthropicClient;
import com.anthropic.client.okhttp.AnthropicOkHttpClient;
import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;
import java.util.stream.Collectors;

public class ClaudeReviewFindingSource implements FindingSource {

    private static final String TOOL = "claude-review";
    private static final Logger LOG = Logger.getLogger(ClaudeReviewFindingSource.class.getName());

    private final ClaudeReviewConfig config;
    private final ClaudeFindingParser parser;
    private final FindingCacheMapper cacheMapper;
    private final SourceFileCollector fileCollector;
    private final SystemPromptLoader promptLoader;

    public ClaudeReviewFindingSource(final ClaudeReviewConfig config) {
        this.config = config;
        this.parser = new ClaudeFindingParser(config.enabledCodes(), TOOL, config.model());
        this.cacheMapper = new FindingCacheMapper(TOOL);
        this.fileCollector = new SourceFileCollector(config.excludePatterns(), config.minFileLines());
        this.promptLoader = new SystemPromptLoader();
    }

    @Override
    public String id() {
        return TOOL;
    }

    @Override
    public String displayName() {
        return "Claude Review";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return config.enabledCodes();
    }

    @Override
    public boolean isAvailable(final ProjectContext context) {
        return config.enabled() && config.hasApiKey();
    }

    @Override
    public List<Finding> collectFindings(final ProjectContext context) throws FindingSourceException {
        if (!config.hasApiKey()) {
            return List.of();
        }
        final ReviewSession session = openSession(context);
        final List<Finding> allFindings = analyseAll(session);
        persistCache(session.cache());
        return allFindings;
    }

    List<Finding> parseFindings(final String json, final String sourceFile) {
        return parser.parse(json, sourceFile);
    }

    ReviewSession openSession(final ProjectContext context) {
        final AnthropicClient client = AnthropicOkHttpClient.builder().apiKey(config.apiKey()).build();
        final ClaudeFileAnalyser analyser = new ClaudeFileAnalyser(client, config.model(), parser);
        final String systemPrompt = promptLoader.load();
        final String codesKey = buildCodesKey();
        final ReviewCache cache = ReviewCache.load(context.buildDir().resolve("claude-review-cache"));
        return new ReviewSession(context, analyser, systemPrompt, codesKey, cache);
    }

    private String buildCodesKey() {
        return config.enabledCodes().stream()
                .map(HeuristicCode::name)
                .sorted()
                .collect(Collectors.joining(","));
    }

    private List<Finding> analyseAll(final ReviewSession session) {
        final List<Path> files = fileCollector.collect(session.context());
        final List<Finding> allFindings = new ArrayList<>();
        int analysed = 0;
        for (final Path file : files) {
            if (analysed >= config.maxFilesPerRun()) {
                break;
            }
            final Optional<List<Finding>> fresh = analyseOne(file, session, allFindings);
            if (fresh.isPresent()) {
                allFindings.addAll(fresh.get());
                analysed++;
            }
        }
        return allFindings;
    }

    private Optional<List<Finding>> analyseOne(final Path file, final ReviewSession session,
            final List<Finding> cachedSink) {
        try {
            final String content = Files.readString(file, StandardCharsets.UTF_8);
            final String relativePath = session.context().projectRoot().relativize(file).toString();
            final String hash = ReviewCache.hash(content, session.codesKey());
            final var cached = session.cache().lookup(hash);
            if (cached.isPresent()) {
                cachedSink.addAll(cacheMapper.toFindings(cached.get(), relativePath));
                return Optional.empty();
            }
            final List<Finding> findings = session.analyser().analyse(
                    new AnalysisRequest(content, relativePath, session.systemPrompt(), session.codesKey()));
            session.cache().store(hash, cacheMapper.toCachedFindings(findings));
            return Optional.of(findings);
        } catch (IOException e) {
            LOG.log(Level.WARNING, "Failed to read file: " + file, e);
            return Optional.empty();
        }
    }

    private static void persistCache(final ReviewCache cache) throws FindingSourceException {
        try {
            cache.save();
        } catch (IOException e) {
            throw new FindingSourceException("Failed to save review cache", e);
        }
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.Severity;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.io.IOException;
import java.io.InputStream;
import java.io.UncheckedIOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.Collections;
import java.util.EnumSet;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Properties;
import java.util.Set;
import java.util.TreeMap;

public class SpotBugsFindingSource implements FindingSource {

    private record RuleMapping(HeuristicCode code, Severity severity, Confidence confidence, String ruleUrl) {}

    private static final String SB_BASE = "https://spotbugs.readthedocs.io/en/latest/bugDescriptions.html#";
    private static final String MAPPING_RESOURCE = "/spotbugs/rule-mapping.properties";
    private static final String SPOTBUGS = "spotbugs";

    private static final Map<String, RuleMapping> RULE_MAP = loadMappings();

    @Override
    public String id() {
        return SPOTBUGS;
    }

    @Override
    public String displayName() {
        return "SpotBugs";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        final Set<HeuristicCode> codes = EnumSet.noneOf(HeuristicCode.class);
        RULE_MAP.values().forEach(m -> codes.add(m.code()));
        return Collections.unmodifiableSet(codes);
    }

    @Override
    public boolean isAvailable(final ProjectContext context) {
        return Files.exists(reportPath(context));
    }

    @Override
    public List<Finding> collectFindings(final ProjectContext context) throws FindingSourceException {
        final Path report = reportPath(context);
        if (!Files.exists(report)) {
            return List.of();
        }

        final Document doc = XmlReportParser.parse(report);
        final NodeList bugInstances = doc.getElementsByTagName("BugInstance");
        final List<Finding> findings = new ArrayList<>();

        for (int i = 0; i < bugInstances.getLength(); i++) {
            final Element bug = (Element) bugInstances.item(i);
            findingFor(bug).ifPresent(findings::add);
        }

        return findings;
    }

    private Optional<Finding> findingFor(final Element bug) {
        final String type = bug.getAttribute("type");
        final String category = bug.getAttribute("category");

        final RuleMapping mapping = lookupMapping(category, type);
        if (mapping == null) {
            return Optional.empty();
        }

        final Element sourceLine = firstSourceLine(bug);
        if (sourceLine == null) {
            return Optional.empty();
        }

        final int startLine = Integer.parseInt(sourceLine.getAttribute("start"));
        final int endLine = Integer.parseInt(sourceLine.getAttribute("end"));
        final String sourcePath = sourceLine.getAttribute("sourcepath");
        final String message = messageFor(bug, type);

        return Optional.of(new Finding(
                mapping.code(), sourcePath, startLine, endLine,
                message, mapping.severity(), mapping.confidence(),
                SPOTBUGS, type, Map.of("ruleUrl", mapping.ruleUrl())));
    }

    static RuleMapping lookupMapping(final String category, final String type) {
        final RuleMapping specific = RULE_MAP.get(category + "/" + type);
        return specific != null ? specific : RULE_MAP.get(category);
    }

    private static Element firstSourceLine(final Element bug) {
        final NodeList sourceLines = bug.getElementsByTagName("SourceLine");
        return sourceLines.getLength() == 0 ? null : (Element) sourceLines.item(0);
    }

    private static String messageFor(final Element bug, final String fallbackType) {
        final NodeList shortMessages = bug.getElementsByTagName("ShortMessage");
        if (shortMessages.getLength() == 0) {
            return fallbackType;
        }
        return shortMessages.item(0).getTextContent().trim();
    }

    private Path reportPath(final ProjectContext context) {
        return context.reportsDir().resolve("spotbugs/main.xml");
    }

    private static Map<String, RuleMapping> loadMappings() {
        final Properties properties = new Properties();
        try (InputStream stream = SpotBugsFindingSource.class.getResourceAsStream(MAPPING_RESOURCE)) {
            if (stream == null) {
                throw new IllegalStateException("Missing resource: " + MAPPING_RESOURCE);
            }
            properties.load(stream);
        } catch (IOException e) {
            throw new UncheckedIOException("Failed to load " + MAPPING_RESOURCE, e);
        }
        final Map<String, RuleMapping> mappings = new TreeMap<>();
        properties.stringPropertyNames().forEach(key ->
                mappings.put(key, parseMapping(properties.getProperty(key))));
        return Collections.unmodifiableMap(mappings);
    }

    private static RuleMapping parseMapping(final String value) {
        final String[] parts = value.split(",", -1);
        if (parts.length != 4) {
            throw new IllegalStateException("Expected 4 comma-separated fields but got: " + value);
        }
        final HeuristicCode code = HeuristicCode.valueOf(parts[0].trim());
        final Severity severity = Severity.valueOf(parts[1].trim());
        final Confidence confidence = Confidence.valueOf(parts[2].trim());
        final String urlSlug = parts[3].trim();
        return new RuleMapping(code, severity, confidence, SB_BASE + urlSlug);
    }
}

