    private List<FindingSource> buildFindingSources(final CleanCodeExtension ext) {
        final RecipeThresholds thresholds = ext.buildRecipeThresholds();
        final ClaudeReviewConfig claudeConfig = ext.buildClaudeReviewConfig(resolveApiKey());
        return List.of(
                new PmdFindingSource(),
                new CheckstyleFindingSource(),
                new SpotBugsFindingSource(),
                new CpdFindingSource(),
                new JacocoFindingSource(),
                new SurefireFindingSource(),
                new DependencyUpdatesFindingSource(),
                new OpenRewriteFindingSource(thresholds),
                new ClaudeReviewFindingSource(claudeConfig));
    }

    private AggregatedReport aggregateAndFilter(final List<FindingSource> sources,
                                                final ProjectContext context,
                                                final CleanCodeExtension ext) throws Exception {
        final Set<String> disabledRecipes = Set.copyOf(ext.getDisabledRecipes().get());
        final PackageSuppression packageSuppression = PackageSuppression.of(ext.getPackageSuppressions().get());
        final AggregatedReport fullReport = FindingAggregator.aggregate(sources, context);
        final AggregatedReport filteredByCode = ReportFiltering.filterDisabledRecipes(fullReport, disabledRecipes);
        return ReportFiltering.filterSuppressions(filteredByCode, context.projectRoot(), packageSuppression);
    }

    private Path writeReports(final AggregatedReport report,
                              final Path outputDir,
                              final CleanCodeExtension ext,
                              final Path projectRoot) throws Exception {
        final String repositoryUrl = buildRepositoryUrl(ext, projectRoot);
        final Path htmlReport = outputDir.resolve(HTML_REPORT_NAME);
        JsonReportWriter.write(report, outputDir.resolve(JSON_REPORT_NAME));
        HtmlReportWriter.write(report, htmlReport, repositoryUrl);
        return htmlReport;
    }

    private String buildRepositoryUrl(final CleanCodeExtension ext, final Path projectRoot) {
        final String baseRepoUrl = ext.getRepositoryUrl().get();
        final String modulePath = getProject().getRootDir().toPath().relativize(projectRoot).toString();
        return baseRepoUrl.isBlank() ? ""
                : baseRepoUrl + "/blob/main" + (modulePath.isEmpty() ? "" : "/" + modulePath);
    }

    private void logSummary(final AggregatedReport report, final Path projectRoot, final Path htmlReport)
            throws Exception {
        final Path baselineFile = projectRoot.resolve(BASELINE_FILE_NAME);
        final Map<HeuristicCode, BaselineManager.Delta> deltas = Files.exists(baselineFile)
                ? BaselineManager.computeDeltas(report, baselineFile)
                : Map.of();
        getLogger().lifecycle(BuildOutputFormatter.format(report, deltas));
        getLogger().lifecycle("\n  Report: file://" + htmlReport.toAbsolutePath());
    }

    private String resolveApiKey() {
        final Object prop = getProject().findProperty("ANTHROPIC_API_KEY");
        if (prop != null && !prop.toString().isBlank()) {
            return prop.toString();
        }
        final String env = System.getenv("ANTHROPIC_API_KEY");
        return env != null ? env : "";
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Locale;
import java.util.regex.Pattern;

public class MumblingCommentRecipe extends ScanningRecipe<MumblingCommentRecipe.Accumulator> {

    static final int MIN_COMMENT_LENGTH = 3;
    static final Pattern WHITESPACE = Pattern.compile("\\s+");

    public record Row(String className, String methodName, String commentPreview, int lineNumber) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Mumbling comment detection (C3)";
    }

    @Override
    public String getDescription() {
        return "Detects comments that restate the method name, parameter names, or the code that follows them.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new MumblingCommentScanner(acc);
    }

    static String normalise(String text) {
        final String alphaNumeric = text.toLowerCase(Locale.ROOT).replaceAll("[^a-z0-9]", " ");
        return WHITESPACE.matcher(alphaNumeric).replaceAll(" ").trim();
    }

    static String camelToWords(String camelCase) {
        return camelCase.replaceAll("([a-z])([A-Z])", "$1 $2");
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.Severity;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Set;

public class JacocoFindingSource implements FindingSource {

    private static final int MIN_CLASS_LINES = 10;
    private static final String LINE_COUNTER_TYPE = "LINE";
    private static final String COUNTER_TAG = "counter";
    private static final double PERCENT_MULTIPLIER = 100.0;
    private static final double CLASS_COVERAGE_WARNING_THRESHOLD = 50.0;
    private static final double COVERAGE_ERROR_THRESHOLD = 50.0;
    private static final double COVERAGE_WARNING_THRESHOLD = 75.0;

    @Override
    public String id() {
        return "jacoco";
    }

    @Override
    public String displayName() {
        return "JaCoCo";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return Set.of(HeuristicCode.T1, HeuristicCode.T2, HeuristicCode.T8);
    }

    @Override
    public boolean isAvailable(ProjectContext context) {
        return true;
    }

    @Override
    public List<Finding> collectFindings(ProjectContext context) throws FindingSourceException {
        final Path report = reportPath(context);
        if (!Files.exists(report)) {
            return handleMissingReport(context);
        }
        final Document doc = XmlReportParser.parse(report);
        final List<Finding> findings = new ArrayList<>();
        findings.addAll(projectLevelCoverage(doc));
        findings.addAll(perClassFindings(doc));
        return findings;
    }

    private List<Finding> handleMissingReport(ProjectContext context) {
        final boolean hasTestSources = context.testSourceRoots().stream().anyMatch(Files::exists);
        if (hasTestSources) {
            return List.of(Finding.projectLevel(
                    HeuristicCode.T2,
                    "JaCoCo report not found — coverage tool not configured",
                    Severity.ERROR, Confidence.HIGH, "jacoco", "missing-report"));
        }
        return List.of();
    }

    private List<Finding> projectLevelCoverage(Document doc) {
        return findReportLineCounter(doc)
                .map(this::projectCoverageFinding)
                .map(List::of)
                .orElseGet(List::of);
    }

    private Optional<Element> findReportLineCounter(Document doc) {
        final NodeList counters = doc.getDocumentElement().getChildNodes();
        for (int i = 0; i < counters.getLength(); i++) {
            if (isLineCounter(counters.item(i))) {
                return Optional.of((Element) counters.item(i));
            }
        }
        return Optional.empty();
    }

    private boolean isLineCounter(Object node) {
        if (!(node instanceof Element el)) {
            return false;
        }
        if (!COUNTER_TAG.equals(el.getTagName())) {
            return false;
        }
        return LINE_COUNTER_TYPE.equals(el.getAttribute("type"));
    }

    private Finding projectCoverageFinding(Element counter) {
        final LineCoverage coverage = LineCoverage.from(counter);
        return Finding.projectLevel(
                HeuristicCode.T1,
                String.format("Overall line coverage: %.1f%% (%d/%d lines covered)",
                        coverage.percentage(), coverage.covered(), coverage.total()),
                coverageSeverity(coverage.percentage()), Confidence.HIGH, "jacoco", "line-coverage");
    }

    private List<Finding> perClassFindings(Document doc) {
        final NodeList classNodes = doc.getElementsByTagName("class");
        final List<Finding> findings = new ArrayList<>();
        for (int i = 0; i < classNodes.getLength(); i++) {
            classFinding((Element) classNodes.item(i)).ifPresent(findings::add);
        }
        return findings;
    }

    private Optional<Finding> classFinding(Element classElement) {
        final Element lineCounter = findClassLineCounter(classElement);
        if (lineCounter == null) {
            return Optional.empty();
        }
        final LineCoverage coverage = LineCoverage.from(lineCounter);
        if (coverage.total() < MIN_CLASS_LINES) {
            return Optional.empty();
        }
        if (coverage.percentage() >= CLASS_COVERAGE_WARNING_THRESHOLD) {
            return Optional.empty();
        }
        return Optional.of(classCoverageFinding(classElement, coverage));
    }

    private Element findClassLineCounter(Element classElement) {
        final NodeList counters = classElement.getElementsByTagName(COUNTER_TAG);
        for (int j = 0; j < counters.getLength(); j++) {
            final Element counter = (Element) counters.item(j);
            if (LINE_COUNTER_TYPE.equals(counter.getAttribute("type"))) {
                return counter;
            }
        }
        return null;
    }

    private Finding classCoverageFinding(Element classElement, LineCoverage coverage) {
        final String className = classElement.getAttribute("name");
        final String sourceFile = classElement.getAttribute("sourcefilename");
        final int simpleNameStart = className.lastIndexOf('/') + 1;
        final String packagePath = className.substring(0, simpleNameStart - 1);
        final String simpleName = className.substring(simpleNameStart);
        return Finding.at(
                HeuristicCode.T8,
                packagePath + "/" + sourceFile,
                1, -1,
                String.format("Class %s has %.1f%% line coverage (%d/%d lines)",
                        simpleName, coverage.percentage(), coverage.covered(), coverage.total()),
                Severity.WARNING, Confidence.MEDIUM,
                "jacoco", "class-coverage");
    }

    private Severity coverageSeverity(double percentage) {
        if (percentage < COVERAGE_ERROR_THRESHOLD) {
            return Severity.ERROR;
        }
        return percentage < COVERAGE_WARNING_THRESHOLD ? Severity.WARNING : Severity.INFO;
    }

    private Path reportPath(ProjectContext context) {
        return context.reportsDir().resolve("jacoco/test/jacocoTestReport.xml");
    }

    private record LineCoverage(int missed, int covered) {
        static LineCoverage from(Element counter) {
            return new LineCoverage(
                    Integer.parseInt(counter.getAttribute("missed")),
                    Integer.parseInt(counter.getAttribute("covered")));
        }

        int total() {
            return missed + covered;
        }

        double percentage() {
            return total() > 0 ? (covered * PERCENT_MULTIPLIER) / total() : 0;
        }
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import org.openrewrite.ExecutionContext;
import org.openrewrite.Recipe;
import org.openrewrite.SourceFile;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.JavaParser;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Statement;

import java.util.ArrayList;
import java.util.List;
import java.util.Set;

public class EncapsulateBoundaryRecipe extends Recipe {

    private static final Set<String> BOUNDARY_METHODS = Set.of("length", "size");
    private static final String DECL_TEMPLATE = "class _T { void _m() { final int lastIndex = %s; } }";

    @Override
    public String getDisplayName() {
        return "Encapsulate boundary conditions into named variables";
    }

    @Override
    public String getDescription() {
        return "Adds a named variable for boundary arithmetic like array.length - 1. Fixes G33.";
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor() {
        return new JavaIsoVisitor<>() {
            @Override
            public J.Block visitBlock(J.Block block, ExecutionContext ctx) {
                final J.Block visitedBlock = super.visitBlock(block, ctx);
                return rewriteStatements(visitedBlock);
            }
        };
    }

    static J.Block rewriteStatements(final J.Block block) {
        final List<Statement> statements = block.getStatements();
        final List<Statement> newStatements = new ArrayList<>();
        boolean changed = false;

        for (final Statement stmt : statements) {
            final Statement lastIndexDecl = buildLastIndexDeclaration(stmt);
            if (lastIndexDecl == null) {
                newStatements.add(stmt);
                continue;
            }
            newStatements.add(lastIndexDecl);
            newStatements.add(stmt);
            changed = true;
        }

        return changed ? block.withStatements(newStatements) : block;
    }

    static Statement buildLastIndexDeclaration(final Statement stmt) {
        final String boundaryExpr = extractBoundaryText(stmt);
        if (boundaryExpr == null) {
            return null;
        }
        final Statement parsedDecl = parseLastIndexDecl(boundaryExpr);
        if (parsedDecl == null) {
            return null;
        }
        return parsedDecl.withPrefix(stmt.getPrefix());
    }

    static Statement parseLastIndexDecl(final String boundaryExpr) {
        final String declSource = DECL_TEMPLATE.formatted(boundaryExpr);
        final List<SourceFile> parsed = JavaParser.fromJavaVersion()
                .logCompilationWarningsAndErrors(false)
                .build().parse(declSource).toList();
        if (parsed.isEmpty()) {
            return null;
        }
        final J.CompilationUnit compilationUnit = (J.CompilationUnit) parsed.getFirst();
        final J.MethodDeclaration method = (J.MethodDeclaration)
                compilationUnit.getClasses().getFirst().getBody().getStatements().getFirst();
        return method.getBody().getStatements().getFirst();
    }

    static String extractBoundaryText(final Statement stmt) {
        final BoundaryCollector collector = new BoundaryCollector();
        collector.visit(stmt, 0);
        if (collector.matches.isEmpty()) {
            return null;
        }
        final J.Binary match = collector.matches.getFirst();
        final String left = match.getLeft().toString().trim();
        return left + " - 1";
    }

    private static final class BoundaryCollector extends JavaIsoVisitor<Integer> {
        private final List<J.Binary> matches = new ArrayList<>();

        @Override
        public J.Binary visitBinary(final J.Binary binary, final Integer unused) {
            if (isBoundaryMinusOne(binary)) {
                matches.add(binary);
            }
            return super.visitBinary(binary, unused);
        }
    }

    private static boolean isBoundaryMinusOne(final J.Binary binary) {
        return binary.getOperator() == J.Binary.Type.Subtraction
                && isLiteralOne(binary.getRight())
                && isBoundaryAccess(binary.getLeft());
    }

    private static boolean isLiteralOne(final Expression expr) {
        return expr instanceof J.Literal lit
                && lit.getValue() instanceof Integer value
                && value == 1;
    }

    private static boolean isBoundaryAccess(final Expression expr) {
        return switch (expr) {
            case J.FieldAccess fa -> BOUNDARY_METHODS.contains(fa.getSimpleName());
            case J.MethodInvocation mi -> BOUNDARY_METHODS.contains(mi.getSimpleName());
            default -> false;
        };
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Map;

final class DeltaTableWriter {

    private static final String HEADING = "## Current standing vs baseline\n\n";
    private static final String TABLE_HEADER = "| Category | Baseline | Current | Delta |\n";
    private static final String TABLE_DIVIDER = "|---|---|---|---|\n";
    private static final String ROW_FORMAT = "| %s | %d | %d | %s |%n";

    private DeltaTableWriter() {}

    static void append(final StringBuilder sb, final AggregatedReport report,
                       final Path baselineFile) throws IOException {
        if (baselineFile == null || !Files.exists(baselineFile)) {
            return;
        }
        final Map<HeuristicCode, BaselineManager.Delta> deltas =
                BaselineManager.computeDeltas(report, baselineFile);
        if (deltas.isEmpty()) {
            return;
        }
        appendTableHeader(sb);
        appendTableRows(sb, deltas);
        sb.append('\n');
    }

    private static void appendTableHeader(final StringBuilder sb) {
        sb.append(HEADING);
        sb.append(TABLE_HEADER);
        sb.append(TABLE_DIVIDER);
    }

    private static void appendTableRows(final StringBuilder sb,
                                        final Map<HeuristicCode, BaselineManager.Delta> deltas) {
        deltas.forEach((code, delta) -> sb.append(formatRow(code, delta)));
    }

    private static String formatRow(final HeuristicCode code, final BaselineManager.Delta delta) {
        return String.format(ROW_FORMAT, code.name(), delta.baseline(), delta.current(), formatDelta(delta.change()));
    }

    private static String formatDelta(final long delta) {
        return switch (Long.signum(delta)) {
            case 0 -> "0";
            case 1 -> "+" + delta + " \u26A0";
            default -> delta + " \u2713";
        };
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.MIN_COMMENT_LENGTH;
import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.Row;
import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.camelToWords;
import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.normalise;

final class MumblingCommentScanner extends JavaIsoVisitor<ExecutionContext> {

    private static final int MAX_PREVIEW_LENGTH = 60;
    private static final int UNKNOWN_LINE = -1;
    private static final String UNKNOWN_CLASS = "<unknown>";
    private static final String LINE_COMMENT_MARKER = "//";
    private static final int LINE_COMMENT_MARKER_LENGTH = LINE_COMMENT_MARKER.length();

    private final MumblingCommentRecipe.Accumulator acc;

    MumblingCommentScanner(final MumblingCommentRecipe.Accumulator acc) {
        this.acc = acc;
    }

    @Override
    public J.MethodDeclaration visitMethodDeclaration(final J.MethodDeclaration method, final ExecutionContext ctx) {
        final J.MethodDeclaration visited = super.visitMethodDeclaration(method, ctx);
        final List<String> lines = visited.print(getCursor()).lines().toList();
        final MumblingContext context = new MumblingContext(
                findEnclosingClassName(),
                visited.getSimpleName(),
                extractParamNames(visited));
        for (int i = 0; i < lines.size(); i++) {
            inspectLine(lines, i, context);
        }
        return visited;
    }

    private void inspectLine(final List<String> lines, final int index, final MumblingContext context) {
        final String commentText = extractLineComment(lines.get(index));
        if (commentText == null) {
            return;
        }
        final String normalised = normalise(commentText);
        final String nextLine = index + 1 < lines.size() ? lines.get(index + 1).trim() : "";
        if (isMumbling(normalised, context, nextLine)) {
            acc.rows.add(new Row(context.className(), context.methodName(), preview(commentText), UNKNOWN_LINE));
        }
    }

    private String preview(final String commentText) {
        return commentText.substring(0, Math.min(MAX_PREVIEW_LENGTH, commentText.length()));
    }

    String extractLineComment(final String line) {
        final String stripped = stripStringLiterals(line);
        final int idx = stripped.indexOf(LINE_COMMENT_MARKER);
        if (idx < 0) {
            return null;
        }
        final String text = stripped.substring(idx + LINE_COMMENT_MARKER_LENGTH).trim();
        return text.length() >= MIN_COMMENT_LENGTH ? text : null;
    }

    String stripStringLiterals(final String line) {
        final StringBuilder result = new StringBuilder(line.length());
        boolean inString = false;
        for (int i = 0; i < line.length(); i++) {
            final char ch = line.charAt(i);
            if (ch == '\\' && inString && i + 1 < line.length()) {
                i++;
                continue;
            }
            if (ch == '"') {
                inString = !inString;
                continue;
            }
            if (!inString) {
                result.append(ch);
            }
        }
        return result.toString();
    }

    boolean isMumbling(final String normalisedComment, final MumblingContext context, final String nextCodeLine) {
        if (restatesMethodName(normalisedComment, context.methodName())) {
            return true;
        }
        if (restatesAllParameters(normalisedComment, context.paramNames())) {
            return true;
        }
        return !nextCodeLine.isEmpty() && restatesNextLine(normalisedComment, nextCodeLine);
    }

    private boolean restatesMethodName(final String normalisedComment, final String methodName) {
        final String[] methodWords = MumblingCommentRecipe.WHITESPACE.split(normalise(camelToWords(methodName)));
        return allWordsPresent(normalisedComment, methodWords);
    }

    private boolean restatesAllParameters(final String normalisedComment, final Set<String> paramNames) {
        if (paramNames.isEmpty()) {
            return false;
        }
        final long matchCount = paramNames.stream()
                .filter(p -> normalisedComment.contains(normalise(p)))
                .count();
        return matchCount >= paramNames.size();
    }

    boolean restatesNextLine(final String normalisedComment, final String nextCodeLine) {
        final String normalisedCode = normalise(nextCodeLine);
        final String[] commentWords = MumblingCommentRecipe.WHITESPACE.split(normalisedComment);
        final String[] codeWords = MumblingCommentRecipe.WHITESPACE.split(normalisedCode);
        if (commentWords.length < MumblingThresholds.MIN_WORDS
                || codeWords.length < MumblingThresholds.MIN_WORDS) {
            return false;
        }
        final long significantCodeWords = countSignificantWords(codeWords);
        final long codeWordsInComment = countSignificantWordsFoundIn(codeWords, normalisedComment);
        return hasEnoughOverlap(significantCodeWords, codeWordsInComment);
    }

    private long countSignificantWords(final String[] words) {
        return java.util.Arrays.stream(words)
                .filter(w -> w.length() >= MumblingThresholds.MIN_SIGNIFICANT_WORD_LENGTH)
                .count();
    }

    private long countSignificantWordsFoundIn(final String[] words, final String text) {
        return java.util.Arrays.stream(words)
                .filter(w -> w.length() >= MumblingThresholds.MIN_SIGNIFICANT_WORD_LENGTH)
                .filter(text::contains)
                .count();
    }

    private boolean hasEnoughOverlap(final long significantCodeWords, final long codeWordsInComment) {
        final boolean enoughCodeWords = significantCodeWords >= MumblingThresholds.MIN_WORDS;
        final double requiredOverlap = significantCodeWords * MumblingThresholds.RESTATEMENT_RATIO;
        return enoughCodeWords && codeWordsInComment >= requiredOverlap;
    }

    private boolean allWordsPresent(final String text, final String[] words) {
        if (words.length < MumblingThresholds.MIN_WORDS) {
            return false;
        }
        final String[] textWords = MumblingCommentRecipe.WHITESPACE.split(text);
        for (final String word : words) {
            if (word.length() < MumblingThresholds.MIN_MEANINGFUL_WORD_LENGTH) {
                continue;
            }
            if (!hasPrefixMatch(textWords, word)) {
                return false;
            }
        }
        return true;
    }

    private boolean hasPrefixMatch(final String[] textWords, final String word) {
        return java.util.Arrays.stream(textWords)
                .anyMatch(tw -> tw.startsWith(word) || word.startsWith(tw));
    }

    private Set<String> extractParamNames(final J.MethodDeclaration method) {
        final Set<String> names = new HashSet<>();
        method.getParameters().stream()
                .filter(J.VariableDeclarations.class::isInstance)
                .map(J.VariableDeclarations.class::cast)
                .forEach(v -> v.getVariables().forEach(named -> names.add(named.getSimpleName())));
        return names;
    }

    private String findEnclosingClassName() {
        final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
        return classDecl != null ? classDecl.getSimpleName() : UNKNOWN_CLASS;
    }

    record MumblingContext(String className, String methodName, Set<String> paramNames) {}
}

