package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.JavaType;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class StringlyTypedDispatchRecipe extends ScanningRecipe<StringlyTypedDispatchRecipe.Accumulator> {

    private static final Set<String> SKIP_METHODS = Set.of("equals", "hashCode", "toString", "main");
    private static final String EQUALS_CALL = ".equals(";
    private static final int MIN_BRANCHES = 2;

    public record Row(String className, String methodName, String parameterName, int branchCount) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Stringly-typed dispatch detection";
    }

    @Override
    public String getDescription() {
        return "Detects methods that use a String parameter to select behaviour via switch or if/else chains.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new DispatchScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static final class DispatchScanner extends JavaIsoVisitor<ExecutionContext> {
        private final Accumulator acc;

        DispatchScanner(Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.MethodDeclaration visitMethodDeclaration(J.MethodDeclaration method, ExecutionContext ctx) {
            final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
            if (shouldSkip(m)) {
                return m;
            }
            final Set<String> stringParamNames = collectStringParamNames(m);
            if (stringParamNames.isEmpty()) {
                return m;
            }
            final String className = enclosingClassName();
            stringParamNames.forEach(paramName -> recordDispatch(m, className, paramName));
            return m;
        }

        private static boolean shouldSkip(J.MethodDeclaration m) {
            return SKIP_METHODS.contains(m.getSimpleName()) || m.getBody() == null;
        }

        private static Set<String> collectStringParamNames(J.MethodDeclaration m) {
            return m.getParameters().stream()
                    .filter(J.VariableDeclarations.class::isInstance)
                    .map(J.VariableDeclarations.class::cast)
                    .filter(StringlyTypedDispatchRecipe::isStringType)
                    .flatMap(v -> v.getVariables().stream())
                    .map(J.VariableDeclarations.NamedVariable::getSimpleName)
                    .collect(Collectors.toSet());
        }

        private String enclosingClassName() {
            final J.ClassDeclaration enclosingClass = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return enclosingClass != null ? enclosingClass.getSimpleName() : "<unknown>";
        }

        private void recordDispatch(J.MethodDeclaration m, String className, String paramName) {
            final int switchBranches = countSwitchBranches(m.getBody(), paramName);
            if (switchBranches >= MIN_BRANCHES) {
                acc.rows.add(new Row(className, m.getSimpleName(), paramName, switchBranches));
                return;
            }
            final int ifBranches = countIfElseBranches(m.getBody(), paramName);
            if (ifBranches >= MIN_BRANCHES) {
                acc.rows.add(new Row(className, m.getSimpleName(), paramName, ifBranches));
            }
        }
    }

    static boolean isStringType(J.VariableDeclarations varDecls) {
        if (varDecls.getType() instanceof JavaType.FullyQualified fq) {
            return "java.lang.String".equals(fq.getFullyQualifiedName());
        }
        if (varDecls.getTypeExpression() == null) {
            return false;
        }
        final String typeExpressionText = varDecls.getTypeExpression().toString().trim();
        return "String".equals(typeExpressionText);
    }

    private static int countSwitchBranches(J.Block body, String paramName) {
        final List<Integer> counts = new ArrayList<>();
        new JavaIsoVisitor<List<Integer>>() {
            @Override
            public J.Switch visitSwitch(J.Switch sw, List<Integer> out) {
                if (selectorReferencesParam(sw.getSelector(), paramName)) {
                    out.add(caseCount(sw));
                }
                return super.visitSwitch(sw, out);
            }
        }.visit(body, counts);
        return counts.stream().mapToInt(Integer::intValue).max().orElse(0);
    }

    private static int caseCount(J.Switch sw) {
        return (int) sw.getCases().getStatements().stream()
                .filter(J.Case.class::isInstance)
                .count();
    }

    private static boolean selectorReferencesParam(J.ControlParentheses<Expression> selector, String paramName) {
        return selector.getTree().toString().trim().equals(paramName);
    }

    private static int countIfElseBranches(J.Block body, String paramName) {
        final List<Integer> counts = new ArrayList<>();
        new JavaIsoVisitor<List<Integer>>() {
            @Override
            public J.If visitIf(J.If iff, List<Integer> out) {
                final int branches = countChainedEquals(iff, paramName);
                if (branches >= MIN_BRANCHES) {
                    out.add(branches);
                }
                return super.visitIf(iff, out);
            }
        }.visit(body, counts);
        return counts.stream().mapToInt(Integer::intValue).max().orElse(0);
    }

    private static int countChainedEquals(J.If iff, String paramName) {
        int count = 0;
        J.If current = iff;
        while (current != null) {
            if (conditionReferencesParamEquals(current.getIfCondition(), paramName)) {
                count++;
            }
            if (current.getElsePart() != null && current.getElsePart().getBody() instanceof J.If nextIf) {
                current = nextIf;
            } else {
                break;
            }
        }
        return count;
    }

    private static boolean conditionReferencesParamEquals(
            J.ControlParentheses<Expression> cond, String paramName) {
        final String condStr = cond.toString().trim();
        return condStr.contains(paramName + EQUALS_CALL) || condStr.contains(EQUALS_CALL + paramName + ")");
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonProperty;
import org.openrewrite.ExecutionContext;
import org.openrewrite.Recipe;
import org.openrewrite.SourceFile;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.JavaParser;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Statement;

import java.util.ArrayList;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class WrapAssertAllRecipe extends Recipe {

    private static final Set<String> ASSERT_PREFIXES = Set.of(
            "assertThat", "assertEquals", "assertTrue", "assertFalse",
            "assertNull", "assertNotNull", "assertThrows", "assertSame",
            "assertNotEquals", "assertArrayEquals", "assertIterableEquals");

    private final int minConsecutive;

    @JsonCreator
    public WrapAssertAllRecipe(@JsonProperty("minConsecutive") int minConsecutive) {
        this.minConsecutive = minConsecutive;
    }

    @Override
    public String getDisplayName() {
        return "Wrap consecutive assertions in assertAll";
    }

    @Override
    public String getDescription() {
        return "Wraps %d+ consecutive assert statements in assertAll so all failures are reported together. Fixes T1."
                .formatted(minConsecutive);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor() {
        return new JavaIsoVisitor<>() {
            @Override
            public J.Block visitBlock(J.Block block, ExecutionContext ctx) {
                final J.Block visitedBlock = super.visitBlock(block, ctx);
                if (!isInsideTestMethod(getCursor())) {
                    return visitedBlock;
                }
                final List<Statement> statements = visitedBlock.getStatements();
                final List<AssertRun> runs = findAssertRuns(statements);
                if (runs.isEmpty()) {
                    return visitedBlock;
                }
                return visitedBlock.withStatements(rewriteStatements(statements, runs));
            }
        };
    }

    private boolean isInsideTestMethod(final org.openrewrite.Cursor cursor) {
        final J.MethodDeclaration enclosingMethod = cursor.firstEnclosing(J.MethodDeclaration.class);
        return enclosingMethod != null && isTestMethod(enclosingMethod);
    }

    private List<Statement> rewriteStatements(final List<Statement> statements, final List<AssertRun> runs) {
        final List<Statement> newStatements = new ArrayList<>();
        int i = 0;
        for (final AssertRun run : runs) {
            while (i < run.startIndex()) {
                newStatements.add(statements.get(i++));
            }
            appendAssertAllOrOriginals(newStatements, statements, run);
            i = run.endIndex();
        }
        while (i < statements.size()) {
            newStatements.add(statements.get(i++));
        }
        return newStatements;
    }

    private void appendAssertAllOrOriginals(final List<Statement> newStatements,
                                            final List<Statement> statements,
                                            final AssertRun run) {
        final Statement assertAllStmt = buildAssertAllStatement(statements, run);
        if (assertAllStmt != null) {
            newStatements.add(assertAllStmt.withPrefix(statements.get(run.startIndex()).getPrefix()));
        } else {
            statements.subList(run.startIndex(), run.endIndex()).forEach(newStatements::add);
        }
    }

    private Statement buildAssertAllStatement(final List<Statement> statements, final AssertRun run) {
        final String lambdas = statements.subList(run.startIndex(), run.endIndex()).stream()
                .map(s -> "() -> " + s.toString().trim())
                .collect(Collectors.joining(",\n                "));
        final String assertAllSource =
                "class _T { void _m() { assertAll(\n                %s\n        ); } }".formatted(lambdas);
        final List<SourceFile> parsed = JavaParser.fromJavaVersion()
                .logCompilationWarningsAndErrors(false)
                .build().parse(assertAllSource).toList();
        if (parsed.isEmpty()) {
            return null;
        }
        final J.MethodDeclaration method = (J.MethodDeclaration)
                ((J.CompilationUnit) parsed.getFirst())
                        .getClasses().getFirst().getBody().getStatements().getFirst();
        return method.getBody().getStatements().getFirst();
    }

    private record AssertRun(int startIndex, int endIndex) {}

    List<AssertRun> findAssertRuns(final List<Statement> statements) {
        final List<AssertRun> runs = new ArrayList<>();
        int runStart = -1;
        int runLength = 0;
        for (int i = 0; i < statements.size(); i++) {
            if (isAssertCall(statements.get(i))) {
                if (runStart < 0) {
                    runStart = i;
                }
                runLength++;
            } else {
                if (runLength >= minConsecutive) {
                    runs.add(new AssertRun(runStart, runStart + runLength));
                }
                runStart = -1;
                runLength = 0;
            }
        }
        if (runLength >= minConsecutive) {
            runs.add(new AssertRun(runStart, runStart + runLength));
        }
        return runs;
    }

    private static boolean isAssertCall(final Statement stmt) {
        if (stmt instanceof J.MethodInvocation mi) {
            return ASSERT_PREFIXES.stream().anyMatch(p -> mi.getSimpleName().startsWith(p));
        }
        return false;
    }

    private static boolean isTestMethod(final J.MethodDeclaration method) {
        return method.getLeadingAnnotations().stream()
                .anyMatch(a -> "Test".equals(a.getSimpleName()));
    }
}

