package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Flag;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class InappropriateStaticRecipe extends ScanningRecipe<InappropriateStaticRecipe.Accumulator> {

    private static final int MIN_BODY_STATEMENTS = 3;

    public record Row(String className, String methodName) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Inappropriate static detection (G18)";
    }

    @Override
    public String getDescription() {
        return "Detects non-private instance methods that never reference instance state.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new MethodDeclarationScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        if (lastAccumulator == null) {
            return List.of();
        }
        return Collections.unmodifiableList(lastAccumulator.rows);
    }

    private final class MethodDeclarationScanner extends JavaIsoVisitor<ExecutionContext> {
        private final Accumulator acc;

        MethodDeclarationScanner(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.MethodDeclaration visitMethodDeclaration(final J.MethodDeclaration method, final ExecutionContext ctx) {
            final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
            if (shouldSkip(m)) {
                return m;
            }
            final J.ClassDeclaration enclosingClass = getCursor().firstEnclosing(J.ClassDeclaration.class);
            if (enclosingClass != null && implementsInterface(enclosingClass)) {
                return m;
            }
            if (!referencesInstanceState(m)) {
                acc.rows.add(new Row(classNameOf(enclosingClass), m.getSimpleName()));
            }
            return m;
        }

        private String classNameOf(final J.ClassDeclaration enclosingClass) {
            return enclosingClass != null ? enclosingClass.getSimpleName() : "<unknown>";
        }
    }

    private static boolean shouldSkip(final J.MethodDeclaration m) {
        return isStatic(m)
                || isPrivate(m)
                || isConstructor(m)
                || isOverride(m)
                || isMain(m)
                || bodyLineCount(m) < MIN_BODY_STATEMENTS;
    }

    private static boolean isStatic(final J.MethodDeclaration m) {
        return m.getModifiers().stream().anyMatch(mod -> mod.getType() == J.Modifier.Type.Static);
    }

    private static boolean isPrivate(final J.MethodDeclaration m) {
        return m.getModifiers().stream().anyMatch(mod -> mod.getType() == J.Modifier.Type.Private);
    }

    private static boolean isConstructor(final J.MethodDeclaration m) {
        return m.getMethodType() != null && m.getMethodType().isConstructor();
    }

    private static boolean isOverride(final J.MethodDeclaration m) {
        return m.getLeadingAnnotations().stream()
                .anyMatch(a -> "Override".equals(a.getSimpleName()));
    }

    private static boolean isMain(final J.MethodDeclaration m) {
        return "main".equals(m.getSimpleName());
    }

    private static boolean implementsInterface(final J.ClassDeclaration classDecl) {
        return classDecl.getImplements() != null && !classDecl.getImplements().isEmpty();
    }

    private static int bodyLineCount(final J.MethodDeclaration m) {
        if (m.getBody() == null) {
            return 0;
        }
        return m.getBody().getStatements().size();
    }

    private static boolean referencesInstanceState(final J.MethodDeclaration m) {
        if (m.getBody() == null) {
            return false;
        }
        final InstanceStateDetector detector = new InstanceStateDetector();
        detector.visit(m.getBody(), null);
        return detector.found;
    }

    private static final class InstanceStateDetector extends JavaIsoVisitor<Object> {
        private boolean found;

        @Override
        public J.Identifier visitIdentifier(final J.Identifier identifier, final Object ignored) {
            if ("this".equals(identifier.getSimpleName())) {
                found = true;
            }
            return identifier;
        }

        @Override
        public J.MethodInvocation visitMethodInvocation(final J.MethodInvocation method, final Object ignored) {
            final J.MethodInvocation mi = super.visitMethodInvocation(method, ignored);
            if (isUnqualifiedInstanceCall(mi)) {
                found = true;
            }
            return mi;
        }

        private static boolean isUnqualifiedInstanceCall(final J.MethodInvocation mi) {
            return mi.getSelect() == null
                    && mi.getMethodType() != null
                    && !mi.getMethodType().hasFlags(Flag.Static);
        }
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.Severity;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Set;

public class JacocoFindingSource implements FindingSource {

    private static final int MIN_CLASS_LINES = 10;
    private static final String LINE_COUNTER_TYPE = "LINE";
    private static final String COUNTER_TAG = "counter";
    private static final double CLASS_COVERAGE_WARNING_THRESHOLD = 50.0;
    private static final double COVERAGE_ERROR_THRESHOLD = 50.0;
    private static final double COVERAGE_WARNING_THRESHOLD = 75.0;

    @Override
    public String id() {
        return "jacoco";
    }

    @Override
    public String displayName() {
        return "JaCoCo";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return Set.of(HeuristicCode.T1, HeuristicCode.T2, HeuristicCode.T8);
    }

    @Override
    public boolean isAvailable(ProjectContext context) {
        return true;
    }

    @Override
    public List<Finding> collectFindings(ProjectContext context) throws FindingSourceException {
        final Path report = reportPath(context);
        if (!Files.exists(report)) {
            return handleMissingReport(context);
        }
        final Document doc = XmlReportParser.parse(report);
        final List<Finding> findings = new ArrayList<>();
        findings.addAll(projectLevelCoverage(doc));
        findings.addAll(perClassFindings(doc));
        return findings;
    }

    private List<Finding> handleMissingReport(ProjectContext context) {
        final boolean hasTestSources = context.testSourceRoots().stream().anyMatch(Files::exists);
        if (hasTestSources) {
            return List.of(Finding.projectLevel(
                    HeuristicCode.T2,
                    "JaCoCo report not found — coverage tool not configured",
                    Severity.ERROR, Confidence.HIGH, "jacoco", "missing-report"));
        }
        return List.of();
    }

    private List<Finding> projectLevelCoverage(Document doc) {
        return findReportLineCounter(doc).map(this::projectCoverageFinding).map(List::of).orElseGet(List::of);
    }

    private Optional<Element> findReportLineCounter(Document doc) {
        final NodeList counters = doc.getDocumentElement().getChildNodes();
        for (int i = 0; i < counters.getLength(); i++) {
            if (isLineCounter(counters.item(i))) {
                return Optional.of((Element) counters.item(i));
            }
        }
        return Optional.empty();
    }

    private boolean isLineCounter(Object node) {
        if (!(node instanceof Element el)) {
            return false;
        }
        return COUNTER_TAG.equals(el.getTagName()) && LINE_COUNTER_TYPE.equals(el.getAttribute("type"));
    }

    private Finding projectCoverageFinding(Element counter) {
        final LineCoverage coverage = LineCoverage.from(counter);
        return Finding.projectLevel(
                HeuristicCode.T1,
                String.format("Overall line coverage: %.1f%% (%d/%d lines covered)",
                        coverage.percentage(), coverage.covered(), coverage.total()),
                coverageSeverity(coverage.percentage()), Confidence.HIGH, "jacoco", "line-coverage");
    }

    private List<Finding> perClassFindings(Document doc) {
        final NodeList classNodes = doc.getElementsByTagName("class");
        final List<Finding> findings = new ArrayList<>();
        for (int i = 0; i < classNodes.getLength(); i++) {
            classFinding((Element) classNodes.item(i)).ifPresent(findings::add);
        }
        return findings;
    }

    private Optional<Finding> classFinding(Element classElement) {
        final Element lineCounter = findClassLineCounter(classElement);
        if (lineCounter == null) {
            return Optional.empty();
        }
        final LineCoverage coverage = LineCoverage.from(lineCounter);
        if (coverage.total() < MIN_CLASS_LINES || coverage.percentage() >= CLASS_COVERAGE_WARNING_THRESHOLD) {
            return Optional.empty();
        }
        return Optional.of(classCoverageFinding(classElement, coverage));
    }

    private Element findClassLineCounter(Element classElement) {
        final NodeList counters = classElement.getElementsByTagName(COUNTER_TAG);
        for (int j = 0; j < counters.getLength(); j++) {
            final Element counter = (Element) counters.item(j);
            if (LINE_COUNTER_TYPE.equals(counter.getAttribute("type"))) {
                return counter;
            }
        }
        return null;
    }

    private Finding classCoverageFinding(Element classElement, LineCoverage coverage) {
        final String className = classElement.getAttribute("name");
        final String sourceFile = classElement.getAttribute("sourcefilename");
        final int simpleNameStart = className.lastIndexOf('/') + 1;
        final String packagePath = className.substring(0, simpleNameStart - 1);
        final String simpleName = className.substring(simpleNameStart);
        return Finding.at(
                HeuristicCode.T8, packagePath + "/" + sourceFile, 1, -1,
                String.format("Class %s has %.1f%% line coverage (%d/%d lines)",
                        simpleName, coverage.percentage(), coverage.covered(), coverage.total()),
                Severity.WARNING, Confidence.MEDIUM, "jacoco", "class-coverage");
    }

    private Severity coverageSeverity(double percentage) {
        if (percentage < COVERAGE_ERROR_THRESHOLD) {
            return Severity.ERROR;
        }
        return percentage < COVERAGE_WARNING_THRESHOLD ? Severity.WARNING : Severity.INFO;
    }

    private Path reportPath(ProjectContext context) {
        return context.reportsDir().resolve("jacoco/test/jacocoTestReport.xml");
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.Set;
import java.util.stream.Collectors;

final class DispatchScanner extends JavaIsoVisitor<ExecutionContext> {

    private static final Set<String> SKIP_METHODS = Set.of("equals", "hashCode", "toString", "main");
    private static final int MIN_BRANCHES = 2;
    private static final String UNKNOWN_CLASS_NAME = "<unknown>";

    private final StringlyTypedDispatchRecipe.Accumulator acc;

    DispatchScanner(StringlyTypedDispatchRecipe.Accumulator acc) {
        this.acc = acc;
    }

    @Override
    public J.MethodDeclaration visitMethodDeclaration(J.MethodDeclaration method, ExecutionContext ctx) {
        final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
        if (shouldSkip(m)) {
            return m;
        }
        final Set<String> stringParamNames = collectStringParamNames(m);
        if (stringParamNames.isEmpty()) {
            return m;
        }
        final String className = enclosingClassName();
        stringParamNames.forEach(paramName -> recordDispatch(m, className, paramName));
        return m;
    }

    private static boolean shouldSkip(J.MethodDeclaration m) {
        return SKIP_METHODS.contains(m.getSimpleName()) || m.getBody() == null;
    }

    private static Set<String> collectStringParamNames(J.MethodDeclaration m) {
        return m.getParameters().stream()
                .filter(J.VariableDeclarations.class::isInstance)
                .map(J.VariableDeclarations.class::cast)
                .filter(StringlyTypedDispatchRecipe::isStringType)
                .flatMap(v -> v.getVariables().stream())
                .map(J.VariableDeclarations.NamedVariable::getSimpleName)
                .collect(Collectors.toSet());
    }

    private String enclosingClassName() {
        final J.ClassDeclaration enclosingClass = getCursor().firstEnclosing(J.ClassDeclaration.class);
        return enclosingClass != null ? enclosingClass.getSimpleName() : UNKNOWN_CLASS_NAME;
    }

    private void recordDispatch(J.MethodDeclaration m, String className, String paramName) {
        final int switchBranches = DispatchBranchCounter.countSwitchBranches(m.getBody(), paramName);
        if (switchBranches >= MIN_BRANCHES) {
            acc.rows.add(new StringlyTypedDispatchRecipe.Row(className, m.getSimpleName(), paramName, switchBranches));
            return;
        }
        final int ifBranches = DispatchBranchCounter.countIfElseBranches(m.getBody(), paramName);
        if (ifBranches >= MIN_BRANCHES) {
            acc.rows.add(new StringlyTypedDispatchRecipe.Row(className, m.getSimpleName(), paramName, ifBranches));
        }
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.List;

final class DispatchBranchCounter {

    private static final String EQUALS_CALL = ".equals(";
    private static final int MIN_BRANCHES = 2;

    private DispatchBranchCounter() {}

    static int countSwitchBranches(J.Block body, String paramName) {
        final List<Integer> counts = new ArrayList<>();
        new JavaIsoVisitor<List<Integer>>() {
            @Override
            public J.Switch visitSwitch(J.Switch sw, List<Integer> out) {
                if (selectorReferencesParam(sw.getSelector(), paramName)) {
                    out.add(caseCount(sw));
                }
                return super.visitSwitch(sw, out);
            }
        }.visit(body, counts);
        return maxOrZero(counts);
    }

    static int countIfElseBranches(J.Block body, String paramName) {
        final List<Integer> counts = new ArrayList<>();
        new JavaIsoVisitor<List<Integer>>() {
            @Override
            public J.If visitIf(J.If iff, List<Integer> out) {
                final int branches = countChainedEquals(iff, paramName);
                if (branches >= MIN_BRANCHES) {
                    out.add(branches);
                }
                return super.visitIf(iff, out);
            }
        }.visit(body, counts);
        return maxOrZero(counts);
    }

    private static int maxOrZero(List<Integer> counts) {
        return counts.stream().mapToInt(Integer::intValue).max().orElse(0);
    }

    private static int caseCount(J.Switch sw) {
        return (int) sw.getCases().getStatements().stream()
                .filter(J.Case.class::isInstance)
                .count();
    }

    private static boolean selectorReferencesParam(J.ControlParentheses<Expression> selector, String paramName) {
        return selector.getTree().toString().trim().equals(paramName);
    }

    private static int countChainedEquals(J.If iff, String paramName) {
        int count = 0;
        J.If current = iff;
        while (current != null) {
            if (conditionReferencesParamEquals(current.getIfCondition(), paramName)) {
                count++;
            }
            if (current.getElsePart() != null && current.getElsePart().getBody() instanceof J.If nextIf) {
                current = nextIf;
            } else {
                break;
            }
        }
        return count;
    }

    private static boolean conditionReferencesParamEquals(
            J.ControlParentheses<Expression> cond, String paramName) {
        final String condStr = cond.toString().trim();
        return condStr.contains(paramName + EQUALS_CALL) || condStr.contains(EQUALS_CALL + paramName + ")");
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.JavaType;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class StringlyTypedDispatchRecipe extends ScanningRecipe<StringlyTypedDispatchRecipe.Accumulator> {

    private static final String JAVA_LANG_STRING = "java.lang.String";
    private static final String STRING_SIMPLE_NAME = "String";

    public record Row(String className, String methodName, String parameterName, int branchCount) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Stringly-typed dispatch detection";
    }

    @Override
    public String getDescription() {
        return "Detects methods that use a String parameter to select behaviour via switch or if/else chains.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new DispatchScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    static boolean isStringType(J.VariableDeclarations varDecls) {
        if (varDecls.getType() instanceof JavaType.FullyQualified fq) {
            return JAVA_LANG_STRING.equals(fq.getFullyQualifiedName());
        }
        if (varDecls.getTypeExpression() == null) {
            return false;
        }
        final String typeExpressionText = varDecls.getTypeExpression().toString().trim();
        return STRING_SIMPLE_NAME.equals(typeExpressionText);
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Finding;
import org.fiftieshousewife.cleancode.core.FindingSource;
import org.fiftieshousewife.cleancode.core.FindingSourceException;
import org.fiftieshousewife.cleancode.core.ProjectContext;
import org.fiftieshousewife.cleancode.core.Severity;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Set;

public class JacocoFindingSource implements FindingSource {

    private static final int MIN_CLASS_LINES = 10;
    private static final String LINE_COUNTER_TYPE = "LINE";
    private static final String COUNTER_TAG = "counter";
    private static final double CLASS_COVERAGE_WARNING_THRESHOLD = 50.0;
    private static final double COVERAGE_ERROR_THRESHOLD = 50.0;
    private static final double COVERAGE_WARNING_THRESHOLD = 75.0;

    @Override
    public String id() {
        return "jacoco";
    }

    @Override
    public String displayName() {
        return "JaCoCo";
    }

    @Override
    public Set<HeuristicCode> coveredCodes() {
        return Set.of(HeuristicCode.T1, HeuristicCode.T2, HeuristicCode.T8);
    }

    @Override
    public boolean isAvailable(final ProjectContext context) {
        return true;
    }

    @Override
    public List<Finding> collectFindings(final ProjectContext context) throws FindingSourceException {
        final Path report = reportPath(context);
        if (!Files.exists(report)) {
            return missingReportFindings(context);
        }
        final Document doc = XmlReportParser.parse(report);
        final List<Finding> findings = new ArrayList<>(projectLevelCoverage(doc));
        findings.addAll(perClassFindings(doc));
        return findings;
    }

    private List<Finding> missingReportFindings(final ProjectContext context) {
        final boolean hasTestSources = context.testSourceRoots().stream().anyMatch(Files::exists);
        if (!hasTestSources) {
            return List.of();
        }
        return List.of(Finding.projectLevel(HeuristicCode.T2,
                "JaCoCo report not found — coverage tool not configured",
                Severity.ERROR, Confidence.HIGH, "jacoco", "missing-report"));
    }

    private List<Finding> projectLevelCoverage(final Document doc) {
        return reportLineCounter(doc).map(this::projectCoverageFinding).map(List::of).orElseGet(List::of);
    }

    private Optional<Element> reportLineCounter(final Document doc) {
        final NodeList counters = doc.getDocumentElement().getChildNodes();
        for (int i = 0; i < counters.getLength(); i++) {
            if (isLineCounter(counters.item(i))) {
                return Optional.of((Element) counters.item(i));
            }
        }
        return Optional.empty();
    }

    private boolean isLineCounter(final Object node) {
        return node instanceof Element el
                && COUNTER_TAG.equals(el.getTagName())
                && LINE_COUNTER_TYPE.equals(el.getAttribute("type"));
    }

    private Finding projectCoverageFinding(final Element counter) {
        final LineCoverage coverage = LineCoverage.from(counter);
        return Finding.projectLevel(HeuristicCode.T1,
                String.format("Overall line coverage: %.1f%% (%d/%d lines covered)",
                        coverage.percentage(), coverage.covered(), coverage.total()),
                coverageSeverity(coverage.percentage()), Confidence.HIGH, "jacoco", "line-coverage");
    }

    private List<Finding> perClassFindings(final Document doc) {
        final NodeList classNodes = doc.getElementsByTagName("class");
        final List<Finding> findings = new ArrayList<>();
        for (int i = 0; i < classNodes.getLength(); i++) {
            classFinding((Element) classNodes.item(i)).ifPresent(findings::add);
        }
        return findings;
    }

    private Optional<Finding> classFinding(final Element classElement) {
        return classLineCounter(classElement)
                .map(LineCoverage::from)
                .filter(c -> c.total() >= MIN_CLASS_LINES)
                .filter(c -> c.percentage() < CLASS_COVERAGE_WARNING_THRESHOLD)
                .map(c -> classCoverageFinding(classElement, c));
    }

    private Optional<Element> classLineCounter(final Element classElement) {
        final NodeList counters = classElement.getElementsByTagName(COUNTER_TAG);
        for (int j = 0; j < counters.getLength(); j++) {
            final Element counter = (Element) counters.item(j);
            if (LINE_COUNTER_TYPE.equals(counter.getAttribute("type"))) {
                return Optional.of(counter);
            }
        }
        return Optional.empty();
    }

    private Finding classCoverageFinding(final Element classElement, final LineCoverage coverage) {
        final String className = classElement.getAttribute("name");
        final int simpleNameStart = className.lastIndexOf('/') + 1;
        final String packagePath = className.substring(0, simpleNameStart - 1);
        final String simpleName = className.substring(simpleNameStart);
        final String sourcePath = packagePath + "/" + classElement.getAttribute("sourcefilename");
        return Finding.at(HeuristicCode.T8, sourcePath, 1, -1,
                String.format("Class %s has %.1f%% line coverage (%d/%d lines)",
                        simpleName, coverage.percentage(), coverage.covered(), coverage.total()),
                Severity.WARNING, Confidence.MEDIUM, "jacoco", "class-coverage");
    }

    private Severity coverageSeverity(final double percentage) {
        if (percentage < COVERAGE_ERROR_THRESHOLD) {
            return Severity.ERROR;
        }
        return percentage < COVERAGE_WARNING_THRESHOLD ? Severity.WARNING : Severity.INFO;
    }

    private Path reportPath(final ProjectContext context) {
        return context.reportsDir().resolve("jacoco/test/jacocoTestReport.xml");
    }
}

package org.fiftieshousewife.cleancode.core;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.io.InputStream;
import java.io.UncheckedIOException;
import java.util.Comparator;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.Properties;
import java.util.stream.Collectors;

import static org.fiftieshousewife.cleancode.core.HtmlEscaping.escape;

final class HtmlFindingsRenderer {

    private static final String TEMPLATES_RESOURCE =
            "/org/fiftieshousewife/cleancode/core/html-findings-templates.properties";
    private static final Properties TEMPLATES = loadTemplates();

    private static final String SRC_JAVA_PREFIX = "src/main/java/";
    private static final String SRC_PREFIX = "src/";
    private static final char URL_SEPARATOR = '/';
    private static final String PROJECT_LOCATION = "(project)";

    private HtmlFindingsRenderer() {}

    static void appendFindingsByCode(final StringBuilder html, final List<Finding> findings,
                                      final String repositoryUrl) {
        final Map<HeuristicCode, List<Finding>> byCode = findings.stream()
                .collect(Collectors.groupingBy(Finding::code));

        byCode.entrySet().stream()
                .sorted(Comparator.comparing(entry -> entry.getKey().name()))
                .forEach(entry -> html.append(renderCodeGroup(entry.getKey(), entry.getValue(), repositoryUrl)));
    }

    static void appendToolSummary(final StringBuilder html, final List<Finding> findings) {
        final Map<String, Long> byTool = findings.stream()
                .collect(Collectors.groupingBy(Finding::tool, Collectors.counting()));

        final String toolRows = byTool.entrySet().stream()
                .sorted(Map.Entry.<String, Long>comparingByValue().reversed())
                .map(entry -> renderToolRow(entry.getKey(), entry.getValue()))
                .collect(Collectors.joining());

        html.append(template("tool-summary").replace("{toolRows}", toolRows));
    }

    static String renderCodeGroup(final HeuristicCode code, final List<Finding> group,
                                   final String repositoryUrl) {
        final String findingRows = group.stream()
                .sorted(Comparator.comparing(finding -> finding.sourceFile() != null ? finding.sourceFile() : ""))
                .map(finding -> renderFindingRow(finding, repositoryUrl))
                .collect(Collectors.joining());

        return template("code-group")
                .replace("{codeName}", escape(code.name()))
                .replace("{heuristicName}", escape(HeuristicDescriptions.name(code)))
                .replace("{count}", Integer.toString(group.size()))
                .replace("{reference}", renderOptionalParagraph("reference", HeuristicDescriptions.reference(code)))
                .replace("{guidance}", renderOptionalParagraph("guidance", HeuristicDescriptions.guidance(code)))
                .replace("{findingRows}", findingRows);
    }

    static String renderFindingRow(final Finding finding, final String repositoryUrl) {
        final String severityClass = "sev-" + finding.severity().name().toLowerCase(Locale.ROOT);
        final String location = formatLocation(finding);
        final String locationHtml = buildLocationHtml(finding, location, repositoryUrl);

        return template("finding-row")
                .replace("{severityClass}", severityClass)
                .replace("{severityName}", finding.severity().name())
                .replace("{locationHtml}", locationHtml)
                .replace("{message}", escape(finding.message()));
    }

    static String buildLocationHtml(final Finding finding, final String location, final String repositoryUrl) {
        if (cannotLinkToRepository(finding, repositoryUrl)) {
            return escape(location);
        }
        final String baseUrl = stripTrailingSlash(repositoryUrl);
        final String relativePath = pathAfterPrefix(finding.sourceFile(), SRC_PREFIX);
        final String fileUrl = baseUrl + URL_SEPARATOR + relativePath;
        final String linkedUrl = finding.startLine() > 0 ? fileUrl + "#L" + finding.startLine() : fileUrl;
        return template("location-link")
                .replace("{url}", escape(linkedUrl))
                .replace("{label}", escape(location));
    }

    static String formatLocation(final Finding finding) {
        if (finding.sourceFile() == null) {
            return PROJECT_LOCATION;
        }
        final String file = pathAfterPrefix(finding.sourceFile(), SRC_JAVA_PREFIX);
        return finding.startLine() > 0 ? file + ":" + finding.startLine() : file;
    }

    private static boolean cannotLinkToRepository(final Finding finding, final String repositoryUrl) {
        return finding.sourceFile() == null || repositoryUrl == null || repositoryUrl.isBlank();
    }

    private static String stripTrailingSlash(final String url) {
        if (!url.endsWith("/")) {
            return url;
        }
        final int lastCharIndex = url.length() - 1;
        return url.substring(0, lastCharIndex);
    }

    private static String pathAfterPrefix(final String path, final String prefix) {
        final int prefixIndex = path.indexOf(prefix);
        if (prefixIndex < 0) {
            return path;
        }
        return path.substring(prefixIndex + (prefix.equals(SRC_JAVA_PREFIX) ? prefix.length() : 0));
    }

    private static String renderOptionalParagraph(final String cssClass, final String text) {
        if (text == null) {
            return "";
        }
        return template("optional-paragraph")
                .replace("{cssClass}", cssClass)
                .replace("{text}", escape(text));
    }

    private static String renderToolRow(final String tool, final Long count) {
        return template("tool-row")
                .replace("{tool}", escape(tool))
                .replace("{count}", Long.toString(count));
    }

    private static String template(final String key) {
        final String value = TEMPLATES.getProperty(key);
        if (value == null) {
            throw new IllegalStateException("Missing HTML template fragment: " + key);
        }
        return value;
    }

    private static Properties loadTemplates() {
        final Properties properties = new Properties();
        try (InputStream stream = HtmlFindingsRenderer.class.getResourceAsStream(TEMPLATES_RESOURCE)) {
            if (stream == null) {
                throw new IllegalStateException("Missing HTML templates resource: " + TEMPLATES_RESOURCE);
            }
            properties.load(stream);
            return properties;
        } catch (final IOException exception) {
            throw new UncheckedIOException("Failed to load HTML templates: " + TEMPLATES_RESOURCE, exception);
        }
    }
}

