package org.fiftieshousewife.cleancode.recipes;

import java.util.Arrays;

final class CommentWordOverlap {

    private CommentWordOverlap() {}

    static long countSignificantWords(final String[] words) {
        return Arrays.stream(words)
                .filter(w -> w.length() >= MumblingThresholds.MIN_SIGNIFICANT_WORD_LENGTH)
                .count();
    }

    static long countSignificantWordsFoundIn(final String[] words, final String text) {
        return Arrays.stream(words)
                .filter(w -> w.length() >= MumblingThresholds.MIN_SIGNIFICANT_WORD_LENGTH)
                .filter(text::contains)
                .count();
    }

    static boolean hasEnoughOverlap(final long significantCodeWords, final long codeWordsInComment) {
        final boolean enoughCodeWords = significantCodeWords >= MumblingThresholds.MIN_WORDS;
        final double requiredOverlap = significantCodeWords * MumblingThresholds.RESTATEMENT_RATIO;
        return enoughCodeWords && codeWordsInComment >= requiredOverlap;
    }

    static boolean allWordsPresent(final String text, final String[] words) {
        if (words.length < MumblingThresholds.MIN_WORDS) {
            return false;
        }
        final String[] textWords = MumblingCommentRecipe.WHITESPACE.split(text);
        for (final String word : words) {
            if (word.length() < MumblingThresholds.MIN_MEANINGFUL_WORD_LENGTH) {
                continue;
            }
            if (!hasPrefixMatch(textWords, word)) {
                return false;
            }
        }
        return true;
    }

    private static boolean hasPrefixMatch(final String[] textWords, final String word) {
        return Arrays.stream(textWords)
                .anyMatch(tw -> tw.startsWith(word) || word.startsWith(tw));
    }
}

package org.fiftieshousewife.cleancode.recipes;

final class LineCommentExtractor {

    private static final String LINE_COMMENT_MARKER = "//";
    private static final int LINE_COMMENT_MARKER_LENGTH = LINE_COMMENT_MARKER.length();

    private LineCommentExtractor() {}

    static String extract(final String line) {
        final String stripped = stripStringLiterals(line);
        final int idx = stripped.indexOf(LINE_COMMENT_MARKER);
        if (idx < 0) {
            return null;
        }
        final String text = stripped.substring(idx + LINE_COMMENT_MARKER_LENGTH).trim();
        return text.length() >= MumblingCommentRecipe.MIN_COMMENT_LENGTH ? text : null;
    }

    static String stripStringLiterals(final String line) {
        final StringBuilder result = new StringBuilder(line.length());
        boolean inString = false;
        for (int i = 0; i < line.length(); i++) {
            final char ch = line.charAt(i);
            if (ch == '\\' && inString && i + 1 < line.length()) {
                i++;
                continue;
            }
            if (ch == '"') {
                inString = !inString;
                continue;
            }
            if (!inString) {
                result.append(ch);
            }
        }
        return result.toString();
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.Row;
import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.WHITESPACE;
import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.camelToWords;
import static org.fiftieshousewife.cleancode.recipes.MumblingCommentRecipe.normalise;

final class MumblingCommentScanner extends JavaIsoVisitor<ExecutionContext> {

    private static final int MAX_PREVIEW_LENGTH = 60;
    private static final int UNKNOWN_LINE = -1;
    private static final String UNKNOWN_CLASS = "<unknown>";

    private final MumblingCommentRecipe.Accumulator acc;

    MumblingCommentScanner(final MumblingCommentRecipe.Accumulator acc) {
        this.acc = acc;
    }

    @Override
    public J.MethodDeclaration visitMethodDeclaration(final J.MethodDeclaration method, final ExecutionContext ctx) {
        final J.MethodDeclaration visited = super.visitMethodDeclaration(method, ctx);
        final MumblingContext context = new MumblingContext(
                findEnclosingClassName(),
                visited.getSimpleName(),
                extractParamNames(visited));
        final List<String> lines = visited.print(getCursor()).lines().toList();
        for (int i = 0; i < lines.size(); i++) {
            inspectLine(lines, i, context);
        }
        return visited;
    }

    private void inspectLine(final List<String> lines, final int index, final MumblingContext context) {
        final String commentText = LineCommentExtractor.extract(lines.get(index));
        if (commentText == null) {
            return;
        }
        final String normalised = normalise(commentText);
        final String nextLine = index + 1 < lines.size() ? lines.get(index + 1).trim() : "";
        if (isMumbling(normalised, context, nextLine)) {
            acc.rows.add(new Row(context.className(), context.methodName(), preview(commentText), UNKNOWN_LINE));
        }
    }

    private String preview(final String commentText) {
        return commentText.substring(0, Math.min(MAX_PREVIEW_LENGTH, commentText.length()));
    }

    boolean isMumbling(final String normalisedComment, final MumblingContext context, final String nextCodeLine) {
        if (restatesMethodName(normalisedComment, context.methodName())) {
            return true;
        }
        if (restatesAllParameters(normalisedComment, context.paramNames())) {
            return true;
        }
        return !nextCodeLine.isEmpty() && restatesNextLine(normalisedComment, nextCodeLine);
    }

    private boolean restatesMethodName(final String normalisedComment, final String methodName) {
        final String[] methodWords = WHITESPACE.split(normalise(camelToWords(methodName)));
        return CommentWordOverlap.allWordsPresent(normalisedComment, methodWords);
    }

    private boolean restatesAllParameters(final String normalisedComment, final Set<String> paramNames) {
        if (paramNames.isEmpty()) {
            return false;
        }
        final long matchCount = paramNames.stream()
                .filter(p -> normalisedComment.contains(normalise(p)))
                .count();
        return matchCount >= paramNames.size();
    }

    boolean restatesNextLine(final String normalisedComment, final String nextCodeLine) {
        final String[] commentWords = WHITESPACE.split(normalisedComment);
        final String[] codeWords = WHITESPACE.split(normalise(nextCodeLine));
        if (commentWords.length < MumblingThresholds.MIN_WORDS
                || codeWords.length < MumblingThresholds.MIN_WORDS) {
            return false;
        }
        final long significantCodeWords = CommentWordOverlap.countSignificantWords(codeWords);
        final long codeWordsInComment = CommentWordOverlap.countSignificantWordsFoundIn(codeWords, normalisedComment);
        return CommentWordOverlap.hasEnoughOverlap(significantCodeWords, codeWordsInComment);
    }

    private Set<String> extractParamNames(final J.MethodDeclaration method) {
        final Set<String> names = new HashSet<>();
        method.getParameters().stream()
                .filter(J.VariableDeclarations.class::isInstance)
                .map(J.VariableDeclarations.class::cast)
                .forEach(v -> v.getVariables().forEach(named -> names.add(named.getSimpleName())));
        return names;
    }

    private String findEnclosingClassName() {
        final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
        return classDecl != null ? classDecl.getSimpleName() : UNKNOWN_CLASS;
    }

    record MumblingContext(String className, String methodName, Set<String> paramNames) {}
}

package org.fiftieshousewife.cleancode.core;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;
import org.fiftieshousewife.cleancode.annotations.HeuristicCode;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.EnumMap;
import java.util.EnumSet;
import java.util.Map;
import java.util.Set;
import java.util.TreeMap;
import java.util.stream.Collectors;

public final class BaselineManager {

    private static final Set<String> KNOWN_CODES = EnumSet.allOf(HeuristicCode.class).stream()
            .map(Enum::name)
            .collect(Collectors.toUnmodifiableSet());

    private BaselineManager() {}

    public record Delta(int baseline, int current, int change) {}

    private record BaselineSnapshot(Map<String, Integer> counts) {
        BaselineSnapshot {
            counts = counts == null ? Map.of() : counts;
        }
    }

    public static void writeBaseline(final AggregatedReport report, final Path baselineFile) throws IOException {
        final Map<String, Integer> counts = report.findings().stream()
                .collect(Collectors.groupingBy(
                        f -> f.code().name(),
                        TreeMap::new,
                        Collectors.collectingAndThen(Collectors.counting(), Long::intValue)));

        final BaselineSnapshot snapshot = new BaselineSnapshot(counts);
        final Gson gson = new GsonBuilder().setPrettyPrinting().create();
        final Path parent = baselineFile.getParent();
        if (parent != null) {
            Files.createDirectories(parent);
        }
        Files.writeString(baselineFile, gson.toJson(snapshot));
    }

    public static Map<HeuristicCode, Integer> readBaseline(final Path baselineFile) throws IOException {
        if (!Files.exists(baselineFile)) {
            return Map.of();
        }

        final String json = Files.readString(baselineFile);
        final BaselineSnapshot snapshot = new Gson().fromJson(json, BaselineSnapshot.class);

        final Map<HeuristicCode, Integer> result = new EnumMap<>(HeuristicCode.class);
        snapshot.counts().entrySet().stream()
                .filter(entry -> KNOWN_CODES.contains(entry.getKey()))
                .forEach(entry -> result.put(HeuristicCode.valueOf(entry.getKey()), entry.getValue()));
        return result;
    }

    public static Map<HeuristicCode, Delta> computeDeltas(final AggregatedReport report,
                                                            final Path baselineFile) throws IOException {
        final Map<HeuristicCode, Integer> baselineCounts = readBaseline(baselineFile);

        final Map<HeuristicCode, Long> currentCounts = report.findings().stream()
                .collect(Collectors.groupingBy(Finding::code, Collectors.counting()));

        final Set<HeuristicCode> allCodes = EnumSet.noneOf(HeuristicCode.class);
        allCodes.addAll(baselineCounts.keySet());
        allCodes.addAll(currentCounts.keySet());

        final Map<HeuristicCode, Delta> deltas = new TreeMap<>();
        for (final HeuristicCode code : allCodes) {
            final int baseline = baselineCounts.getOrDefault(code, 0);
            final int current = currentCounts.getOrDefault(code, 0L).intValue();
            deltas.put(code, new Delta(baseline, current, current - baseline));
        }
        return deltas;
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonProperty;
import org.openrewrite.ExecutionContext;
import org.openrewrite.Recipe;
import org.openrewrite.SourceFile;
import org.openrewrite.Tree;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.JavaParser;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Space;
import org.openrewrite.java.tree.Statement;
import org.openrewrite.marker.Markers;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;

public class ExtractExplanatoryVariableRecipe extends Recipe {

    private static final int NO_CHAIN = 0;
    private static final int LEAF_CHAIN = 1;
    private static final int CHAIN_INCREMENT = 1;

    private static final Map<String, String> NAME_BY_KEYWORD = Map.of(
            "startsWith", "hasExpectedPrefix",
            "equals", "isMatch",
            "contains", "containsTarget");
    private static final String FALLBACK_NAME = "condition";

    private final int minChainDepth;

    @JsonCreator
    public ExtractExplanatoryVariableRecipe(@JsonProperty("minChainDepth") final int minChainDepth) {
        this.minChainDepth = minChainDepth;
    }

    @Override
    public String getDisplayName() {
        return "Extract complex expressions to explanatory variables";
    }

    @Override
    public String getDescription() {
        return "Extracts method chains of depth %d+ in if-conditions to named local variables. Fixes G19/G28."
                .formatted(minChainDepth);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor() {
        return new JavaIsoVisitor<>() {
            @Override
            public J.Block visitBlock(final J.Block block, final ExecutionContext ctx) {
                final J.Block visited = super.visitBlock(block, ctx);
                final List<Statement> rewritten = new ArrayList<>();
                boolean changed = false;
                for (final Statement stmt : visited.getStatements()) {
                    final List<Statement> replacement = tryExtract(stmt);
                    if (replacement == null) {
                        rewritten.add(stmt);
                    } else {
                        rewritten.addAll(replacement);
                        changed = true;
                    }
                }
                return changed ? visited.withStatements(rewritten) : visited;
            }
        };
    }

    private List<Statement> tryExtract(final Statement stmt) {
        if (!(stmt instanceof J.If ifStmt)) {
            return null;
        }
        final Expression condition = ifStmt.getIfCondition().getTree();
        if (chainDepth(condition) < minChainDepth) {
            return null;
        }
        final String condText = condition.toString().trim();
        final String varName = generateVariableName(condText);
        final Statement varDecl = parseVariableDeclaration(varName, condText);
        if (varDecl == null) {
            return null;
        }
        final J.Identifier varRef = identifier(varName);
        final J.If updated = ifStmt.withIfCondition(ifStmt.getIfCondition().withTree(varRef));
        return List.of(varDecl, updated);
    }

    private static Statement parseVariableDeclaration(final String varName, final String condText) {
        final String declSource = "class _T { void _m() { final var %s = %s; } }".formatted(varName, condText);
        final List<SourceFile> parsed = JavaParser.fromJavaVersion()
                .logCompilationWarningsAndErrors(false)
                .build().parse(declSource).toList();
        if (parsed.isEmpty()) {
            return null;
        }
        final J.CompilationUnit cu = (J.CompilationUnit) parsed.getFirst();
        final J.MethodDeclaration method = (J.MethodDeclaration) cu.getClasses().getFirst()
                .getBody().getStatements().getFirst();
        return method.getBody().getStatements().getFirst();
    }

    private static J.Identifier identifier(final String name) {
        return new J.Identifier(Tree.randomId(), Space.EMPTY, Markers.EMPTY, List.of(), name, null, null);
    }

    static int chainDepth(final Expression expr) {
        if (expr instanceof J.MethodInvocation mi) {
            return chainDepthOfMethodInvocation(mi);
        }
        if (expr instanceof J.FieldAccess fa) {
            return CHAIN_INCREMENT + chainDepth(fa.getTarget());
        }
        if (expr instanceof J.Parentheses<?> p && p.getTree() instanceof Expression inner) {
            return chainDepth(inner);
        }
        if (expr instanceof J.Binary binary) {
            return Math.max(chainDepth(binary.getLeft()), chainDepth(binary.getRight()));
        }
        return NO_CHAIN;
    }

    private static int chainDepthOfMethodInvocation(final J.MethodInvocation mi) {
        return mi.getSelect() == null ? LEAF_CHAIN : CHAIN_INCREMENT + chainDepth(mi.getSelect());
    }

    private static String generateVariableName(final String conditionText) {
        return NAME_BY_KEYWORD.entrySet().stream()
                .filter(entry -> conditionText.contains(entry.getKey()))
                .map(Map.Entry::getValue)
                .findFirst()
                .orElse(FALLBACK_NAME);
    }
}

