package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Set;

public class SideEffectNamingRecipe extends ScanningRecipe<SideEffectNamingRecipe.Accumulator> {

    static final String ASSIGNS_TO = "assigns to ";

    // Java query-method prefixes. These are inherent to the N7 heuristic (detecting
    // query-named methods that mutate state), not arbitrary configuration data, so
    // they live here rather than in an external config file.
    static final Set<String> QUERY_PREFIXES = Set.of("get", "find", "is", "has", "check");

    public record Row(String className, String methodName, String sideEffect, int lineNumber) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Side-effect naming detection (N7)";
    }

    @Override
    public String getDescription() {
        return "Detects methods whose name suggests a pure query but whose body modifies state via assignments.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new SideEffectNamingVisitor(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    static boolean hasQueryPrefix(String name) {
        return QUERY_PREFIXES.stream().anyMatch(prefix -> startsWithQueryPrefix(name, prefix));
    }

    private static boolean startsWithQueryPrefix(String name, String prefix) {
        if (!name.startsWith(prefix)) {
            return false;
        }
        if (name.length() <= prefix.length()) {
            return false;
        }
        return Character.isUpperCase(name.charAt(prefix.length()));
    }

    private static final class SideEffectNamingVisitor extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;

        SideEffectNamingVisitor(Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.MethodDeclaration visitMethodDeclaration(J.MethodDeclaration method, ExecutionContext ctx) {
            final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
            if (shouldSkip(m)) {
                return m;
            }
            final String sideEffect = findSideEffect(m.getBody());
            if (sideEffect != null) {
                acc.rows.add(new Row(findEnclosingClassName(), m.getSimpleName(), sideEffect, -1));
            }
            return m;
        }

        private boolean shouldSkip(J.MethodDeclaration method) {
            return hasOverrideAnnotation(method)
                    || !hasQueryPrefix(method.getSimpleName())
                    || method.getBody() == null;
        }

        private boolean hasOverrideAnnotation(J.MethodDeclaration method) {
            return method.getLeadingAnnotations().stream()
                    .anyMatch(ann -> "Override".equals(ann.getSimpleName()));
        }

        private String findSideEffect(J.Block body) {
            for (final var statement : body.getStatements()) {
                if (statement instanceof J.Assignment assignment) {
                    return ASSIGNS_TO + assignment.getVariable().printTrimmed(getCursor());
                }
                if (statement instanceof J.AssignmentOperation assignOp) {
                    return ASSIGNS_TO + assignOp.getVariable().printTrimmed(getCursor());
                }
            }
            return null;
        }

        private String findEnclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : "<unknown>";
        }
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.regex.Pattern;

public class MagicStringRecipe extends ScanningRecipe<MagicStringRecipe.Accumulator> {

    private static final int MIN_LENGTH = 3;
    private static final int MAX_TOOL_ID_LENGTH = 15;
    private static final int DEFAULT_MIN_OCCURRENCES = 2;
    private static final int UNKNOWN_LINE = -1;

    // G35 skipped intentionally: these are intrinsic to the "magic string" heuristic itself —
    // moving them to config would require config to bootstrap this recipe, and callers expect
    // consistent exclusions across runs. The set is small and stable.
    private static final Set<String> IGNORED_VALUES = Set.of(
            "UTF-8", "application/json", "text/plain", "text/html",
            "Content-Type", "Accept", "Authorization",
            "<unknown>"
    );

    private static final Pattern TOOL_ID_PATTERN = Pattern.compile("^[a-z][a-z0-9-]*$");

    private final int minOccurrences;

    private Accumulator lastAccumulator;

    public MagicStringRecipe() {
        this(DEFAULT_MIN_OCCURRENCES);
    }

    public MagicStringRecipe(final int minOccurrences) {
        this.minOccurrences = minOccurrences;
    }

    public record Row(String className, String value, int count, int lineNumber) {}

    record Occurrence(String value, int lineNumber) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    @Override
    public String getDisplayName() {
        return "Magic string detection (G25)";
    }

    @Override
    public String getDescription() {
        return "Detects string literals that appear more than once in the same class "
                + "and should be extracted to named constants.";
    }

    @Override
    public Accumulator getInitialValue(final ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(final Accumulator acc) {
        return new JavaIsoVisitor<>() {
            @Override
            public J.ClassDeclaration visitClassDeclaration(final J.ClassDeclaration classDecl, final ExecutionContext ctx) {
                final J.ClassDeclaration visited = super.visitClassDeclaration(classDecl, ctx);
                recordDuplicateLiterals(visited, acc);
                return visited;
            }
        };
    }

    private void recordDuplicateLiterals(final J.ClassDeclaration classDecl, final Accumulator acc) {
        final List<Occurrence> occurrences = collectCandidateLiterals(classDecl);
        final Map<String, List<Occurrence>> grouped = groupByValue(occurrences);
        final String className = classDecl.getSimpleName();
        grouped.forEach((value, occs) -> {
            if (occs.size() >= minOccurrences) {
                acc.rows.add(new Row(className, value, occs.size(), occs.getFirst().lineNumber()));
            }
        });
    }

    private static List<Occurrence> collectCandidateLiterals(final J.ClassDeclaration classDecl) {
        final LiteralCollector collector = new LiteralCollector();
        collector.visit(classDecl.getBody(), 0);
        return collector.occurrences();
    }

    private static Map<String, List<Occurrence>> groupByValue(final List<Occurrence> occurrences) {
        final Map<String, List<Occurrence>> grouped = new HashMap<>();
        occurrences.forEach(occ -> grouped.computeIfAbsent(occ.value(), k -> new ArrayList<>()).add(occ));
        return grouped;
    }

    private static final class LiteralCollector extends JavaIsoVisitor<Integer> {
        private final List<Occurrence> occurrences = new ArrayList<>();

        List<Occurrence> occurrences() {
            return occurrences;
        }

        @Override
        public J.Literal visitLiteral(final J.Literal literal, final Integer ignored) {
            final J.Literal lit = super.visitLiteral(literal, ignored);
            if (isInsideAnnotation() || isInsideMapEntry()) {
                return lit;
            }
            if (lit.getValue() instanceof String stringValue && isCandidate(stringValue)) {
                occurrences.add(new Occurrence(stringValue, UNKNOWN_LINE));
            }
            return lit;
        }

        private boolean isInsideAnnotation() {
            return getCursor().firstEnclosing(J.Annotation.class) != null;
        }

        private boolean isInsideMapEntry() {
            final J.MethodInvocation enclosing = getCursor().firstEnclosing(J.MethodInvocation.class);
            return enclosing != null && "entry".equals(enclosing.getSimpleName());
        }
    }

    static boolean isCandidate(final String value) {
        return value.length() >= MIN_LENGTH
                && !value.isBlank()
                && !IGNORED_VALUES.contains(value)
                && !containsAngleBracket(value)
                && !containsPathSeparator(value)
                && !isShortToolId(value);
    }

    private static boolean containsAngleBracket(final String value) {
        return value.contains("<") || value.contains(">");
    }

    private static boolean containsPathSeparator(final String value) {
        return value.contains("/") || value.contains(".claude/");
    }

    private static boolean isShortToolId(final String value) {
        return value.length() < MAX_TOOL_ID_LENGTH && TOOL_ID_PATTERN.matcher(value).matches();
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(final Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class UncheckedCastRecipe extends ScanningRecipe<UncheckedCastRecipe.Accumulator> {

    private static final String UNCHECKED = "unchecked";
    private static final String SUPPRESS_WARNINGS = "SuppressWarnings";
    private static final String UNKNOWN_CLASS = "<unknown>";
    private static final String CLASS_LEVEL_MEMBER = "<class-level>";

    public record Row(String className, String memberName, int lineNumber) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Unchecked cast detection";
    }

    @Override
    public String getDescription() {
        return "Detects @SuppressWarnings(\"unchecked\") annotations that indicate type system workarounds.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new UncheckedCastScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    static boolean isSuppressUnchecked(final J.Annotation annotation) {
        return isSuppressWarnings(annotation) && containsUnchecked(annotation);
    }

    static boolean isSuppressWarnings(final J.Annotation annotation) {
        return annotation.getAnnotationType() instanceof J.Identifier id
                && SUPPRESS_WARNINGS.equals(id.getSimpleName());
    }

    static boolean containsUnchecked(final J.Annotation annotation) {
        final List<Expression> arguments = annotation.getArguments();
        if (arguments == null) {
            return false;
        }
        return arguments.stream().anyMatch(UncheckedCastRecipe::argumentMentionsUnchecked);
    }

    static boolean argumentMentionsUnchecked(final Expression argument) {
        if (argument instanceof J.Assignment assignment) {
            return expressionMentionsUnchecked(assignment.getAssignment());
        }
        return expressionMentionsUnchecked(argument);
    }

    static boolean expressionMentionsUnchecked(final Expression expression) {
        if (expression instanceof J.Literal literal) {
            return isUncheckedLiteral(literal);
        }
        if (expression instanceof J.NewArray newArray) {
            return arrayMentionsUnchecked(newArray);
        }
        return false;
    }

    static boolean arrayMentionsUnchecked(final J.NewArray newArray) {
        final List<Expression> initializer = newArray.getInitializer();
        if (initializer == null) {
            return false;
        }
        return initializer.stream()
                .filter(J.Literal.class::isInstance)
                .map(J.Literal.class::cast)
                .anyMatch(UncheckedCastRecipe::isUncheckedLiteral);
    }

    static boolean isUncheckedLiteral(final J.Literal literal) {
        return literal.getValue() instanceof String value && value.contains(UNCHECKED);
    }

    static final class UncheckedCastScanner extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;

        UncheckedCastScanner(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.Annotation visitAnnotation(final J.Annotation annotation, final ExecutionContext ctx) {
            final J.Annotation ann = super.visitAnnotation(annotation, ctx);
            if (isSuppressUnchecked(ann)) {
                acc.rows.add(new Row(findEnclosingClassName(), findEnclosingMemberName(), -1));
            }
            return ann;
        }

        String findEnclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : UNKNOWN_CLASS;
        }

        String findEnclosingMemberName() {
            final J.MethodDeclaration methodDecl = getCursor().firstEnclosing(J.MethodDeclaration.class);
            if (methodDecl != null) {
                return methodDecl.getSimpleName();
            }
            return findEnclosingVariableName();
        }

        String findEnclosingVariableName() {
            final J.VariableDeclarations varDecls = getCursor().firstEnclosing(J.VariableDeclarations.class);
            if (varDecls == null || varDecls.getVariables().isEmpty()) {
                return CLASS_LEVEL_MEMBER;
            }
            return varDecls.getVariables().getFirst().getSimpleName();
        }
    }
