package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.JavaType;

import java.util.Map;

final class FeatureEnvyScanner extends JavaIsoVisitor<ExecutionContext> {

    private static final String UNKNOWN_CLASS_NAME = "<unknown>";

    private final FeatureEnvyRecipe.Accumulator acc;

    FeatureEnvyScanner(FeatureEnvyRecipe.Accumulator acc) {
        this.acc = acc;
    }

    @Override
    public J.CompilationUnit visitCompilationUnit(J.CompilationUnit cu, ExecutionContext ctx) {
        cu.getClasses().forEach(classDecl -> collectProjectTypes(classDecl, packagePrefix(cu)));
        return super.visitCompilationUnit(cu, ctx);
    }

    @Override
    public J.MethodDeclaration visitMethodDeclaration(J.MethodDeclaration method, ExecutionContext ctx) {
        final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
        if (isExcluded(m)) {
            return m;
        }
        final CallCounter counter = countCalls(m);
        if (counter.totalCalls() < FeatureEnvyRecipe.MINIMUM_CALL_THRESHOLD) {
            return m;
        }
        recordEnviedClass(m, counter);
        return m;
    }

    private boolean isExcluded(J.MethodDeclaration m) {
        return isConstructor(m) || isStatic(m) || isInTestClass() || isVisitorMethod(m);
    }

    private CallCounter countCalls(J.MethodDeclaration m) {
        final CallCounter counter = new CallCounter();
        new CallClassifier(acc).visit(m, counter);
        return counter;
    }

    private void recordEnviedClass(J.MethodDeclaration m, CallCounter counter) {
        counter.externalCalls.entrySet().stream()
                .filter(entry -> entry.getValue() > counter.selfCalls * 2)
                .max(Map.Entry.comparingByValue())
                .ifPresent(entry -> acc.rows.add(new FeatureEnvyRecipe.Row(
                        enclosingClassName(),
                        m.getSimpleName(),
                        entry.getKey(),
                        counter.selfCalls,
                        entry.getValue(),
                        -1)));
    }

    private void collectProjectTypes(J.ClassDeclaration classDecl, String pkg) {
        final String fqn = pkg.isEmpty() ? classDecl.getSimpleName() : pkg + "." + classDecl.getSimpleName();
        acc.projectTypeNames.add(fqn);
        classDecl.getBody().getStatements().stream()
                .filter(J.ClassDeclaration.class::isInstance)
                .map(J.ClassDeclaration.class::cast)
                .forEach(inner -> collectProjectTypes(inner, fqn));
    }

    private static String packagePrefix(J.CompilationUnit cu) {
        return cu.getPackageDeclaration() != null
                ? cu.getPackageDeclaration().getExpression().toString()
                : "";
    }

    static boolean isProjectType(J.Identifier id, FeatureEnvyRecipe.Accumulator acc) {
        final JavaType type = id.getType();
        return type instanceof JavaType.FullyQualified fq
                && acc.projectTypeNames.contains(fq.getFullyQualifiedName());
    }

    static String resolveTypeName(J.Identifier id) {
        return id.getType() instanceof JavaType.FullyQualified fq ? fq.getClassName() : id.getSimpleName();
    }

    private static boolean isVisitorMethod(J.MethodDeclaration method) {
        return method.getSimpleName().startsWith("visit");
    }

    private static boolean isConstructor(J.MethodDeclaration method) {
        return method.getMethodType() != null && method.getMethodType().isConstructor();
    }

    private static boolean isStatic(J.MethodDeclaration method) {
        return method.getModifiers().stream().anyMatch(mod -> mod.getType() == J.Modifier.Type.Static);
    }

    private boolean isInTestClass() {
        final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
        return classDecl != null && classDecl.getSimpleName().endsWith("Test");
    }

    private String enclosingClassName() {
        final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
        return classDecl != null ? classDecl.getSimpleName() : UNKNOWN_CLASS_NAME;
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.JavaType;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class SelectorArgumentRecipe extends ScanningRecipe<SelectorArgumentRecipe.Accumulator> {

    private static final String UNKNOWN = "unknown";

    public record Row(String className, String methodName, String parameterName, String parameterType) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Selector argument detection (G15)";
    }

    @Override
    public String getDescription() {
        return "Detects methods with boolean or enum parameters used to select behaviour via if or switch.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new SelectorScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private final class SelectorScanner extends JavaIsoVisitor<ExecutionContext> {
        private final Accumulator acc;

        SelectorScanner(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.MethodDeclaration visitMethodDeclaration(final J.MethodDeclaration method, final ExecutionContext ctx) {
            final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
            final Set<String> selectorParams = findSelectorParams(m);
            if (selectorParams.isEmpty()) {
                return m;
            }
            recordSelectorUsages(m, selectorParams);
            return m;
        }

        private void recordSelectorUsages(final J.MethodDeclaration m, final Set<String> selectorParams) {
            final String className = enclosingClassName();
            selectorParams.stream()
                    .filter(param -> isUsedAsSelector(m.getBody(), param))
                    .forEach(param -> acc.rows.add(new Row(className, m.getSimpleName(), param, findParamType(m, param))));
        }

        private String enclosingClassName() {
            final J.ClassDeclaration enclosing = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return enclosing != null ? enclosing.getSimpleName() : "<unknown>";
        }
    }

    private static Set<String> findSelectorParams(final J.MethodDeclaration m) {
        if (m.getBody() == null) {
            return Set.of();
        }
        return m.getParameters().stream()
                .filter(J.VariableDeclarations.class::isInstance)
                .map(J.VariableDeclarations.class::cast)
                .filter(SelectorArgumentRecipe::isBooleanOrEnum)
                .flatMap(v -> v.getVariables().stream())
                .map(J.VariableDeclarations.NamedVariable::getSimpleName)
                .collect(Collectors.toSet());
    }

    private static boolean isBooleanOrEnum(final J.VariableDeclarations varDecl) {
        if (varDecl.getType() instanceof JavaType.Primitive p) {
            return p == JavaType.Primitive.Boolean;
        }
        final String typeText = varDecl.getTypeExpression() != null
                ? varDecl.getTypeExpression().toString().trim() : "";
        return "boolean".equals(typeText) || isLikelyEnum(varDecl);
    }

    private static boolean isLikelyEnum(final J.VariableDeclarations varDecl) {
        if (varDecl.getType() instanceof JavaType.FullyQualified fq) {
            return fq.getKind() == JavaType.FullyQualified.Kind.Enum;
        }
        return false;
    }

    private static boolean isUsedAsSelector(final J.Block body, final String paramName) {
        final SelectorUsageDetector detector = new SelectorUsageDetector(paramName);
        detector.visit(body, 0);
        return detector.found;
    }

    private static final class SelectorUsageDetector extends JavaIsoVisitor<Integer> {
        private final String paramName;
        boolean found;

        SelectorUsageDetector(final String paramName) {
            this.paramName = paramName;
        }

        @Override
        public J.If visitIf(final J.If iff, final Integer unused) {
            if (conditionReferencesParam(iff.getIfCondition().getTree(), paramName)) {
                found = true;
            }
            return super.visitIf(iff, unused);
        }

        @Override
        public J.Switch visitSwitch(final J.Switch sw, final Integer unused) {
            if (selectorReferencesParam(sw.getSelector().getTree(), paramName)) {
                found = true;
            }
            return super.visitSwitch(sw, unused);
        }
    }

    private static boolean conditionReferencesParam(final Expression condition, final String paramName) {
        final String condText = condition.toString().trim();
        return condText.equals(paramName) || condText.startsWith(paramName + " ")
                || condText.startsWith("!" + paramName);
    }

    private static boolean selectorReferencesParam(final Expression selector, final String paramName) {
        return selector.toString().trim().equals(paramName);
    }

    private static String findParamType(final J.MethodDeclaration method, final String paramName) {
        return method.getParameters().stream()
                .filter(J.VariableDeclarations.class::isInstance)
                .map(J.VariableDeclarations.class::cast)
                .filter(v -> v.getVariables().stream().anyMatch(n -> n.getSimpleName().equals(paramName)))
                .map(v -> v.getTypeExpression() != null ? v.getTypeExpression().toString().trim() : UNKNOWN)
                .findFirst()
                .orElse(UNKNOWN);
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;

final class CallClassifier extends JavaIsoVisitor<CallCounter> {

    private static final String THIS = "this";

    private final FeatureEnvyRecipe.Accumulator acc;

    CallClassifier(FeatureEnvyRecipe.Accumulator acc) {
        this.acc = acc;
    }

    @Override
    public J.MethodInvocation visitMethodInvocation(J.MethodInvocation method, CallCounter counter) {
        final J.MethodInvocation mi = super.visitMethodInvocation(method, counter);
        final Expression select = mi.getSelect();
        if (isSelfCall(select)) {
            counter.selfCalls++;
        } else if (select instanceof J.Identifier id && FeatureEnvyScanner.isProjectType(id, acc)) {
            counter.externalCalls.merge(FeatureEnvyScanner.resolveTypeName(id), 1, Integer::sum);
        }
        return mi;
    }

    private static boolean isSelfCall(Expression select) {
        if (select == null) {
            return true;
        }
        return select instanceof J.Identifier id && THIS.equals(id.getSimpleName());
    }
}

package org.fiftieshousewife.cleancode.recipes;

import java.util.HashMap;
import java.util.Map;

final class CallCounter {

    int selfCalls;
    final Map<String, Integer> externalCalls = new HashMap<>();

    int totalCalls() {
        return selfCalls + externalCalls.values().stream().mapToInt(Integer::intValue).sum();
    }
}

package org.fiftieshousewife.cleancode.adapters;

import org.fiftieshousewife.cleancode.annotations.HeuristicCode;
import org.fiftieshousewife.cleancode.core.Confidence;
import org.fiftieshousewife.cleancode.core.Severity;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertAll;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

class PmdRuleMapTest {

    @Test
    void parsesWellFormedEntry() {
        final PmdRuleMap.Entry entry = PmdRuleMap.parseEntry(
                "CyclomaticComplexity",
                "G30|WARNING|MEDIUM|DS|cyclomaticcomplexity");

        assertAll(
                () -> assertEquals(HeuristicCode.G30, entry.code()),
                () -> assertEquals(Severity.WARNING, entry.severity()),
                () -> assertEquals(Confidence.MEDIUM, entry.confidence()),
                () -> assertEquals(
                        "https://pmd.github.io/pmd/pmd_rules_java_design.html#cyclomaticcomplexity",
                        entry.ruleUrl()));
    }

    @Test
    void rejectsEntryWithWrongFieldCount() {
        final IllegalStateException ex = assertThrows(
                IllegalStateException.class,
                () -> PmdRuleMap.parseEntry("SomeRule", "G30|WARNING|MEDIUM|DS"));

        assertTrue(ex.getMessage().contains("SomeRule"));
    }

    @Test
    void rejectsEntryWithUnknownCategory() {
        final IllegalStateException ex = assertThrows(
                IllegalStateException.class,
                () -> PmdRuleMap.parseEntry("SomeRule", "G30|WARNING|MEDIUM|XX|slug"));

        assertTrue(ex.getMessage().contains("XX"));
    }
}

