package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.JavaType;

final class LawOfDemeterScanner extends JavaIsoVisitor<ExecutionContext> {

    private static final String UNKNOWN = "<unknown>";
    private static final int UNKNOWN_LINE = -1;

    private final int chainDepthThreshold;
    private final LawOfDemeterRecipe.Accumulator acc;

    LawOfDemeterScanner(final int chainDepthThreshold, final LawOfDemeterRecipe.Accumulator acc) {
        this.chainDepthThreshold = chainDepthThreshold;
        this.acc = acc;
    }

    @Override
    public J.CompilationUnit visitCompilationUnit(final J.CompilationUnit cu, final ExecutionContext ctx) {
        cu.getClasses().forEach(classDecl -> collectProjectTypes(classDecl, packagePrefix(cu)));
        return super.visitCompilationUnit(cu, ctx);
    }

    @Override
    public J.MethodInvocation visitMethodInvocation(final J.MethodInvocation method, final ExecutionContext ctx) {
        final J.MethodInvocation visited = super.visitMethodInvocation(method, ctx);
        if (isPartOfEnclosingChain()) {
            return visited;
        }
        if (isReportableChain(visited)) {
            acc.rows.add(toRow(visited));
        }
        return visited;
    }

    private boolean isReportableChain(final J.MethodInvocation invocation) {
        final int depth = MethodChain.depth(invocation);
        return depth >= chainDepthThreshold
                && !MethodChain.isFluent(invocation)
                && involvesProjectTypes(invocation);
    }

    private LawOfDemeterRecipe.Row toRow(final J.MethodInvocation invocation) {
        return new LawOfDemeterRecipe.Row(
                findEnclosingClassName(),
                findEnclosingMethodName(),
                MethodChain.asString(invocation),
                MethodChain.depth(invocation),
                UNKNOWN_LINE);
    }

    private void collectProjectTypes(final J.ClassDeclaration classDecl, final String pkg) {
        final String fqn = pkg.isEmpty()
                ? classDecl.getSimpleName()
                : pkg + "." + classDecl.getSimpleName();
        acc.projectTypeNames.add(fqn);
        classDecl.getBody().getStatements().stream()
                .filter(J.ClassDeclaration.class::isInstance)
                .map(J.ClassDeclaration.class::cast)
                .forEach(inner -> collectProjectTypes(inner, fqn));
    }

    private static String packagePrefix(final J.CompilationUnit cu) {
        if (cu.getPackageDeclaration() == null) {
            return "";
        }
        return cu.getPackageDeclaration().getExpression().toString();
    }

    private boolean involvesProjectTypes(final J.MethodInvocation invocation) {
        if (anyReturnTypeIsProjectType(invocation)) {
            return true;
        }
        final J.Identifier root = MethodChain.findRoot(invocation);
        return root != null
                && root.getType() instanceof JavaType.FullyQualified fq
                && acc.projectTypeNames.contains(fq.getFullyQualifiedName());
    }

    private boolean anyReturnTypeIsProjectType(final J.MethodInvocation invocation) {
        J.MethodInvocation current = invocation;
        while (current != null) {
            if (current.getType() instanceof JavaType.FullyQualified fq
                    && acc.projectTypeNames.contains(fq.getFullyQualifiedName())) {
                return true;
            }
            current = current.getSelect() instanceof J.MethodInvocation nested ? nested : null;
        }
        return false;
    }

    private boolean isPartOfEnclosingChain() {
        return getCursor().getParentTreeCursor().getValue() instanceof J.MethodInvocation;
    }

    private String findEnclosingClassName() {
        final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
        return classDecl != null ? classDecl.getSimpleName() : UNKNOWN;
    }

    private String findEnclosingMethodName() {
        final J.MethodDeclaration methodDecl = getCursor().firstEnclosing(J.MethodDeclaration.class);
        return methodDecl != null ? methodDecl.getSimpleName() : UNKNOWN;
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.List;

final class MethodChain {

    private static final int FLUENT_MAJORITY_DIVISOR = 2;

    private MethodChain() {}

    static int depth(final J.MethodInvocation invocation) {
        int depth = 1;
        var current = invocation.getSelect();
        while (current instanceof J.MethodInvocation nested) {
            depth++;
            current = nested.getSelect();
        }
        return depth;
    }

    static boolean isFluent(final J.MethodInvocation invocation) {
        int total = 0;
        int fluent = 0;
        J.MethodInvocation current = invocation;
        while (current != null) {
            total++;
            if (FluentMethodNames.contains(current.getSimpleName())) {
                fluent++;
            }
            current = current.getSelect() instanceof J.MethodInvocation nested ? nested : null;
        }
        return fluent > total / FLUENT_MAJORITY_DIVISOR;
    }

    static J.Identifier findRoot(final J.MethodInvocation invocation) {
        var current = invocation.getSelect();
        while (current instanceof J.MethodInvocation nested) {
            current = nested.getSelect();
        }
        return current instanceof J.Identifier id ? id : null;
    }

    static String asString(final J.MethodInvocation invocation) {
        final List<String> parts = new ArrayList<>();
        parts.add(invocation.getSimpleName() + "()");
        var current = invocation.getSelect();
        while (current instanceof J.MethodInvocation nested) {
            parts.addFirst(nested.getSimpleName() + "()");
            current = nested.getSelect();
        }
        if (current instanceof J.Identifier identifier) {
            parts.addFirst(identifier.getSimpleName());
        }
        return String.join(".", parts);
    }
}

package org.fiftieshousewife.cleancode.core;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ParseResult;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.PackageDeclaration;
import com.github.javaparser.ast.body.BodyDeclaration;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.ConstructorDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.AnnotationExpr;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.stream.Stream;

final class SuppressionParser {

    private final List<Suppression> suppressions = new ArrayList<>();
    private final List<Finding> metaFindings = new ArrayList<>();
    private final SuppressionAnnotationProcessor processor =
            new SuppressionAnnotationProcessor(suppressions, new SuppressionMetaFindings(metaFindings));
    private final JavaParser parser = new JavaParser();

    static ParseOutcome parse(final Path sourceRoot) {
        final SuppressionParser instance = new SuppressionParser();
        instance.walk(sourceRoot);
        return new ParseOutcome(instance.suppressions, instance.metaFindings);
    }

    private void walk(final Path sourceRoot) {
        try (Stream<Path> files = Files.walk(sourceRoot)) {
            files.filter(p -> p.toString().endsWith(".java")).forEach(this::parseFile);
        } catch (IOException unreadableRoot) {
            skipUnreadable(sourceRoot, unreadableRoot);
        }
    }

    private void parseFile(final Path file) {
        try {
            final ParseResult<CompilationUnit> result = parser.parse(file);
            final Optional<CompilationUnit> compilationUnit = result.getResult();
            if (result.isSuccessful() && compilationUnit.isPresent()) {
                processCompilationUnit(compilationUnit.get(), deriveSourceFile(compilationUnit.get(), file));
            }
        } catch (IOException unreadableFile) {
            skipUnreadable(file, unreadableFile);
        }
    }

    /**
     * Suppression scanning is best-effort: an unreadable file or root
     * directory contributes no suppressions but must not abort the index
     * build. Lives in a named method so each catch block documents its
     * intent rather than being a silently empty block. Callers in
     * FindingFilterTest pass non-existent paths and rely on this.
     */
    @SuppressWarnings("unused")
    private void skipUnreadable(final Path path, final IOException cause) {
    }

    private void processCompilationUnit(final CompilationUnit cu, final String sourceFile) {
        cu.getPackageDeclaration().ifPresent(pkg -> processPackageDeclaration(pkg, sourceFile));
        final ParseContext fileContext = new ParseContext(sourceFile, null);
        processBodyDeclarations(cu, fileContext);
    }

    private void processBodyDeclarations(final CompilationUnit cu, final ParseContext context) {
        cu.findAll(ClassOrInterfaceDeclaration.class).forEach(cls -> processAnnotatedNode(cls, context));
        cu.findAll(MethodDeclaration.class).forEach(method -> processAnnotatedNode(method, context));
        cu.findAll(ConstructorDeclaration.class).forEach(ctor -> processAnnotatedNode(ctor, context));
    }

    private void processPackageDeclaration(final PackageDeclaration pkg, final String sourceFile) {
        final String packagePath = pkg.getNameAsString().replace('.', '/');
        final int line = pkg.getBegin().map(p -> p.line).orElse(-1);
        final ParseContext context = new ParseContext(sourceFile, packagePath);
        final LineRange range = new LineRange(line, line);
        for (final AnnotationExpr ann : pkg.getAnnotations()) {
            if (SuppressionAnnotationProcessor.SUPPRESS_ANNOTATION.equals(ann.getNameAsString())) {
                processor.processSingle(ann, context, range);
            }
        }
    }

    private void processAnnotatedNode(final BodyDeclaration<?> node, final ParseContext context) {
        final int startLine = node.getBegin().map(p -> p.line).orElse(-1);
        final int endLine = node.getEnd().map(p -> p.line).orElse(-1);
        final LineRange range = new LineRange(startLine, endLine);
        node.getAnnotations().forEach(ann -> processor.processAnnotation(ann, context, range));
    }

    private static String deriveSourceFile(final CompilationUnit cu, final Path file) {
        final String packageName = cu.getPackageDeclaration()
                .map(pd -> pd.getNameAsString().replace('.', '/'))
                .orElse("");
        final String fileName = file.getFileName().toString();
        return packageName.isEmpty() ? fileName : packageName + "/" + fileName;
    }

    record ParseOutcome(List<Suppression> suppressions, List<Finding> metaFindings) {
    }
}

