    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
        final Map<String, Set<String>> subclassMap = new HashMap<>();
        final List<InstanceofCheck> instanceofChecks = new ArrayList<>();
    }

    record InstanceofCheck(String enclosingClass, String checkedType) {}

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Base class depending on derivatives detection (G7)";
    }

    @Override
    public String getDescription() {
        return "Detects base classes that reference their subclasses via instanceof or direct type references.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new ScannerVisitor(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        if (lastAccumulator == null) {
            return List.of();
        }
        return buildRows(lastAccumulator);
    }

    static List<Row> buildRows(final Accumulator acc) {
        final List<Row> results = new ArrayList<>();
        acc.instanceofChecks.forEach(check -> {
            final Set<String> subclasses = acc.subclassMap.getOrDefault(check.enclosingClass(), Set.of());
            if (subclasses.contains(check.checkedType())) {
                results.add(new Row(check.enclosingClass(), check.checkedType()));
            }
        });
        return Collections.unmodifiableList(results);
    }

    static String extractTypeName(final J tree) {
        return switch (tree) {
            case J.Identifier ident -> ident.getSimpleName();
            case J.FieldAccess fa -> fa.getSimpleName();
            default -> null;
        };
    }

    private static final class ScannerVisitor extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;

        ScannerVisitor(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.ClassDeclaration visitClassDeclaration(J.ClassDeclaration classDecl, ExecutionContext ctx) {
            final J.ClassDeclaration c = super.visitClassDeclaration(classDecl, ctx);
            recordSubclass(c);
            return c;
        }

        @Override
        public J.InstanceOf visitInstanceOf(J.InstanceOf instanceOf, ExecutionContext ctx) {
            final J.InstanceOf io = super.visitInstanceOf(instanceOf, ctx);
            recordInstanceofCheck(io);
            return io;
        }

        private void recordSubclass(final J.ClassDeclaration c) {
            if (c.getExtends() == null) {
                return;
            }
            final String parentName = c.getExtends().toString().trim();
            acc.subclassMap
                    .computeIfAbsent(parentName, k -> new HashSet<>())
                    .add(c.getSimpleName());
        }

        private void recordInstanceofCheck(final J.InstanceOf io) {
            final J.ClassDeclaration enclosingClass = getCursor().firstEnclosing(J.ClassDeclaration.class);
            if (enclosingClass == null) {
                return;
            }
            final String className = enclosingClass.getSimpleName();
            final String checkedType = extractTypeName(io.getClazz());
            if (checkedType != null && !checkedType.equals(className)) {
                acc.instanceofChecks.add(new InstanceofCheck(className, checkedType));
            }
        }
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Set;

public class BoundaryConditionRecipe extends ScanningRecipe<BoundaryConditionRecipe.Accumulator> {

    private static final Set<J.Binary.Type> BOUNDARY_OPERATORS = Set.of(
            J.Binary.Type.Addition, J.Binary.Type.Subtraction
    );

    private static final String UNKNOWN_NAME = "<unknown>";

    public record Row(String className, String methodName, String expression, int lineNumber) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Boundary condition detection (G33)";
    }

    @Override
    public String getDescription() {
        return "Detects raw +1/-1 boundary adjustments on method invocations that should be "
                + "extracted to named variables.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new BoundaryScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static final class BoundaryScanner extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;

        BoundaryScanner(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.Binary visitBinary(final J.Binary binary, final ExecutionContext ctx) {
            final J.Binary visited = super.visitBinary(binary, ctx);
            if (!BOUNDARY_OPERATORS.contains(visited.getOperator())) {
                return visited;
            }
            if (isMethodCallBoundaryAdjustment(visited)) {
                acc.rows.add(buildRow(visited));
            }
            return visited;
        }

        private Row buildRow(final J.Binary visited) {
            return new Row(
                    findEnclosingClassName(),
                    findEnclosingMethodName(),
                    visited.printTrimmed(getCursor()),
                    -1
            );
        }

        private boolean isMethodCallBoundaryAdjustment(final J.Binary visited) {
            final boolean leftIsMethodCall = visited.getLeft() instanceof J.MethodInvocation;
            final boolean rightIsMethodCall = visited.getRight() instanceof J.MethodInvocation;
            final boolean leftIsLiteralOne = isLiteralOne(visited.getLeft());
            final boolean rightIsLiteralOne = isLiteralOne(visited.getRight());
            return (leftIsMethodCall && rightIsLiteralOne) || (rightIsMethodCall && leftIsLiteralOne);
        }

        private boolean isLiteralOne(final Expression expr) {
            if (expr instanceof J.Literal literal) {
                final Object value = literal.getValue();
                return value instanceof Integer i && (i == 1 || i == -1);
            }
            if (expr instanceof J.Unary unary
                    && unary.getOperator() == J.Unary.Type.Negative
                    && unary.getExpression() instanceof J.Literal literal) {
                final Object value = literal.getValue();
                return value instanceof Integer i && i == 1;
            }
            return false;
        }

        private String findEnclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : UNKNOWN_NAME;
        }

        private String findEnclosingMethodName() {
            final J.MethodDeclaration methodDecl = getCursor().firstEnclosing(J.MethodDeclaration.class);
            return methodDecl != null ? methodDecl.getSimpleName() : UNKNOWN_NAME;
        }
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class PrivateMethodTestabilityRecipe extends ScanningRecipe<PrivateMethodTestabilityRecipe.Accumulator> {

    private static final int DEFAULT_MIN_BODY_LINES = 5;
    private static final String UNKNOWN_CLASS = "<unknown>";

    private final int minBodyLines;

    public PrivateMethodTestabilityRecipe() {
        this(DEFAULT_MIN_BODY_LINES);
    }

    public PrivateMethodTestabilityRecipe(final int minBodyLines) {
        this.minBodyLines = minBodyLines;
    }

    public record PrivateMethodTestabilityRow(
            String className,
            String methodName,
            int lineCount,
            int lineNumber
    ) {}

    public static class Accumulator {
        final List<PrivateMethodTestabilityRow> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Private method testability detection";
    }

    @Override
    public String getDescription() {
        return "Detects non-trivial private methods that should be package-private for testability.";
    }

    @Override
    public Accumulator getInitialValue(final ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(final Accumulator acc) {
        return new PrivateMethodScanner(acc, minBodyLines);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(final Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<PrivateMethodTestabilityRow> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static final class PrivateMethodScanner extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;
        private final int minBodyLines;

        PrivateMethodScanner(final Accumulator acc, final int minBodyLines) {
            this.acc = acc;
            this.minBodyLines = minBodyLines;
        }

        @Override
        public J.MethodDeclaration visitMethodDeclaration(final J.MethodDeclaration method,
                                                          final ExecutionContext ctx) {
            final J.MethodDeclaration visited = super.visitMethodDeclaration(method, ctx);
            if (shouldSkip(visited)) {
                return visited;
            }
            final int bodyLineCount = bodyStatementCount(visited);
            if (bodyLineCount <= minBodyLines) {
                return visited;
            }
            acc.rows.add(toRow(visited, bodyLineCount));
            return visited;
        }

        private boolean shouldSkip(final J.MethodDeclaration method) {
            return !isPrivate(method)
                    || isConstructor(method)
                    || isInsideAnonymousClassOrLambda();
        }

        private int bodyStatementCount(final J.MethodDeclaration method) {
            final J.Block body = method.getBody();
            return body != null ? body.getStatements().size() : -1;
        }

        private PrivateMethodTestabilityRow toRow(final J.MethodDeclaration method, final int bodyLineCount) {
            return new PrivateMethodTestabilityRow(
                    findEnclosingClassName(),
                    method.getSimpleName(),
                    bodyLineCount,
                    -1
            );
        }

        private boolean isPrivate(final J.MethodDeclaration method) {
            return method.getModifiers().stream()
                    .anyMatch(mod -> mod.getType() == J.Modifier.Type.Private);
        }

        private boolean isConstructor(final J.MethodDeclaration method) {
            return method.getMethodType() != null && method.getMethodType().isConstructor();
        }

        private boolean isInsideAnonymousClassOrLambda() {
            return isInsideAnonymousClass() || isInsideLambda();
        }

        private boolean isInsideAnonymousClass() {
            return getCursor().firstEnclosing(J.NewClass.class) != null;
        }

        private boolean isInsideLambda() {
            return getCursor().firstEnclosing(J.Lambda.class) != null;
        }

        private String findEnclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : UNKNOWN_CLASS;
        }
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Statement;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.function.Predicate;

public class GuardClauseRecipe extends ScanningRecipe<GuardClauseRecipe.Accumulator> {

    private static final int MIN_GUARDS = 2;

    public record Row(String className, String methodName, int guardCount) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "Excessive guard clause detection (G29/G30)";
    }

    @Override
    public String getDescription() {
        return "Detects methods with multiple if-return/if-continue guard clauses that should be simplified.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new GuardScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static final class GuardScanner extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;

        GuardScanner(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.MethodDeclaration visitMethodDeclaration(final J.MethodDeclaration method, final ExecutionContext ctx) {
            final J.MethodDeclaration m = super.visitMethodDeclaration(method, ctx);
            if (m.getBody() == null) {
                return m;
            }
            final int guardCount = countMatching(m.getBody().getStatements(), GuardScanner::isReturnOrThrowGuard);
            if (guardCount >= MIN_GUARDS) {
                acc.rows.add(new Row(enclosingClassName(), m.getSimpleName(), guardCount));
            }
            return m;
        }

        @Override
        public J.ForEachLoop visitForEachLoop(final J.ForEachLoop forLoop, final ExecutionContext ctx) {
            final J.ForEachLoop fl = super.visitForEachLoop(forLoop, ctx);
            if (!(fl.getBody() instanceof J.Block body)) {
                return fl;
            }
            final int guardCount = countMatching(body.getStatements(), GuardScanner::isContinueGuard);
            if (guardCount >= MIN_GUARDS) {
                acc.rows.add(new Row(enclosingClassName(), enclosingMethodName(), guardCount));
            }
            return fl;
        }

        private String enclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : "<unknown>";
        }

        private String enclosingMethodName() {
            final J.MethodDeclaration methodDecl = getCursor().firstEnclosing(J.MethodDeclaration.class);
            return methodDecl != null ? methodDecl.getSimpleName() : "<loop>";
        }

        private static int countMatching(final List<Statement> statements, final Predicate<Statement> predicate) {
            return (int) statements.stream().filter(predicate).count();
        }

        private static boolean isReturnOrThrowGuard(final Statement stmt) {
            return isBareIf(stmt) && bodyIsReturnOrThrow(((J.If) stmt).getThenPart());
        }

        private static boolean isContinueGuard(final Statement stmt) {
            return isBareIf(stmt) && bodyIsContinue(((J.If) stmt).getThenPart());
        }

        private static boolean isBareIf(final Statement stmt) {
            return stmt instanceof J.If ifStmt && ifStmt.getElsePart() == null;
        }

        private static boolean bodyIsReturnOrThrow(final Statement body) {
            return isReturnOrThrow(body) || (body instanceof J.Block block && singleStatementMatches(block, GuardScanner::isReturnOrThrow));
        }

        private static boolean bodyIsContinue(final Statement body) {
            return body instanceof J.Continue
                    || (body instanceof J.Block block && singleStatementMatches(block, s -> s instanceof J.Continue));
        }

        private static boolean isReturnOrThrow(final Statement s) {
            return s instanceof J.Return || s instanceof J.Throw;
        }

        private static boolean singleStatementMatches(final J.Block block, final Predicate<Statement> predicate) {
            return block.getStatements().size() == 1 && predicate.test(block.getStatements().getFirst());
        }
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Statement;

final class ImperativeLoopScanner extends JavaIsoVisitor<ExecutionContext> {

    private static final String UNKNOWN = "<unknown>";
    private static final String FOR_EACH_PREFIX = "for-each with ";
    private static final String FOR_PREFIX = "for with ";

    private final ImperativeLoopRecipe.Accumulator acc;

    ImperativeLoopScanner(ImperativeLoopRecipe.Accumulator acc) {
        this.acc = acc;
    }

    @Override
    public J.ForEachLoop visitForEachLoop(J.ForEachLoop forEachLoop, ExecutionContext ctx) {
        final J.ForEachLoop loop = super.visitForEachLoop(forEachLoop, ctx);
        recordIfClassifiable(loop.getBody(), FOR_EACH_PREFIX);
        return loop;
    }

    @Override
    public J.ForLoop visitForLoop(J.ForLoop forLoop, ExecutionContext ctx) {
        final J.ForLoop loop = super.visitForLoop(forLoop, ctx);
        recordIfClassifiable(loop.getBody(), FOR_PREFIX);
        return loop;
    }

    private void recordIfClassifiable(Statement loopBody, String patternPrefix) {
        final Statement body = LoopBodies.extractSingleStatement(loopBody);
        if (body == null) {
            return;
        }
        final String suffix = LoopBodies.classifyBody(body);
        if (suffix == null) {
            return;
        }
        acc.rows.add(new ImperativeLoopRecipe.Row(
                enclosingClassName(),
                enclosingMethodName(),
                patternPrefix + suffix,
                -1));
    }

    private String enclosingClassName() {
        final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
        return classDecl != null ? classDecl.getSimpleName() : UNKNOWN;
    }

    private String enclosingMethodName() {
        final J.MethodDeclaration methodDecl = getCursor().firstEnclosing(J.MethodDeclaration.class);
        return methodDecl != null ? methodDecl.getSimpleName() : UNKNOWN;
    }
}

