package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.J;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class SystemOutRecipe extends ScanningRecipe<SystemOutRecipe.Accumulator> {

    private static final String PRINT_STACK_TRACE = "printStackTrace";
    private static final String SYSTEM = "System";
    private static final String OUT = "out";
    private static final String ERR = "err";
    private static final String UNKNOWN_CLASS = "<unknown>";

    public record Row(String className, String call) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "System.out/err detection (G4)";
    }

    @Override
    public String getDescription() {
        return "Detects System.out.println, System.err.println, and e.printStackTrace() in production code.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new SystemOutScanner(acc);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static final class SystemOutScanner extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;

        SystemOutScanner(final Accumulator acc) {
            this.acc = acc;
        }

        @Override
        public J.MethodInvocation visitMethodInvocation(J.MethodInvocation method, ExecutionContext ctx) {
            final J.MethodInvocation m = super.visitMethodInvocation(method, ctx);
            recordIfPrintStackTrace(m);
            recordIfSystemStreamCall(m);
            return m;
        }

        private void recordIfPrintStackTrace(final J.MethodInvocation m) {
            if (PRINT_STACK_TRACE.equals(m.getSimpleName())) {
                acc.rows.add(new Row(findEnclosingClassName(), PRINT_STACK_TRACE));
            }
        }

        private void recordIfSystemStreamCall(final J.MethodInvocation m) {
            if (!(m.getSelect() instanceof J.FieldAccess fieldAccess)) {
                return;
            }
            if (!isSystemStreamAccess(fieldAccess)) {
                return;
            }
            final String fieldName = fieldAccess.getSimpleName();
            acc.rows.add(new Row(findEnclosingClassName(), SYSTEM + "." + fieldName + "." + m.getSimpleName()));
        }

        private boolean isSystemStreamAccess(final J.FieldAccess fieldAccess) {
            final String fieldName = fieldAccess.getSimpleName();
            if (!OUT.equals(fieldName) && !ERR.equals(fieldName)) {
                return false;
            }
            return fieldAccess.getTarget() instanceof J.Identifier ident && SYSTEM.equals(ident.getSimpleName());
        }

        private String findEnclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : UNKNOWN_CLASS;
        }
    }
}

package org.fiftieshousewife.cleancode.refactoring;

import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonProperty;
import org.openrewrite.ExecutionContext;
import org.openrewrite.Recipe;
import org.openrewrite.Tree;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.format.AutoFormat;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.Space;
import org.openrewrite.java.tree.Statement;
import org.openrewrite.marker.Markers;

import java.util.ArrayList;
import java.util.List;

public class RecordToLombokValueRecipe extends Recipe {

    private static final String VALUE_ANNOTATION = "Value";
    private static final String BUILDER_ANNOTATION = "Builder";
    private static final String LOMBOK_VALUE_IMPORT = "lombok.Value";
    private static final String LOMBOK_BUILDER_IMPORT = "lombok.Builder";
    private static final String FIELD_PREFIX = "\n    ";

    private final int minComponents;

    @JsonCreator
    public RecordToLombokValueRecipe(@JsonProperty("minComponents") final int minComponents) {
        this.minComponents = minComponents;
    }

    @Override
    public String getDisplayName() {
        return "Convert large records to @Value @Builder classes";
    }

    @Override
    public String getDescription() {
        return "Converts Java records with more than %d components to Lombok @Value @Builder classes."
                .formatted(minComponents);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor() {
        return new RecordToValueVisitor();
    }

    private class RecordToValueVisitor extends JavaIsoVisitor<ExecutionContext> {

        @Override
        public J.ClassDeclaration visitClassDeclaration(final J.ClassDeclaration classDecl, final ExecutionContext ctx) {
            final J.ClassDeclaration c = super.visitClassDeclaration(classDecl, ctx);
            final List<J.VariableDeclarations> components = eligibleComponents(c);
            if (components == null) {
                return c;
            }
            registerLombokImports();
            return autoFormat(convertRecordToValueClass(c, components), ctx);
        }

        private List<J.VariableDeclarations> eligibleComponents(final J.ClassDeclaration c) {
            if (c.getKind() != J.ClassDeclaration.Kind.Type.Record || c.getPrimaryConstructor() == null) {
                return null;
            }
            final List<J.VariableDeclarations> components = c.getPrimaryConstructor().stream()
                    .filter(J.VariableDeclarations.class::isInstance)
                    .map(J.VariableDeclarations.class::cast)
                    .toList();
            return components.size() >= minComponents ? components : null;
        }

        private void registerLombokImports() {
            maybeAddImport(LOMBOK_VALUE_IMPORT);
            maybeAddImport(LOMBOK_BUILDER_IMPORT);
        }

        private J.ClassDeclaration autoFormat(final J.ClassDeclaration transformed, final ExecutionContext ctx) {
            return (J.ClassDeclaration) new AutoFormat().getVisitor()
                    .visit(transformed, ctx, getCursor().getParentOrThrow());
        }
    }

    private static J.ClassDeclaration convertRecordToValueClass(
            final J.ClassDeclaration c,
            final List<J.VariableDeclarations> components) {
        return c.withKind(J.ClassDeclaration.Kind.Type.Class)
                .withLeadingAnnotations(annotationsWithValueAndBuilder(c))
                .withPrimaryConstructor(null)
                .withBody(c.getBody().withStatements(componentsAsFields(components)));
    }

    private static List<J.Annotation> annotationsWithValueAndBuilder(final J.ClassDeclaration c) {
        final List<J.Annotation> annotations = new ArrayList<>(c.getLeadingAnnotations());
        annotations.add(buildAnnotation(VALUE_ANNOTATION));
        annotations.add(buildAnnotation(BUILDER_ANNOTATION));
        return annotations;
    }

    private static List<Statement> componentsAsFields(final List<J.VariableDeclarations> components) {
        return components.stream()
                .map(RecordToLombokValueRecipe::componentToField)
                .map(Statement.class::cast)
                .toList();
    }

    private static J.Annotation buildAnnotation(final String name) {
        return new J.Annotation(
                Tree.randomId(),
                Space.format("\n"),
                Markers.EMPTY,
                new J.Identifier(
                        Tree.randomId(),
                        Space.EMPTY,
                        Markers.EMPTY,
                        List.of(),
                        name,
                        null, null),
                null);
    }

    private static Statement componentToField(final J.VariableDeclarations component) {
        return component
                .withModifiers(List.of())
                .withPrefix(Space.format(FIELD_PREFIX));
    }
}

package org.fiftieshousewife.cleancode.recipes;

import org.openrewrite.ExecutionContext;
import org.openrewrite.ScanningRecipe;
import org.openrewrite.TreeVisitor;
import org.openrewrite.java.JavaIsoVisitor;
import org.openrewrite.java.tree.Expression;
import org.openrewrite.java.tree.J;
import org.openrewrite.java.tree.JavaType;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class StringSwitchRecipe extends ScanningRecipe<StringSwitchRecipe.Accumulator> {

    private static final int DEFAULT_MIN_CASE_COUNT = 3;
    private static final String JAVA_LANG_STRING = "java.lang.String";

    private final int minCaseCount;

    public StringSwitchRecipe() {
        this(DEFAULT_MIN_CASE_COUNT);
    }

    public StringSwitchRecipe(final int minCaseCount) {
        this.minCaseCount = minCaseCount;
    }

    public record Row(
            String className,
            String methodName,
            int caseCount,
            String selectorName,
            int lineNumber
    ) {}

    public static class Accumulator {
        final List<Row> rows = new ArrayList<>();
    }

    private Accumulator lastAccumulator;

    @Override
    public String getDisplayName() {
        return "String switch detection (G23)";
    }

    @Override
    public String getDescription() {
        return "Detects switch statements and expressions that dispatch on String values with 3 or more cases.";
    }

    @Override
    public Accumulator getInitialValue(ExecutionContext ctx) {
        lastAccumulator = new Accumulator();
        return lastAccumulator;
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getScanner(Accumulator acc) {
        return new StringSwitchScanner(acc, minCaseCount);
    }

    @Override
    public TreeVisitor<?, ExecutionContext> getVisitor(Accumulator acc) {
        return TreeVisitor.noop();
    }

    public List<Row> collectedRows() {
        return lastAccumulator != null ? Collections.unmodifiableList(lastAccumulator.rows) : List.of();
    }

    private static final class StringSwitchScanner extends JavaIsoVisitor<ExecutionContext> {

        private final Accumulator acc;
        private final int minCaseCount;

        StringSwitchScanner(final Accumulator acc, final int minCaseCount) {
            this.acc = acc;
            this.minCaseCount = minCaseCount;
        }

        @Override
        public J.Switch visitSwitch(J.Switch switchStatement, ExecutionContext ctx) {
            final J.Switch s = super.visitSwitch(switchStatement, ctx);
            final int caseCount = s.getCases().getStatements().size();
            inspect(s.getSelector(), caseCount);
            return s;
        }

        @Override
        public J.SwitchExpression visitSwitchExpression(J.SwitchExpression switchExpression, ExecutionContext ctx) {
            final J.SwitchExpression s = super.visitSwitchExpression(switchExpression, ctx);
            final int caseCount = s.getCases().getStatements().size();
            inspect(s.getSelector(), caseCount);
            return s;
        }

        private void inspect(J.ControlParentheses<Expression> selector, int caseCount) {
            final Expression selectorExpr = selector.getTree();
            if (!isStringType(selectorExpr) || caseCount < minCaseCount) {
                return;
            }
            final String selectorName = selectorName(selectorExpr);
            acc.rows.add(new Row(
                    findEnclosingClassName(),
                    findEnclosingMethodName(),
                    caseCount,
                    selectorName,
                    -1
            ));
        }

        private static String selectorName(Expression selectorExpr) {
            return selectorExpr instanceof J.Identifier ident
                    ? ident.getSimpleName()
                    : selectorExpr.toString();
        }

        private static boolean isStringType(Expression expression) {
            final JavaType type = expression.getType();
            return type instanceof JavaType.Class classType
                    && JAVA_LANG_STRING.equals(classType.getFullyQualifiedName());
        }

        private String findEnclosingClassName() {
            final J.ClassDeclaration classDecl = getCursor().firstEnclosing(J.ClassDeclaration.class);
            return classDecl != null ? classDecl.getSimpleName() : "<unknown>";
        }

        private String findEnclosingMethodName() {
            final J.MethodDeclaration methodDecl = getCursor().firstEnclosing(J.MethodDeclaration.class);
            return methodDecl != null ? methodDecl.getSimpleName() : "<unknown>";
        }
    }
}

